// 画像を Cloud Storage にアップロードして URL を返す。失敗時は base64 のまま返す (フォールバック)
// 既存データ (base64 直保存) と互換: <img src={...}> は URL/base64 両方扱える
// ローカル日付文字列 (UTC変換しない。JST で 1 日ズレるのを防ぐ)。日付の絞り込み・集計・納期計算に使う。
// ※ ダウンロードファイル名等は従来通り UTC でも実害がないため置換不要。
const localYMD = (d) => { const x = (d instanceof Date) ? d : new Date(d); return `${x.getFullYear()}-${String(x.getMonth()+1).padStart(2,'0')}-${String(x.getDate()).padStart(2,'0')}`; };
const localYM = (d) => { const x = (d instanceof Date) ? d : new Date(d); return `${x.getFullYear()}-${String(x.getMonth()+1).padStart(2,'0')}`; };

// ── 納期など「日付だけ」の値を、あらゆる入力形式から1つの正規表現に統一する(最終検査 golden と同一) ──
//  受理: YYYY-MM-DD / YYYY-M-D / YYYY/M/D / YY/M/D / M/D/YYYY / M/D(年なし) / YYYY年M月D日 / 全角数字 /
//        括弧の曜日 "7/14 (火)" / Excelシリアル値(数値・5桁文字列) / ミリ秒タイムスタンプ / Date。返り {y,m,d} or null。
//  ⚠表示(fmtDue)・比較(dueMs)・並び替えの唯一の入口。new Date(lot.dueDate) 直呼び/文字列比較は別形式で化けるので廃止。
const DOW_JP = ['日', '月', '火', '水', '木', '金', '土'];
const parseDueParts = (raw) => {
  if (raw == null || raw === '') return null;
  if (raw instanceof Date) { return isNaN(raw.getTime()) ? null : { y: raw.getFullYear(), m: raw.getMonth() + 1, d: raw.getDate() }; }
  if (typeof raw === 'number' && isFinite(raw)) {
    if (raw > 10 && raw < 100000) { const dt = new Date(Math.round((raw - 25569) * 86400000)); return { y: dt.getUTCFullYear(), m: dt.getUTCMonth() + 1, d: dt.getUTCDate() }; }
    const dt = new Date(raw); return isNaN(dt.getTime()) ? null : { y: dt.getFullYear(), m: dt.getMonth() + 1, d: dt.getDate() };
  }
  let s = String(raw).trim();
  if (!s) return null;
  s = s.replace(/[０-９]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0));
  if (/^\d{5}$/.test(s)) return parseDueParts(Number(s));
  s = s.replace(/[（(].*?[)）]/g, ' ').replace(/[（(].*$/, ' ');
  s = s.replace(/[年月]/g, '/').replace(/日/g, '').replace(/[.\-]/g, '/').trim();
  s = s.replace(/\/+/g, '/').replace(/\/$/, '');
  const parts = s.split('/').map(x => x.trim()).filter(x => x !== '');
  const nums = parts.map(Number);
  if (!nums.length || nums.some(n => !isFinite(n))) return null;
  let y, m, d;
  if (nums.length >= 3) {
    if (String(parts[2]).length === 4) { y = nums[2]; m = nums[0]; d = nums[1]; }
    else { y = nums[0] < 100 ? 2000 + nums[0] : nums[0]; m = nums[1]; d = nums[2]; }
  } else if (nums.length === 2) { m = nums[0]; d = nums[1]; y = null; }
  else return null;
  if (m < 1 || m > 12 || d < 1 || d > 31) return null;
  if (y == null) {
    const now = new Date(); const today0 = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    let cand = new Date(now.getFullYear(), m - 1, d);
    if ((today0.getTime() - cand.getTime()) > 90 * 86400000) cand = new Date(now.getFullYear() + 1, m - 1, d);
    y = cand.getFullYear();
  }
  return { y, m, d };
};
const dueDateObj = (raw) => { const p = parseDueParts(raw); return p ? new Date(p.y, p.m - 1, p.d) : null; };
const dueMsOf = (raw) => { const dt = dueDateObj(raw); return dt ? dt.getTime() : null; };
const todayMidnightMs = () => { const t = new Date(); return new Date(t.getFullYear(), t.getMonth(), t.getDate()).getTime(); };
// 表示: 2026/8/15（金）。パース不能値は元文字列をそのまま返す(データを隠さない)。
const fmtDue = (raw, withDow = true) => {
  const p = parseDueParts(raw);
  if (!p) return raw == null ? '' : String(raw);
  const dt = new Date(p.y, p.m - 1, p.d);
  return `${p.y}/${p.m}/${p.d}${withDow ? `（${DOW_JP[dt.getDay()]}）` : ''}`;
};

let _storageInstance = null;
const getStorageInstance = () => {
  if (_storageInstance) return _storageInstance;
  try {
    _storageInstance = getStorage();
  } catch (e) {
    console.warn('Storage init failed', e);
  }
  return _storageInstance;
};

const uploadImageToStorage = async (base64DataUrl, pathHint = 'images') => {
  // 100KB 未満なら base64 維持（小さい画像は Storage より直保存の方が早い）
  if (!base64DataUrl || typeof base64DataUrl !== 'string') return base64DataUrl;
  if (!base64DataUrl.startsWith('data:')) return base64DataUrl; // 既に URL
  const sizeKB = base64DataUrl.length / 1024;
  if (sizeKB < 100) return base64DataUrl;
  try {
    const storage = getStorageInstance();
    if (!storage) return base64DataUrl;
    const fileId = `${Date.now()}_${Math.random().toString(36).slice(2, 9)}.jpg`;
    const ref = storageRef(storage, `artifacts/product-inspection-v1/${pathHint}/${fileId}`);
    await uploadString(ref, base64DataUrl, 'data_url');
    const url = await getDownloadURL(ref);
    return url;
  } catch (e) {
    console.warn('Image upload failed, falling back to base64', e);
    return base64DataUrl;
  }
};

// PDF など画像以外のファイルを Cloud Storage へ。data URL から contentType を保持してアップロード。
// 失敗時は null を返す (PDF を base64 のまま Firestore に入れると 1MB 上限を超えるため、base64 へはフォールバックしない)。
const uploadFileToStorage = async (base64DataUrl, pathHint = 'files', ext = 'bin') => {
  if (!base64DataUrl || typeof base64DataUrl !== 'string') return base64DataUrl;
  if (!base64DataUrl.startsWith('data:')) return base64DataUrl; // 既に URL
  try {
    const storage = getStorageInstance();
    if (!storage) return null;
    const fileId = `${Date.now()}_${Math.random().toString(36).slice(2, 9)}.${ext}`;
    const ref = storageRef(storage, `artifacts/product-inspection-v1/${pathHint}/${fileId}`);
    await uploadString(ref, base64DataUrl, 'data_url');
    return await getDownloadURL(ref);
  } catch (e) {
    console.warn('File upload failed', e);
    return null;
  }
};

// ExcelJS / JSZip は動的 import で初回バンドルから除外 (各 ~1MB / ~100KB)
let _ExcelJS = null;
const loadExcelJS = async () => {
  if (_ExcelJS) return _ExcelJS;
  const mod = await import('exceljs');
  _ExcelJS = mod.default || mod;
  return _ExcelJS;
};
let _JSZip = null;
const loadJSZip = async () => {
  if (_JSZip) return _JSZip;
  const mod = await import('jszip');
  _JSZip = mod.default || mod;
  return _JSZip;
};

// ExcelJS のセル値 → 表示テキスト (数式は計算結果, リッチテキストは連結, ハイパーリンクは文字列)
const xlsxCellText_pi = (v) => {
  if (v == null) return '';
  if (typeof v === 'object') {
    if (v instanceof Date) return v.toString();
    if (Array.isArray(v.richText)) return v.richText.map(t => t.text).join('');
    if (v.result != null) return String(v.result);   // 数式セル: 計算結果を使う
    if (v.text != null) return String(v.text);        // ハイパーリンク等
    if (v.formula != null) return '';                 // 数式だが結果なし
    return '';
  }
  return String(v);
};

// 列参照 "B3" → { col:2, row:3 }
const xlsxRefToRC_pi = (ref) => {
  const m = /^([A-Z]+)(\d+)$/.exec(ref || '');
  if (!m) return null;
  let c = 0;
  for (const ch of m[1]) c = c * 26 + (ch.charCodeAt(0) - 64);
  return { col: c, row: parseInt(m[2], 10) };
};

// ExcelJS が読めない xlsx (Google スプレッドシート由来など) を JSZip + DOMParser で直接読み、
//   指定シート(無ければ先頭シート)を「1始まり行 × 1始まり列」の文字列グリッドにする。
//   入荷登録取込のフォールバック用 (load 失敗時)。
const readXlsxGridWithJSZip_pi = async (buf, preferredSheetName) => {
  const JSZip = await loadJSZip();
  const zip = await JSZip.loadAsync(buf);
  const readXml = async (p) => { const f = zip.file(p); return f ? await f.async('string') : null; };
  const parser = new DOMParser();
  const RELNS = 'http://schemas.openxmlformats.org/officeDocument/2006/relationships';

  // 共有文字列
  const shared = [];
  const sstXml = await readXml('xl/sharedStrings.xml');
  if (sstXml) {
    const sdoc = parser.parseFromString(sstXml, 'application/xml');
    sdoc.querySelectorAll('si').forEach(si => {
      let text = '';
      si.querySelectorAll('t').forEach(t => { text += t.textContent || ''; });
      shared.push(text);
    });
  }

  // workbook.xml: シート名 → r:id 、 rels: r:id → ターゲット
  const wbXml = await readXml('xl/workbook.xml');
  if (!wbXml) throw new Error('workbook.xml が見つかりません');
  const wdoc = parser.parseFromString(wbXml, 'application/xml');
  const relsXml = await readXml('xl/_rels/workbook.xml.rels');
  const relMap = {};
  if (relsXml) {
    const rdoc = parser.parseFromString(relsXml, 'application/xml');
    rdoc.querySelectorAll('Relationship').forEach(r => { relMap[r.getAttribute('Id')] = r.getAttribute('Target'); });
  }
  const sheetEls = [...wdoc.getElementsByTagName('sheet')];
  const ridOf = (el) => el.getAttributeNS(RELNS, 'id') || el.getAttribute('r:id') || el.getAttribute('id');
  let chosen = (preferredSheetName && sheetEls.find(s => s.getAttribute('name') === preferredSheetName)) || sheetEls[0];
  let targetPath = 'xl/worksheets/sheet1.xml';
  if (chosen) {
    let tgt = relMap[ridOf(chosen)];
    if (tgt) {
      tgt = tgt.replace(/^\.\//, '');
      targetPath = tgt.startsWith('/') ? tgt.slice(1) : (tgt.startsWith('xl/') ? tgt : 'xl/' + tgt);
    }
  }
  let sheetXml = await readXml(targetPath);
  if (!sheetXml) sheetXml = await readXml('xl/worksheets/sheet1.xml');
  if (!sheetXml) throw new Error('シートXMLが見つかりません');

  const doc = parser.parseFromString(sheetXml, 'application/xml');
  const grid = [];
  const rowEls = doc.getElementsByTagName('row');
  for (let ri = 0; ri < rowEls.length; ri++) {
    const rowEl = rowEls[ri];
    const rNum = parseInt(rowEl.getAttribute('r'), 10) || (ri + 1);
    const cells = [];
    const cEls = rowEl.getElementsByTagName('c');
    for (let ci = 0; ci < cEls.length; ci++) {
      const cEl = cEls[ci];
      const pos = xlsxRefToRC_pi(cEl.getAttribute('r'));
      const colNum = pos ? pos.col : (ci + 1);
      const type = cEl.getAttribute('t');
      let val = '';
      const vEl = cEl.getElementsByTagName('v')[0];
      const isEl = cEl.getElementsByTagName('is')[0];
      if (type === 's') { const idx = parseInt(vEl ? vEl.textContent : '', 10); val = (shared[idx] != null) ? shared[idx] : ''; }
      else if (type === 'inlineStr' && isEl) { const ts = isEl.getElementsByTagName('t'); for (let k = 0; k < ts.length; k++) val += ts[k].textContent || ''; }
      else { val = vEl ? (vEl.textContent || '') : ''; } // str(数式結果) / 数値 / 真偽
      cells[colNum] = val;
    }
    grid[rNum] = cells;
  }
  return grid;
};

// 取込用の柔軟な日付パース → "YYYY-MM-DD"(アプリの正規形式) or ''。
//   対応: "2026/8/15" "2026-8-15"(年先頭) / "7/1/2026" "8/15/2026"(年末尾=Excel/US。M/D優先) /
//         Excelシリアル値(日付型セル) / その他は new Date フォールバック("Tue Jul 01 2026..." 等)。
const parseImportDateToYMD_pi = (raw) => {
  if (raw == null) return '';
  const s = String(raw).trim();
  if (!s) return '';
  let m = s.match(/^(\d{4})[\/\-.](\d{1,2})[\/\-.](\d{1,2})$/); // 年先頭
  if (m) return `${m[1]}-${String(m[2]).padStart(2, '0')}-${String(m[3]).padStart(2, '0')}`;
  m = s.match(/^(\d{1,2})[\/\-.](\d{1,2})[\/\-.](\d{4})$/);      // 年末尾(M/D/YYYY 優先, 月>12なら入替)
  if (m) { let mo = +m[1], da = +m[2]; if (mo > 12 && da <= 12) { const t = mo; mo = da; da = t; } return `${m[3]}-${String(mo).padStart(2, '0')}-${String(da).padStart(2, '0')}`; }
  if (/^\d+(\.\d+)?$/.test(s)) {                                 // Excelシリアル値
    const n = parseFloat(s);
    if (n > 59 && n < 80000) { const d = new Date(Math.round((n - 25569) * 86400000)); if (!isNaN(d.getTime())) return localYMD(d); }
  }
  const t = new Date(s).getTime();                              // フォールバック
  return isNaN(t) ? '' : localYMD(t);
};

