// --- Font Size Configuration ---
const FONT_SIZE_AREAS = [
  { key: 'global', label: '全体ベース', default: 100, min: 70, max: 160, desc: 'アプリ全体の基準文字サイズ' },
  { key: 'header', label: 'ヘッダー・タブ', default: 100, min: 70, max: 160, desc: '上部ナビゲーション・タブ' },
  { key: 'dashboard', label: 'ダッシュボード', default: 100, min: 70, max: 160, desc: 'カード・マップ・ゾーン表示' },
  { key: 'execution', label: '作業実行画面', default: 100, min: 70, max: 160, desc: '作業モーダル・ボタン・タイマー' },
  { key: 'measurement', label: '測定画面 (最大化)', default: 100, min: 70, max: 200, desc: '測定値入力・計算結果 (最大化時)' },
  { key: 'tables', label: 'テーブル・リスト', default: 100, min: 70, max: 160, desc: '検査リスト・完了履歴・分析' },
  { key: 'settings', label: '設定画面', default: 100, min: 70, max: 160, desc: 'マスタ設定・テンプレート編集' },
];

const applyFontSizes = (fontSizes = {}) => {
  const globalScale = (fontSizes.global || 100) / 100;
  document.documentElement.style.fontSize = (16 * globalScale) + 'px';
  const styleId = 'dynamic-font-sizes';
  let styleEl = document.getElementById(styleId);
  if (!styleEl) {
    styleEl = document.createElement('style');
    styleEl.id = styleId;
    document.head.appendChild(styleEl);
  }
  const areas = ['header', 'dashboard', 'tables', 'settings'];
  const rules = areas.map(area => {
    const scale = (fontSizes[area] || 100) / 100;
    if (scale === 1) return '';
    return `[data-fs="${area}"] { zoom: ${scale}; }`;
  }).filter(Boolean);
  // execution: zoom on the fixed container, but compensate dimensions so it stays within viewport
  const execScale = (fontSizes.execution || 100) / 100;
  if (execScale !== 1) {
    rules.push(`[data-fs="execution"] { zoom: ${execScale}; width: ${100 / execScale}vw; height: ${100 / execScale}vh; left: 0; top: 0; transform-origin: top left; }`);
  }
  // measurement: 測定モーダル専用 (最大化時の文字サイズ)
  const measScale = (fontSizes.measurement || 100) / 100;
  if (measScale !== 1) {
    rules.push(`[data-fs="measurement"] { zoom: ${measScale}; width: ${100 / measScale}vw; height: ${100 / measScale}vh; left: 0; top: 0; transform-origin: top left; }`);
  }
  styleEl.textContent = rules.join('\n');
};

// --- Utilities ---
// 衝突防止: crypto.randomUUID 利用可能ならそれを使う、なければ Math.random.
// substr は deprecated なので slice を使用
const generateId = () => {
  try {
    if (typeof crypto !== 'undefined' && crypto.randomUUID) {
      return crypto.randomUUID().replace(/-/g, '').slice(0, 12);
    }
  } catch {}
  return Math.random().toString(36).slice(2, 11) + Math.random().toString(36).slice(2, 5);
};
const formatTime = (sec) => {
  // NaN/undefined/null/負数 を安全にハンドル (旧データ修復時の表示崩れ防止)
  const n = Number(sec);
  if (!Number.isFinite(n) || n < 0) return '0:00';
  const h = Math.floor(n / 3600);
  const m = Math.floor((n % 3600) / 60);
  const s = Math.floor(n % 60);
  if (h > 0) return `${h}:${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}`;
  return `${m.toString().padStart(2,'0')}:${s.toString().padStart(2,'0')}`;
};
const toDatetimeLocal = (timestamp) => {
  const d = new Date(timestamp);
  const pad = (n) => n.toString().padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
};
const toDateShort = (timestamp) => {
  if (!timestamp) return '-';
  const d = new Date(timestamp);
  return `${d.getMonth()+1}/${d.getDate()}`;
};
const formatDateSafe = (ts) => ts ? new Date(ts).toLocaleString() : '-';

// === 画像 容量/画質 制御 ===
// 種別ごとの既定 (低画質スタート=容量節約)。settings.imageQuality で上書きし、syncImageQuality で反映。
const DEFAULT_IMG_QUALITY = {
  workStandard: { maxDim: 800,  quality: 0.55 }, // 作業標準
  defectPhoto:  { maxDim: 1000, quality: 0.6  }, // 不良写真
  packingPhoto: { maxDim: 800,  quality: 0.55 }, // 荷姿写真
  serialAI:     { maxDim: 1280, quality: 0.72 }, // 機番AI認識 (精度のため少し高め)
  diagram:      { maxDim: 1000, quality: 0.6  }, // 測定図
  default:      { maxDim: 900,  quality: 0.6  },
};
let IMG_QUALITY = { ...DEFAULT_IMG_QUALITY };
// settings.imageQuality を IMG_QUALITY に同期 (アプリ起動時/設定変更時に呼ぶ)
const syncImageQuality = (cfg) => {
  const next = { ...DEFAULT_IMG_QUALITY };
  if (cfg && typeof cfg === 'object') Object.keys(cfg).forEach(k => { next[k] = { ...(next[k] || DEFAULT_IMG_QUALITY.default), ...(cfg[k] || {}) }; });
  IMG_QUALITY = next;
};
// resizeImage(file, type) / resizeImage(file, { maxDim, quality }) の両対応
const resizeImage = (file, typeOrOpts = 'default') => new Promise((resolve) => {
  const o = (typeof typeOrOpts === 'object') ? typeOrOpts : (IMG_QUALITY[typeOrOpts] || IMG_QUALITY.default);
  const MAX = o.maxDim || 900; const Q = (typeof o.quality === 'number') ? o.quality : 0.6;
  const r = new FileReader(); r.onload = (e) => { const i = new Image(); i.onload = () => { const c = document.createElement('canvas'); let w=i.width; let h=i.height; if(w>h){if(w>MAX){h*=MAX/w;w=MAX}}else{if(h>MAX){w*=MAX/h;h=MAX}} c.width=w; c.height=h; const ctx=c.getContext('2d'); if(ctx){ctx.drawImage(i,0,0,w,h); resolve(c.toDataURL('image/jpeg', Q));}else resolve(i.src); }; i.src = e.target?.result; }; r.readAsDataURL(file); });
const getBase64 = (file) => new Promise((resolve) => { const r = new FileReader(); r.readAsDataURL(file); r.onload = () => resolve(r.result); r.onerror = () => resolve(""); });

// === 時間ソース一本化 (2026-05-31) ===
// 「工程改善・目標時間最適化」タブが算出した較正値 (settings.customTargetTimes) を
// 実際の目標時間として使うための単一ヘルパー。
// 優先順位: 型式別較正値 (customTargetTimes[model_型式][category_title]) > step.targetTime (テンプレ既定)
//
// キー形式 (ProcessInsightsTab と一致させる):
//   savedKey = `model_${model}`
//   stepKey  = `${step.category || ''}_${step.title}`
const targetTimeStepKey = (step) => `${step?.category || ''}_${step?.title || ''}`;
const getEffectiveTargetTime = (step, model, customTargetTimes, modelGroups = null) => {
  if (!step) return 0;
  const fallback = step.targetTime || 0;
  if (!model || !customTargetTimes) return fallback;
  const sk = targetTimeStepKey(step);
  const own = customTargetTimes[`model_${model}`]?.[sk];
  if (typeof own === 'number' && own > 0) return own;
  // 型式グループ: 自型式に較正値が無ければ同グループ型式の値を引き継ぐ(目標時間のデータ共有)
  if (modelGroups && Array.isArray(modelGroups)) {
    const g = modelGroups.find(gr => Array.isArray(gr?.models) && gr.models.includes(model));
    if (g) for (const sm of g.models) {
      if (sm === model) continue;
      const v = customTargetTimes[`model_${sm}`]?.[sk];
      if (typeof v === 'number' && v > 0) return v;
    }
  }
  return fallback;
};

// === ロット1回(段取り)工程 ===
// step.lotOnce === true の工程は「台数分」ではなく「実施回数分」のタスクを持つ (準備・片付け等)。
// タスクキー: `${step.id}-lot-${k}` (k=0,1,2..)。5台ずつ持ち込み等で準備が複数回発生したら「＋もう1回」で回を追加。
// 目標時間(step.targetTime/較正値)は「1回あたり」の意味になる。
const LOT_ONCE_RE = /^(.+)-lot-(\d+)$/;
const lotOnceKeysOf = (tasks, step) => Object.keys(tasks || {})
  .filter(k => k.startsWith(`${step?.id}-lot-`))
  .sort((a, b) => parseInt(a.slice(a.lastIndexOf('-') + 1)) - parseInt(b.slice(b.lastIndexOf('-') + 1)));
const lotOnceCountOf = (tasks, step) => Math.max(1, lotOnceKeysOf(tasks, step).length); // 表示/分母用 (最低1回)

// === 改善PDCA: 効果測定エンジン (純関数) ===
// 指定の型式×工程×期間窓で、時間統計(平均/中央値/σ/CV/最小最大)・達成率・不具合件数を出す。
// 窓は「タスク完了時刻(endTime優先, 無ければロット完了/更新時刻)」で切る (updatedAtは作業中ロットで揺れるため標本の時刻には使わない)。
const toMsAny = (raw) => {
  if (raw == null) return null;
  if (typeof raw === 'number') return raw;
  // Firestore Timestamp: 真のミリ秒 = seconds*1000 + nanoseconds/1e6 (他の toMs 実装と一貫化。
  //   nanoseconds を落とすと同一秒内の複数完了で微小時刻差が失われ PDCA/年間台数の窓判定がズレる)
  if (raw.seconds) return raw.seconds * 1000 + Math.floor((raw.nanoseconds || 0) / 1e6);
  const t = new Date(raw).getTime();
  return isNaN(t) ? null : t;
};
// CSVセルのエスケープ。カンマ/引用符/改行を含む値(型式名・指図名のユーザー入力や toLocaleString のカンマ)を
// 正しく引用し、列ずれ・破損を防ぐ。RFC4180準拠(" は "" にエスケープ)。
const csvCell = (v) => { const s = String(v ?? ''); return /[",\r\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s; };
// PDCA_MIN_N / PDCA_THRESHOLD_PCT / PDCA_STALE_DAYS は src/domain/goal/verdictEngine.js に移動 (import済)
const measureWindow = (lots, { model, stepKey, templateId, customTargetTimes = {}, modelGroups = [], startMs = 0, endMs = Infinity } = {}) => {
  const samples = []; // {d, tgt}
  let defectCount = 0, unitsSeen = 0, lotsSeen = 0;
  const titlePart = stepKey ? (stepKey.includes('_') ? stepKey.slice(stepKey.indexOf('_') + 1) : stepKey) : null;
  (lots || []).forEach(l => {
    if (!l) return;
    if (model && l.model !== model) return;
    // テンプレ指定時はそのテンプレのロットだけに絞る (同名工程でも検査の種類が違えば別作業=混ぜると中央値が嘘になる)
    if (templateId && l.templateId !== templateId) return;
    // 不具合件数: 不具合自身の timestamp で窓を切る。完了/作業中に関係なく数える
    // (defectStatsと対称=saveDataがupdatedAtを更新する作業中ロットの不具合を落とさない。完了ゲートより前で数える)
    (l.interruptions || []).filter(i => i.type === 'defect').forEach(dft => {
      const ms = toMsAny(dft.timestamp);
      if (ms == null || ms < startMs || ms > endMs) return;
      if (titlePart && (dft.stepInfo?.title || '') !== titlePart) return;
      defectCount++;
    });
    // 時間統計の標本は完了ロットのみ (作業中の途中durationを混ぜない)
    if (l.status !== 'completed' && l.location !== 'completed') return;
    const lotMs = toMsAny(l.completedAt) || toMsAny(l.updatedAt);
    let lotHasStep = !stepKey; // 検査機会(unitsSeen)の分母: この窓・このフィルタに該当するロットの台数
    (l.steps || []).forEach((step, idx) => {
      if (stepKey && targetTimeStepKey(step) !== stepKey) return;
      lotHasStep = true;
      const effTarget = getEffectiveTargetTime(step, l.model, customTargetTimes, modelGroups);
      const keys = step.lotOnce
        ? lotOnceKeysOf(l.tasks || {}, step)
        : Array.from({ length: l.quantity || 1 }, (_, i) => ((l.tasks || {})[`${step.id}-${i}`] !== undefined ? `${step.id}-${i}` : `${idx}-${i}`));
      keys.forEach(k => {
        const t = (l.tasks || {})[k];
        if (!t) return;
        if (t.status !== 'completed' && t.status !== 'ng') return;
        if (t.samplingSkipped) return;
        const d = t.duration || 0; if (d <= 0) return;
        const ms = toMsAny(t.endTime) || lotMs;
        if (ms == null || ms < startMs || ms > endMs) return;
        samples.push({ d, tgt: effTarget });
      });
    });
    // 検査機会: 窓内に完了した該当ロットの台数(抜取でスキップした台も分母に入る=実施率の分母)
    if (lotHasStep && lotMs != null && lotMs >= startMs && lotMs <= endMs) { lotsSeen++; unitsSeen += (l.quantity || 1); }
  });
  const ds = samples.map(x => x.d).sort((a, b) => a - b);
  const n = ds.length;
  const sum = ds.reduce((a, b) => a + b, 0);
  const mean = n ? sum / n : 0;
  const median = n ? (n % 2 ? ds[(n - 1) / 2] : (ds[n / 2 - 1] + ds[n / 2]) / 2) : 0;
  const variance = n ? ds.reduce((a, b) => a + (b - mean) ** 2, 0) / n : 0;
  const sigma = Math.sqrt(variance);
  const sumTgt = samples.reduce((a, x) => a + (x.tgt || 0), 0);
  const within = samples.filter(x => x.tgt > 0 && x.d <= x.tgt).length;
  return {
    n, mean: Math.round(mean), median: Math.round(median), sigma: Math.round(sigma),
    cv: mean > 0 ? Math.round((sigma / mean) * 1000) / 1000 : 0,
    min: n ? ds[0] : 0, max: n ? ds[n - 1] : 0,
    achievementRate: sum > 0 && sumTgt > 0 ? Math.round((sumTgt / sum) * 1000) / 10 : null,
    within, sumTgt, sumAct: sum, defectCount, unitsSeen, lotsSeen,
    avgTarget: n ? Math.round(sumTgt / n) : 0, // 1台(1回)あたりの実効目標秒 (儲けどころの短縮余地算出に使う)
    startMs, endMs, days: (isFinite(endMs) && startMs > 0) ? Math.max(1, (endMs - startMs) / 86400000) : null,
  };
};
// 儲けどころランキング: 型式×工程ごとに「年間台数 × 実績中央値 × 時給」で年間人件費・年間削減見込(円)を出す純関数。
// reductionPerUnit = max(0, 実績中央値 − 目標)。年間台数は窓内標本を365日換算。低頻度(年lowFreq台未満)は flag。
const profitRanking = (lots, settings, { startMs = 0, endMs = Infinity, ratePerHour = 0, lowFreq = 10, annualUnitsByModel = null, byTemplate = false, templates = null, autoLaborPct = 100 } = {}) => {
  const customTargetTimes = settings?.customTargetTimes || {};
  const modelGroups = modelGroupsOf(settings);
  const rate = ratePerHour || settings?.laborCostPerHour || 0;
  const tplNameOf = (id) => (id && (templates || []).find(t => t.id === id)?.name) || '';
  const rows = [];
  // byTemplate: 集計単位を「型式×テンプレ×工程」に分ける。同じ型式でも検査の種類(テンプレ)が違えば
  //   同名工程の中身は別作業(実測: RTT-311,ZD 傾斜分割測定はテンプレ間で中央値8.2倍差) — 混ぜると中央値も目標乖離も嘘になる。
  const pre = [];
  const items = byTemplate ? enumerateModelTplSteps(lots) : enumerateModelSteps(lots);
  items.forEach(ms => {
    const stat = measureWindow(lots, { model: ms.model, stepKey: ms.stepKey, templateId: byTemplate ? ms.templateId : undefined, customTargetTimes, modelGroups, startMs, endMs });
    if (stat.n < 1) return;
    pre.push({ ms, stat });
  });
  // 登録年間台数(型式単位)の扱い(仕様4.3): 台数をそのまま回数にしない。
  //   年間実施回数 = 登録台数 × 窓内実施率(実施回数÷対象台数)。抜取1/10なら1/10回、ロット1回工程はロット回数になる。
  //   テンプレ分割時は同じ型式×工程の全テンプレ行の対象台数合計で割る=二重計上の物理的防止。
  const unitsByModelStep = {};
  if (byTemplate) pre.forEach(p => { const k = `${p.ms.model}||${p.ms.stepKey}`; unitsByModelStep[k] = (unitsByModelStep[k] || 0) + (p.stat.unitsSeen || 0); });
  pre.forEach(({ ms, stat }) => {
    const days = pdcaWindowDays(stat) || 365;
    const measuredAnnual = Math.round(stat.n * (365 / days)); // 実測回数の年換算(未登録時の既定・回数ベースなので工程タイプに依らず正しい)
    const inputAnnual = annualUnitsByModel ? annualUnitsByModel[ms.model] : null;
    const useActual = typeof inputAnnual === 'number' && inputAnnual > 0;
    const windowUnits = byTemplate ? (unitsByModelStep[`${ms.model}||${ms.stepKey}`] || 0) : (stat.unitsSeen || 0);
    const { occ, source: occSource } = annualOccurrencesOf({ useActual, inputAnnualUnits: inputAnnual || 0, windowExecs: stat.n, windowUnits, measuredAnnualExecs: measuredAnnual });
    const annualUnits = occ; // フィールド名は互換のため維持(意味は「年間実施回数」)
    const annualUnitsSource = occSource;
    const median = stat.median || 0;
    const target = stat.avgTarget || 0;
    const reductionPerUnit = target > 0 ? Math.max(0, median - target) : 0; // 目標未設定は削減見込0(過大評価しない)
    // 🤖自動運転の分離: 自動工程は拘束率(autoLaborPct%)分だけ人件費、全時間は機械時間として別集計(混ぜない)。
    const workKind = ms.auto ? 'auto' : 'manual';
    const costSecRaw = annualUnits * median, saveSecRaw = annualUnits * reductionPerUnit;
    const annualCostSec = Math.round(laborSecOf({ workKind, sec: costSecRaw, autoLaborPct }));
    const annualSaveSec = Math.round(laborSecOf({ workKind, sec: saveSecRaw, autoLaborPct }));
    const machineCostSec = Math.round(machineSecOf({ workKind, sec: costSecRaw }));
    const machineSaveSec = Math.round(machineSecOf({ workKind, sec: saveSecRaw }));
    rows.push({
      ...ms, templateId: ms.templateId || '', templateName: tplNameOf(ms.templateId),
      n: stat.n, annualUnits, measuredAnnual, annualUnitsSource, median, target, sigma: stat.sigma, cv: stat.cv,
      reductionPerUnit, workKind, annualCostSec, annualSaveSec, machineCostSec, machineSaveSec,
      annualCostYen: Math.round(annualCostSec / 3600 * rate), annualSaveYen: Math.round(annualSaveSec / 3600 * rate),
      hasTarget: target > 0, lowFreq: annualUnits < lowFreq,
    });
  });
  // 削減見込(¥)優先、同値や時給未設定なら年間コスト(=工数の山=割合が多い所)でソート
  rows.sort((a, b) => (b.annualSaveYen - a.annualSaveYen) || (b.annualCostSec - a.annualCostSec));
  const useYen = rate > 0;
  // 累積%(年間人件費=コスト集中のパレート)
  const totalCost = rows.reduce((s, r) => s + r.annualCostSec, 0) || 1;
  let cum = 0;
  rows.forEach(r => { cum += r.annualCostSec; r.cumPct = Math.round(cum / totalCost * 100); });
  return {
    rows, rate, useYen,
    totalSaveYen: rows.reduce((s, r) => s + r.annualSaveYen, 0),
    totalSaveSec: rows.reduce((s, r) => s + r.annualSaveSec, 0),
    totalCostYen: rows.reduce((s, r) => s + r.annualCostYen, 0),
    totalCostSec: totalCost,
    // 🤖機械時間(設備能力・納期効果): 人件費とは別枠で報告する(混ぜない)
    totalMachineSec: rows.reduce((s, r) => s + (r.machineCostSec || 0), 0),
    totalMachineSaveSec: rows.reduce((s, r) => s + (r.machineSaveSec || 0), 0),
    autoLaborPct,
  };
};
// 共通工程 横断改善: profitRanking の「型式×工程」行を、工程タイトルで型式横断にまとめ直す純関数。
//   「この工程は何型式に共通か」「全型式合計で年いくらかかっているか」と、3つの改善余地を出す:
//   ① 最速の型式に揃える(実証済み=現に一番速い型式の中央値まで全型式を揃えたら) ② ◯%短縮の仮定(レイアウト改善等の大改善)
//   ③ 目標まで詰める(堅実な下限)。狙い=共通ポイントを1つ直すと全型式に効く=大きい、を可視化する。
const crossStepRanking = (lots, settings, { startMs = 0, endMs = Infinity, ratePerHour = 0, reductionPct = 0.5, annualUnitsByModel = null, byTemplate = false, templates = null, autoLaborPct = 100 } = {}) => {
  const base = profitRanking(lots, settings, { startMs, endMs, ratePerHour, lowFreq: 0, annualUnitsByModel, byTemplate, templates, autoLaborPct });
  const rate = base.rate;
  const groups = {};
  base.rows.forEach(r => {
    // 工程タイトル(category_title の title 部分)でまとめる。profitDetail の型式横断比較と同じ粒度。
    const title = r.stepTitle || (r.stepKey && r.stepKey.includes('_') ? r.stepKey.slice(r.stepKey.indexOf('_') + 1) : r.stepKey) || '(不明)';
    (groups[title] = groups[title] || { title, rows: [] }).rows.push(r);
  });
  const out = Object.values(groups).map(g => {
    const rows = g.rows.slice().sort((a, b) => a.median - b.median); // 速い順(先頭=最速型式)
    const modelCount = new Set(rows.map(r => r.model)).size; // byTemplate時は同型式が複数行になるためユニーク型式数で数える
    const actualModels = rows.filter(r => r.annualUnitsSource === 'actual').length; // 実際の年間台数を入力済の型式数
    const annualUnits = rows.reduce((s, r) => s + r.annualUnits, 0);
    const annualCostSec = rows.reduce((s, r) => s + r.annualCostSec, 0);
    const annualCostYen = rows.reduce((s, r) => s + r.annualCostYen, 0);
    // ① 最速の型式に揃える: 一番速い型式の中央値まで、それより遅い型式を全部揃えたら浮く分
    const fastest = rows.reduce((m, r) => (r.median < m ? r.median : m), Infinity);
    const fastestModel = (rows.find(r => r.median === fastest) || {}).model || '';
    const slowest = rows.reduce((m, r) => (r.median > m ? r.median : m), 0);
    const saveToFastestSec = rows.reduce((s, r) => s + r.annualUnits * Math.max(0, r.median - fastest), 0);
    // ② ◯%短縮の仮定: 全型式合計時間 × 短縮率
    const saveByPctSec = Math.round(annualCostSec * reductionPct);
    // ③ 目標まで: 各型式の目標までの削減見込(profitRanking が算出済)の合計。目標未設定型式は0。
    const saveToTargetSec = rows.reduce((s, r) => s + r.annualSaveSec, 0);
    const hasTargetAny = rows.some(r => r.hasTarget);
    const yenOf = (sec) => (rate > 0 ? Math.round(sec / 3600 * rate) : 0);
    return {
      title: g.title, modelCount, actualModels, models: rows, annualUnits, annualCostSec, annualCostYen,
      fastest: isFinite(fastest) ? fastest : 0, fastestModel, slowest,
      saveToFastestSec, saveToFastestYen: yenOf(saveToFastestSec),
      saveByPctSec, saveByPctYen: yenOf(saveByPctSec),
      saveToTargetSec, saveToTargetYen: yenOf(saveToTargetSec), hasTargetAny,
    };
  });
  // 全型式合計の年間コスト(=工数の山)が大きい順 = 横断で直すと効果が大きい順
  out.sort((a, b) => b.annualCostSec - a.annualCostSec);
  return { groups: out, rate, reductionPct };
};
// ===== 🎯 年間目標レイヤー (会社目標から逆算する装置) =====
// 会社/グループの年間目標(時間10%削減・改善金額◯円)に対して「確定/実施中見込み/候補在庫」を積み上げ、残りを見える化する。
// 設定は3アプリ共有の名前空間 goal-shared-v1 (連絡の contact-shared-v1 と同じ方式)。金額 = 時間短縮 × チャージ額(円/h・年度別)。
const GOAL_SHARED_NS = 'goal-shared-v1';
const GOAL_DEFAULT_YEAR = { reductionPct: 10, moneyTargetYen: 1000000, chargePerHour: 2800 };
// 年度: 既定は12月開始〜11月終わり(設定で変更可)。年度キーは「終わる年」(例: 2025/12/1〜2026/11/30 → "2026")。
const fiscalYearOf = (nowMs, startMonth = 12) => {
  const d = new Date(nowMs);
  const y = d.getFullYear();
  const m = d.getMonth() + 1;
  const sm = Math.min(12, Math.max(1, Number(startMonth) || 12));
  const startYear = (m >= sm) ? y : y - 1;
  const startMs = new Date(startYear, sm - 1, 1).getTime();
  const endMs = new Date(startYear + 1, sm - 1, 1).getTime() - 1;
  const key = String(sm === 1 ? startYear : startYear + 1);
  const endMonth = sm === 1 ? 12 : sm - 1;
  return { key, startMs, endMs, label: `${key}年度（${startYear}/${sm}〜${sm === 1 ? startYear : startYear + 1}/${endMonth}）` };
};
// 記録データの開始時刻: 完了タスクの最古 endTime (無ければロット完了時刻)。年間換算の窓決めに使う。
const dataStartMsOf = (lots) => {
  let min = Infinity;
  (lots || []).forEach(l => {
    const lotMs = toMsAny(l.completedAt) || toMsAny(l.updatedAt);
    Object.values(l.tasks || {}).forEach(t => {
      if (!t || (t.status !== 'completed' && t.status !== 'ng')) return;
      if ((t.duration || 0) <= 0) return;
      const ms = toMsAny(t.endTime) || lotMs;
      if (ms != null && ms > 0 && ms < min) min = ms;
    });
  });
  return isFinite(min) ? min : null;
};
// ⚠年間換算の要: 365日窓だと、データがまだ浅い時期(実測: 2026年は5月開始)に「年間◯円」が1/4等に過小化する。
//   → 直近90日(データがそれより浅ければ有る分だけ)の実測ペース×365で年換算する。登録年間台数(経営分析)があれば最優先(profitRanking側で処理)。
const goalMeasureWindow = (lots, nowMs) => {
  const dataStartMs = dataStartMsOf(lots);
  const start90 = nowMs - 90 * 86400000;
  const startMs = dataStartMs != null ? Math.max(dataStartMs, start90) : start90;
  return { startMs, endMs: nowMs, days: Math.max(7, (nowMs - startMs) / 86400000), dataStartMs };
};
// 1アプリ分の目標視点サマリ: 既存 profitRanking を「実ペース窓」で呼ぶだけ(数式は重点工程ランキングと同一・検証済み)。
// excessRatio = 原資÷年間コスト。大きすぎる(>0.3)時は目標時間の未較正を疑う(最終検査で実測57%)。
const goalAppSummary = (lots, settings, { nowMs, chargePerHour, annualUnitsByModel = null, templates = null, autoLaborPct = 100 }) => {
  const win = goalMeasureWindow(lots, nowMs);
  // byTemplate: 型式×テンプレ×工程 単位で集計 (テンプレ概念の無いアプリ=最終検査はtemplateId空で従来と同じ束になる)
  const ranking = profitRanking(lots, settings, { startMs: win.startMs, endMs: win.endMs, ratePerHour: chargePerHour, lowFreq: 0, annualUnitsByModel, byTemplate: true, templates, autoLaborPct });
  const excessRatio = ranking.totalCostSec > 0 ? ranking.totalSaveSec / ranking.totalCostSec : 0;
  return { win, ranking, excessRatio };
};
// 改善カルテの金額換算: 1台あたり短縮秒 × 年間台数 × チャージ。
//   確定(effective) = 凍結before/afterの実測差。実施中 = 目標まで詰めた場合の見込み(原資と同じ式)。時間KPI以外のカルテは金額換算しない(捏造しない)。
const goalCardYen = (card, rows, annualUnitsByModel, chargePerHour) => {
  if (card.kpi && card.kpi !== 'time') return { kind: 'nonTime', yen: 0, perUnitSec: 0, units: 0 };
  // rows は 型式×テンプレ×工程 単位。カルテにテンプレがあればその行だけ、無ければ(旧カルテ)全テンプレ行の合算。
  const all = rows.filter(r => r.model === card.model && r.stepKey === card.stepKey);
  const tplRows = card.templateId ? all.filter(r => (r.templateId || '') === card.templateId) : all;
  const rowsM = tplRows.length ? tplRows : all;
  const sumUnits = rowsM.reduce((s, r) => s + r.annualUnits, 0);
  const reg = annualUnitsByModel && Number(annualUnitsByModel[card.model]);
  // 行の annualUnits は登録台数を按分済み。行が無い時だけ登録台数を直接使う(旧挙動の温存)。
  const units = sumUnits > 0 ? sumUnits : ((reg > 0) ? reg : 0);
  if (card.status === 'effective' && card.verdictFrozen && card.baseline) {
    const b = Number(card.verdictFrozen.beforeVal ?? card.baseline.median) || 0;
    const a = Number(card.verdictFrozen.afterVal) || 0;
    const per = Math.max(0, b - a);
    return { kind: 'fixed', yen: Math.round(units * per / 3600 * chargePerHour), perUnitSec: per, units };
  }
  const per = sumUnits > 0 ? rowsM.reduce((s, r) => s + r.annualSaveSec, 0) / sumUnits : 0;
  return { kind: 'running', yen: Math.round(units * per / 3600 * chargePerHour), perUnitSec: per, units };
};
// 10%レンズ②「台あたり時間」: 年度内でデータがある最初の4週(基準) vs 直近4週。同じ型式×工程で両窓 n>=3 の行だけを直近台数で加重平均(型式ミックスの変化に歪まされない)。
const goalPerUnitLens = (lots, settings, { fiscalStartMs, nowMs }) => {
  const ds = dataStartMsOf(lots);
  const baseStart = Math.max(fiscalStartMs, ds ?? fiscalStartMs);
  const baseEnd = baseStart + 28 * 86400000;
  const curStart = nowMs - 28 * 86400000;
  if (curStart <= baseEnd) return { ok: false, reason: 'データがまだ8週未満（基準4週と直近4週が分離できるまでお待ちください）' };
  const ctt = settings?.customTargetTimes || {};
  const groups = modelGroupsOf(settings);
  let wSum = 0, wBase = 0, rows = 0;
  // 型式×テンプレ×工程 単位で比較 (テンプレ構成が月で変わっても、同じ作業同士の比較になる)
  enumerateModelTplSteps(lots).forEach(msr => {
    const b = measureWindow(lots, { model: msr.model, stepKey: msr.stepKey, templateId: msr.templateId || undefined, customTargetTimes: ctt, modelGroups: groups, startMs: baseStart, endMs: baseEnd });
    const c = measureWindow(lots, { model: msr.model, stepKey: msr.stepKey, templateId: msr.templateId || undefined, customTargetTimes: ctt, modelGroups: groups, startMs: curStart, endMs: nowMs });
    if (b.n < 3 || c.n < 3) return;
    rows++;
    wBase += b.median * c.n;
    wSum += c.median * c.n;
  });
  if (!rows || wBase <= 0) return { ok: false, reason: '基準期間と直近の両方に3台以上ある工程がまだ無い' };
  return { ok: true, pct: Math.round((1 - wSum / wBase) * 1000) / 10, rows, baseStart, baseEnd, curStart };
};
// 貯金箱の集計 (🎯タブと週次ブリーフの両方がこの1関数を使う=数字が食い違わない)。
// 最終検査カルテの「今年度 実実施回数」: golden lots を項目キーで数える(実測=推定でない今年度実績のため)
const goldenExecCountFI = (goldenLots, { itemKey, model = '', startMs, endMs }) => {
  let execs = 0;
  (goldenLots || []).forEach(l => {
    if (model && l.model !== model) return;
    const tasks = l.tasks || {}; const qty = l.quantity || 1;
    const lotMs = toMsAny(l.completedAt) || toMsAny(l.updatedAt);
    (l.steps || []).forEach((step, idx) => {
      if (`${step.category || ''}_${step.title || ''}` !== itemKey) return;
      for (let u = 0; u < qty; u++) {
        const k = tasks[`${step.id}-${u}`] !== undefined ? `${step.id}-${u}` : `${idx}-${u}`;
        const t = tasks[k];
        if (!t || (t.status !== 'completed' && t.status !== 'ng')) continue;
        if ((t.duration || 0) <= 0) continue;
        const ms = toMsAny(t.endTime) || lotMs;
        if (ms == null || ms < startMs || ms > endMs) continue;
        execs++;
      }
    });
  });
  return execs;
};
const goalBankOf = ({ improvements, prodRows, goldenTotalSaveYen = 0, includeGolden = true, annualUnitsByModel, charge, goldenFixedYen = 0, goldenProvisionalYen = 0, partsTotalSaveYen = 0 }) => {
  // 確定(verified)=効果あり判定+30日定着確認済みだけ。効果あり直後は暫定(provisional)。定着崩れ(broken)はどちらにも入れない。
  const fixed = [], provisional = [], broken = [], running = [];
  (improvements || []).forEach(c => {
    if (!c || !c.model || !c.stepKey) return;
    if (c.status === 'effective') {
      const m = goalCardYen(c, prodRows, annualUnitsByModel, charge);
      if (m.kind !== 'fixed') return;
      const stage = cardStageOf(c);
      if (stage === 'verified') fixed.push({ c, m });
      else if (stage === 'broken') broken.push({ c, m });
      else provisional.push({ c, m });
    }
    else if (['plan', 'doing', 'measuring'].includes(c.status)) { const m = goalCardYen(c, prodRows, annualUnitsByModel, charge); if (m.kind === 'running') running.push({ c, m }); }
  });
  // 進行中カルテと同じ場所の在庫は二重計上しない。テンプレ付きカルテはそのテンプレ行だけ、旧カルテ(テンプレ無し)は全テンプレ行を塞ぐ。
  const openKeys = new Set(running.map(x => x.c.templateId ? `${x.c.model}||${x.c.templateId}||${x.c.stepKey}` : `${x.c.model}||${x.c.stepKey}`));
  const rowBlocked = (r) => openKeys.has(`${r.model}||${r.stepKey}`) || openKeys.has(`${r.model}||${r.templateId || ''}||${r.stepKey}`);
  const stockProdYen = prodRows.filter(r => !rowBlocked(r)).reduce((s, r) => s + r.annualSaveYen, 0);
  const stockGoldenYen = includeGolden ? goldenTotalSaveYen : 0;
  // 確定 = 製品のverifiedカルテ + 最終検査のverifiedカルテ。暫定は別バケツ(混ぜて「達成」と呼ばない)。
  const fixedProdYen = fixed.reduce((s, x) => s + x.m.yen, 0);
  const provisionalProdYen = provisional.reduce((s, x) => s + x.m.yen, 0);
  return {
    fixed, provisional, broken, running, openKeys, rowBlocked,
    fixedProdYen, fixedGoldenYen: goldenFixedYen,
    fixedYen: fixedProdYen + (goldenFixedYen || 0),
    provisionalProdYen, provisionalGoldenYen: goldenProvisionalYen,
    provisionalYen: provisionalProdYen + (goldenProvisionalYen || 0),
    runningYen: running.reduce((s, x) => s + x.m.yen, 0),
    stockProdYen, stockGoldenYen, stockPartsYen: partsTotalSaveYen || 0,
    stockYen: stockProdYen + stockGoldenYen + (partsTotalSaveYen || 0),
  };
};
// ===== 🔔 改善エンジン: 週次ブリーフ (自動巡回 → 発見 → 催促 → プッシュ) =====
// 週1回、その週最初にアプリを開いた端末が1回だけ生成する。docId=週の月曜日付で決め打ち
//   (多端末の二重生成/二重送信を物理的に防ぐ・完了連絡の教訓と同方式)。生成物は共有docなので全端末で同じ物が見える。
// カルテ化/却下の「人の判断」も brief doc の decisions(map) に共有保存する(端末ローカルに置かない・配列にしない)。
const goalWeekKey = (nowMs) => {
  const d = new Date(nowMs);
  const dow = (d.getDay() + 6) % 7; // 月曜=0
  const mon = new Date(d.getFullYear(), d.getMonth(), d.getDate() - dow);
  return `${mon.getFullYear()}-${String(mon.getMonth() + 1).padStart(2, '0')}-${String(mon.getDate()).padStart(2, '0')}`;
};
// エンジンの細かい設定(3アプリ共有 goal-shared-v1 の engine map・⚙目標の設定から変更可)。ここは既定値。
const GOAL_ENGINE_DEFAULTS = {
  stallDays: 10,        // ⏰催促: カルテがこの日数動かなければ催促
  mineMinYen: 20000,    // ⛰価値下限: 年この金額未満の原資は出さない(目標に効かないカードで埋めない)
  mineCount: 3,         // ⛰山の件数: 1回のブリーフに出す原資カードの数
  breakTolPct: 5,       // 🧱崩れ: 定着後の中央値が+この%を超えて悪化したら警告
  trendPct: 15,         // 📈兆し: 直近4週が前4週より+この%以上遅くなったら警告
  commonMinModels: 3,   // 🔗共通ポイント: 何型式以上に共通する工程を対象にするか
  commonPct: 10,        // 🔗共通ポイント: 「◯%削ったら」の仮定%
  autoLaborPct: 100,    // 🤖自動運転中の人拘束率%: 100=全額人件費(従来・上限値)。現場実態に合わせて下げると純自動時間が人件費から外れる
  successRatePct: 70,   // 🧮改善の成功率%: 必要計画在庫=残り÷成功率 (全候補は成功しない前提の割増・仕様2)
  maxActive: 3,         // 🚦同時進行カルテの上限: 超えたら新規より停滞解消を優先(仕様5.2)
  briefEnabled: true,   // 📬週次ブリーフの自動生成
  pushEnabled: true,    // 🔔管理者へのプッシュ
};
const goalEngineOf = (goalCfg) => ({ ...GOAL_ENGINE_DEFAULTS, ...((goalCfg && goalCfg.engine) || {}) });
const GOAL_STALL_DAYS = GOAL_ENGINE_DEFAULTS.stallDays;
const GOAL_MINE_MIN_YEN = GOAL_ENGINE_DEFAULTS.mineMinYen;
const GOAL_BREAK_TOL = 1 + GOAL_ENGINE_DEFAULTS.breakTolPct / 100;
const goalCardLastMs = (c) => {
  const logs = Array.isArray(c?.log) ? c.log : [];
  const lastLog = logs.length ? (logs[logs.length - 1]?.ts || 0) : 0;
  return Math.max(toMsAny(c?.updatedAt) || 0, lastLog || 0, c?.createdAt || 0);
};
// 「何をもって減らすか」の手段ヒント(決定論)。決め手が無い時も「なぜ良いポイントか」を必ず言う(清水の指示:
//   減らし方が無いなら無いで良いが、"ここは全部に効く良いポイントだから工夫を考えて"と伝わる形にする)。
const goalMethodHint = ({ stepTitle = '', cv = null }) => {
  const t = stepTitle || '';
  if (/測定|自動|分割/.test(t)) return '💡 減らし方: この時間の多くは機械が回っている時間＋待ちの疑いです。作業を急ぐのではなく、待っている間に他の台・他の工程を進める(並行作業)のが本命です。';
  if (cv != null && cv >= 0.4) return '💡 減らし方: 回によって時間がバラバラ＝やり方が揃っていません。一番速い回のやり方をエース動画に撮って標準にするのが近道です。';
  if (cv != null && cv > 0) return '💡 減らし方: 毎回同じだけ時間がかかる＝やり方そのものか目標の問題。じっと見る(要素分割)で中身を測るか、治具・置き場・手順の見直しを。';
  return '💡 決まった手はまだありません。ただし年間の時間が大きい山なので、ここに効く工夫は何でもそのまま利益になります。まず現場で「なぜ時間がかかるか」を1回観察するところから。';
};
// ブリーフ本体を組み立てる純関数。findings は fid キーの map。
const buildWeeklyBrief = ({ nowMs, fy, yearCfg, lots, settings, improvements, golden, parts = null, annualUnitsByModel, templates = null, engine = GOAL_ENGINE_DEFAULTS }) => {
  const charge = Number(yearCfg.chargePerHour) || GOAL_DEFAULT_YEAR.chargePerHour;
  const moneyTarget = Number(yearCfg.moneyTargetYen) || 0;
  const ctt = settings?.customTargetTimes || {};
  const groups = modelGroupsOf(settings);
  const sumProd = goalAppSummary(lots, settings, { nowMs, chargePerHour: charge, annualUnitsByModel, templates, autoLaborPct: engine.autoLaborPct });
  const sumGolden = golden ? goalAppSummary(golden.lots, golden.settings, { nowMs, chargePerHour: charge, autoLaborPct: engine.autoLaborPct }) : null;
  const goldenSuspect = !!(sumGolden && sumGolden.excessRatio > 0.3);
  // 最終検査カルテ: verified(30日定着済)だけが確定。効果あり直後は暫定。
  const gEff = golden ? (golden.improvements || []).filter(c => c && c.status === 'effective' && c.verdictFrozen?.yenPerYear > 0) : [];
  const goldenFixedYen = gEff.filter(c => (c.verifiedStage || 'provisional') === 'verified').reduce((s, c) => s + c.verdictFrozen.yenPerYear, 0);
  const goldenProvisionalYen = gEff.filter(c => (c.verifiedStage || 'provisional') === 'provisional').reduce((s, c) => s + c.verdictFrozen.yenPerYear, 0);
  // 部品検査も実合算(仕様4.6): 表示だけでなく候補在庫に入れる(稼働前=0のまま自動追従)
  const sumParts = parts ? goalAppSummary(parts.lots, parts.settings, { nowMs, chargePerHour: charge, autoLaborPct: engine.autoLaborPct }) : null;
  const bank = goalBankOf({ improvements, prodRows: sumProd.ranking.rows, goldenTotalSaveYen: sumGolden ? sumGolden.ranking.totalSaveYen : 0, includeGolden: true, annualUnitsByModel, charge, goldenFixedYen, goldenProvisionalYen, partsTotalSaveYen: sumParts ? sumParts.ranking.totalSaveYen : 0 });
  const findings = {};
  // ⏰ 停滞カルテ(催促)
  (improvements || []).forEach(c => {
    if (!c || !['plan', 'doing', 'measuring'].includes(c.status)) return;
    const days = Math.floor((nowMs - goalCardLastMs(c)) / 86400000);
    if (days < (engine.stallDays || 10)) return;
    findings[`stall-${c.id}`] = {
      type: 'stall', model: c.model || '', stepKey: c.stepKey || '', yen: 0,
      title: `⏰ カルテ「${c.model || ''}${c.templateName ? `〔${c.templateName}〕` : ''} ${c.stepTitle || ''}」が ${days}日 止まっています`,
      detail: `状態: ${c.status === 'plan' ? '計画のまま' : c.status === 'doing' ? '実施中' : '効果測定中'} / 担当: ${c.owner || '未定'} / 起票: ${new Date(c.createdAt || 0).toLocaleDateString('ja-JP')}。改善PDCAタブで進めるか、やらないなら「効果なし→完了」で閉じてください(放置が一番もったいない)。`,
    };
  });
  // 🧱 維持の見張り(効果あり定着後の悪化=崩れ)
  (improvements || []).forEach(c => {
    if (!c || c.status !== 'effective' || !c.verdictFrozen || (c.kpi && c.kpi !== 'time')) return;
    const after = Number(c.verdictFrozen.afterVal) || 0;
    if (after <= 0) return;
    const recent = measureWindow(lots, { model: c.model, stepKey: c.stepKey, templateId: c.templateId || undefined, customTargetTimes: ctt, modelGroups: groups, startMs: nowMs - 28 * 86400000, endMs: nowMs });
    if (recent.n < 3 || recent.median <= after * (1 + (engine.breakTolPct || 5) / 100)) return;
    const m = goalCardYen({ ...c, status: 'running' }, sumProd.ranking.rows, annualUnitsByModel, charge);
    const lossYen = Math.round((m.units || 0) * Math.max(0, recent.median - after) / 3600 * charge);
    findings[`break-${c.id}`] = {
      type: 'break', model: c.model || '', stepKey: c.stepKey || '', yen: lossYen,
      title: `🧱 定着したはずの「${c.model || ''}${c.templateName ? `〔${c.templateName}〕` : ''} ${c.stepTitle || ''}」が崩れています`,
      detail: `定着時 ${pdcaFmtSec(after)} → 直近4週 ${pdcaFmtSec(recent.median)}（${recent.n}台）。戻りっぱなしだと年 約¥${lossYen.toLocaleString()} を失います。現場で標準が守られているか確認を。`,
    };
  });
  // ⛰ 山(まだカルテ化していない原資の上位・価値下限つき・製品のみ=goldenは目標未較正のため出さない)
  sumProd.ranking.rows
    .filter(r => r.annualSaveYen >= (engine.mineMinYen ?? 20000) && !bank.rowBlocked(r))
    .slice(0, Math.max(1, engine.mineCount || 3))
    .forEach(r => {
      findings[`mine-${r.model}||${r.templateId || ''}||${r.stepKey}`] = {
        type: 'mine', model: r.model, stepKey: r.stepKey, stepTitle: r.stepTitle, yen: r.annualSaveYen,
        templateId: r.templateId || '', templateName: r.templateName || '',
        median: r.median, target: r.target, cv: r.cv ?? null,
        title: `⛰ ${r.model}${r.templateName ? `〔${r.templateName}〕` : ''} ${r.stepTitle}: 効けば 年 約¥${r.annualSaveYen.toLocaleString()}`,
        detail: `実績中央値 ${pdcaFmtSec(r.median)} / 目標 ${pdcaFmtSec(r.target)}（1台${pdcaFmtSec(r.reductionPerUnit)}の詰め代）× 年${r.annualUnits}台${r.annualUnitsSource === 'estimated' ? '(実測ペース推定)' : '(登録値)'}。`,
        hint: goalMethodHint({ stepTitle: r.stepTitle, cv: r.cv }),
      };
    });
  // 🔗 全部に効く共通ポイント(工程横断: 3型式以上に共通で年間コストが大きい工程の先頭1件)
  try {
    const cross = crossStepRanking(lots, settings, { startMs: sumProd.win.startMs, endMs: nowMs, ratePerHour: charge, reductionPct: (engine.commonPct || 10) / 100, annualUnitsByModel, byTemplate: true, templates, autoLaborPct: engine.autoLaborPct });
    const g0 = (cross.groups || []).filter(g => g.modelCount >= (engine.commonMinModels || 3))[0];
    if (g0 && g0.annualCostYen >= (engine.mineMinYen ?? 20000)) {
      findings[`common-${g0.title}`] = {
        type: 'common', model: '', stepKey: '', stepTitle: g0.title, yen: g0.saveByPctYen,
        title: `🔗 「${g0.title}」は${g0.modelCount}型式に共通 — 1つの改善が全部に効く良いポイント`,
        detail: `全型式合計で年 約${Math.round(g0.annualCostSec / 3600)}時間（¥${g0.annualCostYen.toLocaleString()}）かかっています。ここを${engine.commonPct || 10}%削るだけで年 約¥${g0.saveByPctYen.toLocaleString()}。`,
        hint: '💡 型式ごとではなく「この工程そのもの」への改善(共通の治具・置き場・手順書・段取りの工夫)を1つ考えれば、全部の型式で時間を稼げます。お金と時間を稼ぐ良いポイントです。',
      };
    }
  } catch (e) { /* 横断計算が落ちてもブリーフ自体は出す */ }
  // 📈 兆し(コスト上位工程で直近4週が前4週より15%以上悪化)
  sumProd.ranking.rows
    .slice()
    .sort((a, b) => b.annualCostYen - a.annualCostYen)
    .slice(0, 15)
    .forEach(r => {
      const prev = measureWindow(lots, { model: r.model, stepKey: r.stepKey, templateId: r.templateId || undefined, customTargetTimes: ctt, modelGroups: groups, startMs: nowMs - 56 * 86400000, endMs: nowMs - 28 * 86400000 });
      const cur = measureWindow(lots, { model: r.model, stepKey: r.stepKey, templateId: r.templateId || undefined, customTargetTimes: ctt, modelGroups: groups, startMs: nowMs - 28 * 86400000, endMs: nowMs });
      if (prev.n < 3 || cur.n < 3 || cur.median <= prev.median * (1 + (engine.trendPct || 15) / 100)) return;
      if (Object.values(findings).filter(f => f.type === 'trend').length >= 3) return;
      findings[`trend-${r.model}||${r.templateId || ''}||${r.stepKey}`] = {
        type: 'trend', model: r.model, stepKey: r.stepKey, templateId: r.templateId || '', templateName: r.templateName || '', yen: 0,
        title: `📈 ${r.model}${r.templateName ? `〔${r.templateName}〕` : ''} ${r.stepTitle} がじわじわ遅くなっています`,
        detail: `前4週 ${pdcaFmtSec(prev.median)}（${prev.n}台）→ 直近4週 ${pdcaFmtSec(cur.median)}（${cur.n}台）= +${Math.round((cur.median / Math.max(1, prev.median) - 1) * 100)}%。原因が分かる人に一声かけてください。`,
      };
    });
  // 🥇 今週の最優先(原則1件) + 🧮逆算サマリ (Phase 2: 候補の大量表示でなく、目標不足から今週やる1件を決める)
  const gap = goalGapOf({
    moneyTargetYen: moneyTarget, chargePerHour: charge,
    baselineAnnualLaborSec: (sumProd.ranking.totalCostSec || 0) + (sumGolden ? sumGolden.ranking.totalCostSec : 0) + (sumParts ? sumParts.ranking.totalCostSec : 0),
    reductionPct: Number(yearCfg.reductionPct) || 10, verifiedFixedYen: bank.fixedYen,
  });
  const pfCands = [
    ...sumProd.ranking.rows.map(r => candidateOf(r, { appId: 'product' })),
    ...(sumGolden ? sumGolden.ranking.rows.map(r => candidateOf(r, { appId: 'golden', targetSuspect: goldenSuspect })) : []),
    ...(sumParts ? sumParts.ranking.rows.map(r => candidateOf(r, { appId: 'parts' })) : []),
  ];
  const pfOpen = new Set((improvements || []).filter(c => c && ['plan', 'doing', 'measuring'].includes(c.status)).map(c => `product||${c.model}||${c.templateId || ''}||${c.stepKey}`));
  const pf = planPortfolio({ candidates: pfCands, remainingHours: gap.remainingHours, successRatePct: engine.successRatePct, openKeys: pfOpen });
  const pick = pf.picked[0] || null;
  if (pick && pick.appId === 'product') {
    const row = sumProd.ranking.rows.find(r => r.model === pick.model && (r.templateId || '') === pick.templateId && r.stepKey === pick.stepKey) || null;
    findings[`pick-${pick.key}`] = {
      type: 'pick', model: pick.model, stepKey: pick.stepKey, templateId: pick.templateId, templateName: pick.templateName, stepTitle: pick.stepTitle,
      yen: pick.saveYen, grade: pick.grade, expectedHours: Math.round(pick.expectedHours), median: row?.median || 0, target: row?.target || 0, cv: row?.cv ?? null,
      title: `🥇 今週の最優先: ${pick.model}${pick.templateName ? `〔${pick.templateName}〕` : ''} ${pick.stepTitle}`,
      detail: `選定理由: 信頼度${pick.grade}の候補で期待効果が最大（年${Math.round(pick.saveHours)}h＝¥${pick.saveYen.toLocaleString()}・期待値${Math.round(pick.expectedHours)}h）。まだ不明: 遅い原因は未特定・目標時間が現場で妥当かは未確認。次の行動: 担当と期限を決めてカルテ化 → まず現場観察を1回。`,
      hint: goalMethodHint({ stepTitle: pick.stepTitle, cv: row?.cv }),
    };
  }
  // 🔁 定着崩れ(broken)は「要再計画」として催促に出す (Phase 3: 崩れっぱなしを放置しない)
  (improvements || []).forEach(c => {
    if (!c || c.status !== 'effective' || c.verifiedStage !== 'broken') return;
    findings[`replan-${c.id}`] = {
      type: 'stall', model: c.model || '', stepKey: c.stepKey || '', yen: 0,
      title: `🔁 要再計画: 「${c.model || ''}${c.templateName ? `〔${c.templateName}〕` : ''} ${c.stepTitle || ''}」の定着が崩れています`,
      detail: '30日確認で崩れが確定し、貯金箱の「確定」から外れています。対策をやり直して再度定着確認するか、効果なしで閉じてください。',
    };
  });
  // 🩺 データ品質の注意(捏造しないための正直な注記)
  const notices = [];
  const annualInputCount = Object.values(annualUnitsByModel || {}).filter(v => Number(v) > 0).length;
  if (annualInputCount === 0) notices.push('年間生産台数が未登録(0型式)のため金額は実測ペース推定です。経営分析タブで登録すると精度が上がります。');
  if (goldenSuspect) notices.push(`最終検査は実績が目標を${Math.round(sumGolden.excessRatio * 100)}%超過(目標未較正の疑い)のため、在庫金額は参考値・発見カードからは除外しています。`);
  if (golden == null) notices.push('最終検査のデータが読めなかったため、今回は製品のみで集計しています。');
  const stallN = Object.values(findings).filter(f => f.type === 'stall').length;
  return {
    fy: { key: fy.key, label: fy.label }, charge,
    goal: {
      moneyTargetYen: moneyTarget,
      fixedYen: bank.fixedYen, provisionalYen: bank.provisionalYen, runningYen: bank.runningYen, stockYen: bank.stockYen,
      byApp: {
        product: { fixedYen: bank.fixedProdYen, provisionalYen: bank.provisionalProdYen, stockYen: bank.stockProdYen },
        golden: { fixedYen: bank.fixedGoldenYen, provisionalYen: bank.provisionalGoldenYen, stockYen: bank.stockGoldenYen },
        parts: { fixedYen: 0, provisionalYen: 0, stockYen: bank.stockPartsYen },
      },
      remainYen: Math.max(0, moneyTarget - bank.fixedYen),
      elapsedPct: Math.max(0, Math.min(100, Math.round((nowMs - fy.startMs) / (fy.endMs - fy.startMs) * 100))),
    },
    findings, notices,
    // 🧮 逆算サマリ(週次凍結): 必要削減→残り→必要計画在庫→在庫の充足。golden側の表示にも使う。
    gap: {
      requiredHours: Math.round(gap.requiredHours), fixedHours: Math.round(gap.fixedHours), remainingHours: Math.round(gap.remainingHours),
      pipelineRequiredHours: Math.round(pf.pipelineRequiredHours), usableHours: Math.round(pf.totalUsableHours),
      sufficient: pf.sufficient, shortfallHours: Math.round(pf.shortfallHours), needsObservationCount: pf.needsObservation.length,
      successRatePct: Math.round(pf.successRatePct),
    },
    counts: { total: Object.keys(findings).length, stall: stallN },
  };
};
// 週次ブリーフの生成(claim→組立→保存→任意でプッシュ)。force=既存があっても作り直す(手動ボタン用・プッシュはしない)。
const generateWeeklyBrief = async (db, { lots, settings, improvements, currentUserName = '', force = false, push = false, pushTokens = [], deleteData = null }) => {
  const nowMs = Date.now();
  const wk = goalWeekKey(nowMs);
  const ref = doc(db, 'artifacts', GOAL_SHARED_NS, 'public', 'data', 'weekly_briefs', wk);
  const claim = `${currentUserName || 'x'}-${Math.random().toString(36).slice(2, 10)}`;
  if (!force) {
    const ex = await getDoc(ref);
    // ⚠doc存在ではなく中身(goal)で判定: 最終検査アプリが先に decisions だけ書いてdocを作ることがある(発見の確認共有)
    if (ex.exists() && (ex.data() || {}).goal) return { ok: false, reason: 'exists' };
    // claim を先に書き、読み返して自分が勝ったか確認(同時起動の二重送信をほぼ潰す)
    await setDoc(ref, { weekKey: wk, building: claim, createdAt: nowMs }, { merge: true });
    const chk = await getDoc(ref);
    if ((chk.data() || {}).building !== claim) return { ok: false, reason: 'lost-claim' };
  }
  const gSnap = await getDoc(doc(db, 'artifacts', GOAL_SHARED_NS, 'public', 'data', 'settings', 'config'));
  const goalCfg = gSnap.exists() ? gSnap.data() : {};
  const engine = goalEngineOf(goalCfg);
  if (!force && !engine.briefEnabled) return { ok: false, reason: 'disabled' };
  const fy = fiscalYearOf(nowMs, Number(goalCfg.fiscalStartMonth) || 12);
  const yearCfg = { ...GOAL_DEFAULT_YEAR, chargePerHour: Number(settings?.laborCostPerHour) || GOAL_DEFAULT_YEAR.chargePerHour, ...((goalCfg.years || {})[fy.key] || {}) };
  let golden = null;
  try {
    const [gs, gl, gi] = await Promise.all([
      getDoc(doc(db, 'artifacts', 'final-inspection-v1', 'public', 'data', 'settings', 'config')),
      getDocs(collection(db, 'artifacts', 'final-inspection-v1', 'public', 'data', 'lots')),
      getDocs(collection(db, 'artifacts', 'final-inspection-v1', 'public', 'data', 'improvements')),
    ]);
    golden = { settings: gs.exists() ? gs.data() : {}, lots: gl.docs.map(d => ({ id: d.id, ...d.data() })), improvements: gi.docs.map(d => ({ id: d.id, ...d.data() })) };
  } catch (e) { /* goldenが読めなくても製品だけで作る */ }
  let parts = null;
  try {
    const [ps, pl] = await Promise.all([
      getDoc(doc(db, 'artifacts', 'parts-inspection-v1', 'public', 'data', 'settings', 'config')),
      getDocs(collection(db, 'artifacts', 'parts-inspection-v1', 'public', 'data', 'lots')),
    ]);
    parts = { settings: ps.exists() ? ps.data() : {}, lots: pl.docs.map(d => ({ id: d.id, ...d.data() })) };
  } catch (e) { /* 部品が読めなくても続行 */ }
  const annualUnitsByModel = (settings?.annualProduction && settings.annualProduction[fy.key]) || {};
  // テンプレ一覧(名前解決用)。読めなくてもブリーフは作る(テンプレ名が空になるだけ)。
  let templates = null;
  try {
    const tSnap = await getDocs(collection(db, 'artifacts', APP_DATA_ID, 'public', 'data', 'templates'));
    templates = tSnap.docs.map(d => ({ id: d.id, ...d.data() }));
  } catch (e) { /* noop */ }
  // 📚全件で計算(仕様4.2): 呼び出し元の購読はlimit(500)のため、ここで全件をページング取得。失敗時は渡された分で続行。
  let fullLots = lots;
  try {
    const col = collection(db, 'artifacts', APP_DATA_ID, 'public', 'data', 'lots');
    const r = await fetchAllPaged(async ({ cursor, pageSize }) => {
      const q = cursor ? query(col, orderBy('createdAt', 'desc'), startAfter(cursor), limit(pageSize)) : query(col, orderBy('createdAt', 'desc'), limit(pageSize));
      const snap = await getDocs(q);
      return { items: snap.docs.map(d => ({ id: d.id, ...d.data() })), nextCursor: snap.docs.length ? snap.docs[snap.docs.length - 1] : null };
    });
    if (r.items.length >= (lots || []).length) fullLots = r.items;
  } catch (e) { /* 500件で続行 */ }
  const brief = buildWeeklyBrief({ nowMs, fy, yearCfg, lots: fullLots, settings, improvements, golden, parts, annualUnitsByModel, templates, engine });
  // ⚠merge:true だと findings(map) の旧キーが残って重複する(setDoc merge の教訓)。mergeFields で該当フィールドを丸ごと置換し、decisions/push だけ温存する。
  await setDoc(ref, { weekKey: wk, createdAt: nowMs, createdBy: currentUserName || '', building: deleteField(), ...brief },
    { mergeFields: ['weekKey', 'createdAt', 'createdBy', 'building', 'fy', 'charge', 'goal', 'findings', 'notices', 'counts'] });
  if (push && !engine.pushEnabled) {
    try { await setDoc(ref, { push: { sentAt: null, reason: '設定でプッシュOFF' } }, { merge: true }); } catch (e) { /* noop */ }
  } else if (push) {
    try {
      const cfg = pushCfgOf(settings);
      const targets = (pushTokens || []).filter(t => t && t.token && t.enabled !== false && t.admin === true);
      if (cfg.vapidKey && cfg.workerUrl && targets.length) {
        const man = (n) => `${Math.round(n / 10000)}万`;
        await sendPushViaWorker(cfg.workerUrl, {
          tokens: [...new Set(targets.map(t => t.token))],
          title: `🎯 今週の工場: 目標まであと ¥${man(brief.goal.remainYen)}`,
          body: `発見 ${brief.counts.total}件(うち催促 ${brief.counts.stall}件)。分析 → 🎯年間目標 で確認`,
          link: (typeof window !== 'undefined' ? `${window.location.origin}/` : undefined), tag: `weekly-brief-${wk}`,
        });
        await setDoc(ref, { push: { sentAt: Date.now(), to: targets.length } }, { merge: true });
      } else {
        await setDoc(ref, { push: { sentAt: null, reason: !cfg.workerUrl ? 'push未設定' : '管理者端末の登録なし' } }, { merge: true });
      }
    } catch (e) { console.warn('週次ブリーフのプッシュに失敗(ブリーフ自体は作成済み)', e); }
  }
  return { ok: true, weekKey: wk };
};
// 改善スコアボード(SQDC型の見える化): 重点工程の「今月 vs 先月」の中央値トレンド(速/横/遅)と、
//   今月 実際に浮いた時間/¥ を出す純関数。リサーチの結論=1点集中×結果で評価×正直なお金 を実装。
//   ※ freed(浮いた時間)は「速くなった分×今月台数」。¥は『余力を別の仕事に回せた場合の価値』で即現金ではない。
const improvementScoreboard = (lots, settings, { nowMs, topN = 12 } = {}) => {
  const customTargetTimes = settings?.customTargetTimes || {};
  const modelGroups = modelGroupsOf(settings);
  const rate = Number(settings?.laborCostPerHour) || 0;
  const d = new Date(nowMs);
  const thisStart = new Date(d.getFullYear(), d.getMonth(), 1).getTime();
  const lastStart = new Date(d.getFullYear(), d.getMonth() - 1, 1).getTime();
  // 年間コスト(=工数の山)順の上位工程をスコアボード対象にする(重点工程ランキングを土台に流用)。
  const ranking = profitRanking(lots, settings, { startMs: nowMs - 365 * 86400000, endMs: nowMs, ratePerHour: rate });
  const rows = ranking.rows.slice(0, topN).map(r => {
    const tm = measureWindow(lots, { model: r.model, stepKey: r.stepKey, customTargetTimes, modelGroups, startMs: thisStart, endMs: nowMs });
    const lm = measureWindow(lots, { model: r.model, stepKey: r.stepKey, customTargetTimes, modelGroups, startMs: lastStart, endMs: thisStart });
    const tmMed = tm.n > 0 ? tm.median : null;
    const lmMed = lm.n > 0 ? lm.median : null;
    let trend = 'nodata', deltaSec = 0, freedSec = 0;
    if (tmMed != null && lmMed != null) {
      deltaSec = tmMed - lmMed; // <0 = 今月のほうが速い(良い)
      const pct = lmMed > 0 ? Math.abs(deltaSec) / lmMed * 100 : 0;
      trend = pct < PDCA_THRESHOLD_PCT ? 'same' : (deltaSec < 0 ? 'faster' : 'slower');
      freedSec = (lmMed - tmMed) * (tm.n || 0); // 今月: 速くなった分 × 今月台数 (悪化なら負)
    } else if (tmMed != null) {
      trend = 'new'; // 今月初データ(比較先なし)
    }
    return { ...r, thisMonthMedian: tmMed, lastMonthMedian: lmMed, thisMonthN: tm.n, trend, deltaSec, freedSec };
  });
  const freedSecTotal = rows.reduce((s, r) => s + (r.freedSec > 0 ? r.freedSec : 0), 0);
  const worsenedSecTotal = rows.reduce((s, r) => s + (r.freedSec < 0 ? -r.freedSec : 0), 0);
  return {
    rows, rate, thisStart, lastStart,
    freedSecTotal, freedYenTotal: rate > 0 ? Math.round(freedSecTotal / 3600 * rate) : 0,
    worsenedSecTotal,
    improvedCount: rows.filter(r => r.trend === 'faster').length,
    worsenedCount: rows.filter(r => r.trend === 'slower').length,
  };
};
const medianOf = (arr) => { if (!arr || !arr.length) return 0; const s = [...arr].sort((a, b) => a - b); const n = s.length; return n % 2 ? s[(n - 1) / 2] : Math.round((s[n / 2 - 1] + s[n / 2]) / 2); };
// 五数要約(四分位は標本6未満ではnull=少数で不安定なため出さない。IE/Six Sigmaの定石)
const statsOf = (values) => {
  const ds = [...(values || [])].filter(v => v > 0).sort((a, b) => a - b); const n = ds.length;
  if (!n) return { n: 0, min: 0, max: 0, median: 0, mean: 0, q1: null, q3: null };
  const mean = ds.reduce((a, b) => a + b, 0) / n;
  const q = (p) => { const idx = (n - 1) * p, lo = Math.floor(idx), hi = Math.ceil(idx); return lo === hi ? ds[lo] : Math.round(ds[lo] + (ds[hi] - ds[lo]) * (idx - lo)); };
  return { n, min: ds[0], max: ds[n - 1], median: medianOf(ds), mean: Math.round(mean), q1: n >= 6 ? q(0.25) : null, q3: n >= 6 ? q(0.75) : null };
};
// 重点工程の詳細: 集計に使ったロット一覧(根拠データ=自分で確認できる) + 他型式の同工程との比較
const profitDetail = (lots, settings, { model, stepKey, startMs = 0, endMs = Infinity }) => {
  const customTargetTimes = settings?.customTargetTimes || {};
  const modelGroups = modelGroupsOf(settings);
  const titlePart = stepKey.includes('_') ? stepKey.slice(stepKey.indexOf('_') + 1) : stepKey;
  const srcLots = [];
  let target = 0;
  const byModel = {}; // 同じ工程タイトルの実績を型式別に集める(類似比較用)
  (lots || []).forEach(l => {
    if (l.status !== 'completed' && l.location !== 'completed') return;
    const lotMs = toMsAny(l.completedAt) || toMsAny(l.updatedAt);
    (l.steps || []).forEach((step, idx) => {
      const sk = targetTimeStepKey(step);
      const sameTitle = (step.title || '') === titlePart;
      if (sk !== stepKey && !sameTitle) return;
      const keys = step.lotOnce ? lotOnceKeysOf(l.tasks || {}, step) : Array.from({ length: l.quantity || 1 }, (_, i) => (l.tasks || {})[`${step.id}-${i}`] !== undefined ? `${step.id}-${i}` : `${idx}-${i}`);
      const durs = [];
      keys.forEach(k => { const t = (l.tasks || {})[k]; if (!t) return; if (t.status !== 'completed' && t.status !== 'ng') return; if (t.samplingSkipped) return; const d = t.duration || 0; if (d <= 0) return; const ms = toMsAny(t.endTime) || lotMs; if (ms == null || ms < startMs || ms > endMs) return; durs.push(d); });
      if (!durs.length) return;
      if (sameTitle) (byModel[l.model] = byModel[l.model] || []).push(...durs);
      if (sk === stepKey && l.model === model) {
        target = getEffectiveTargetTime(step, l.model, customTargetTimes, modelGroups);
        srcLots.push({ orderNo: l.orderNo || l.id, completedAt: lotMs, count: durs.length, median: medianOf(durs) });
      }
    });
  });
  const compares = Object.entries(byModel).map(([m, ds]) => ({ model: m, median: medianOf(ds), n: ds.length })).sort((a, b) => a.median - b.median);
  srcLots.sort((a, b) => (b.completedAt || 0) - (a.completedAt || 0));
  return { srcLots, target, compares, titlePart };
};

// === 工程分析の土台: 型式(+テンプレ)別に、工程ごとの実績を集計してグラフ用に返す純関数 ===
// 各工程の durations(生データ) + 中央値/平均/σ/CV/最小最大 + 作業者別 + 月別、を返す。Pareto は totalSec(時間の山)順。
const stepBreakdown = (lots, { model, templateId, startMs = 0, endMs = Infinity, customTargetTimes = {}, modelGroups = [] } = {}) => {
  const byStep = new Map();
  (lots || []).forEach(l => {
    if (l.status !== 'completed' && l.location !== 'completed') return;
    if (model && l.model !== model) return;
    if (templateId && l.templateId !== templateId) return;
    const lotMs = toMsAny(l.completedAt) || toMsAny(l.updatedAt);
    (l.steps || []).forEach((step, idx) => {
      const sk = targetTimeStepKey(step);
      const keys = step.lotOnce
        ? lotOnceKeysOf(l.tasks || {}, step)
        : Array.from({ length: l.quantity || 1 }, (_, i) => ((l.tasks || {})[`${step.id}-${i}`] !== undefined ? `${step.id}-${i}` : `${idx}-${i}`));
      keys.forEach(k => {
        const t = (l.tasks || {})[k]; if (!t) return;
        if (t.status !== 'completed' && t.status !== 'ng') return;
        if (t.samplingSkipped) return;
        const d = t.duration || 0; if (d <= 0) return;
        const ms = toMsAny(t.endTime) || lotMs; if (ms == null || ms < startMs || ms > endMs) return;
        let e = byStep.get(sk);
        if (!e) { e = { stepKey: sk, stepTitle: step.title, category: step.category || '', durations: [], workers: {}, monthly: {}, target: getEffectiveTargetTime(step, l.model, customTargetTimes, modelGroups) }; byStep.set(sk, e); }
        e.durations.push(d);
        const w = (t.workerName || '?'); (e.workers[w] = e.workers[w] || []).push(d);
        const dt = new Date(ms); const ym = `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}`; (e.monthly[ym] = e.monthly[ym] || []).push(d);
      });
    });
  });
  const rows = [...byStep.values()].map(e => {
    const ds = [...e.durations].sort((a, b) => a - b); const n = ds.length; const sum = ds.reduce((a, b) => a + b, 0); const mean = n ? sum / n : 0;
    const variance = n ? ds.reduce((a, b) => a + (b - mean) ** 2, 0) / n : 0; const sigma = Math.sqrt(variance);
    return { ...e, n, totalSec: sum, mean: Math.round(mean), median: medianOf(ds), sigma: Math.round(sigma), cv: mean > 0 ? Math.round(sigma / mean * 1000) / 1000 : 0, min: n ? ds[0] : 0, max: n ? ds[n - 1] : 0 };
  }).sort((a, b) => b.totalSec - a.totalSec);
  const grand = rows.reduce((s, r) => s + r.totalSec, 0) || 1;
  let cum = 0; rows.forEach(r => { cum += r.totalSec; r.cumPct = Math.round(cum / grand * 100); r.sharePct = Math.round(r.totalSec / grand * 1000) / 10; });
  return { rows, grandTotalSec: grand };
};
// === じっと見るモード(要素作業分割)のヘルパー ===
// 観測プランの検索: (templateId, stepKey, model) を優先し、model未指定の全型式共通プランにフォールバック
const findObsPlan = (plans, templateId, stepKey, model) => {
  if (!templateId || !stepKey) return null;
  const ps = (plans || []).filter(p => p.enabled && p.templateId === templateId && p.stepKey === stepKey && Array.isArray(p.elements) && p.elements.length);
  return ps.find(p => p.model && p.model === model) || ps.find(p => !p.model) || null;
};
// 工程(step)に直付けした要素(じっと見る)。工程テンプレ編集で常設設定したもの → 旧 observationPlans コレクションより優先。
//   明示OFF(observationEnabled===false)は {enabled:false} を返し、旧プランへのフォールバックを止める。
const stepObsPlan = (step) => {
  if (!step || !Array.isArray(step.observationElements)) return null;
  if (step.observationEnabled === false) return { enabled: false, elements: [] };
  const els = step.observationElements.filter(e => e && (e.label || '').trim() !== '').slice().sort((a, b) => (a.order || 0) - (b.order || 0));
  if (els.length < 2) return null;
  return { source: 'step', enabled: true, model: '', elements: els };
};
// 旧 observationPlans の「型式専用(model一致)」プランのみを返す。step直付け(全型式)より優先させて型式別プランの黙殺を防ぐ。
const findObsPlanModel = (plans, templateId, stepKey, model) => {
  if (!templateId || !stepKey || !model) return null;
  return (plans || []).find(p => p.enabled && p.templateId === templateId && p.stepKey === stepKey && p.model === model && Array.isArray(p.elements) && p.elements.length) || null;
};
// 要素別の実績集計: 完了タスクの elementDurations を要素IDごとに集める→中央値/n
const obsElementStats = (lots, { model, templateId, stepKey, plan }) => {
  const byEl = {};
  let observedUnits = 0; // 内訳(elementDurations)を持つ完了台の実数 = 「何台ぶんの観測か」
  (lots || []).forEach(l => {
    if (l.status !== 'completed' && l.location !== 'completed') return;
    if (model && l.model !== model) return;
    if (templateId && l.templateId !== templateId) return;
    (l.steps || []).forEach((step, idx) => {
      if (targetTimeStepKey(step) !== stepKey || step.lotOnce) return; // 段取り(回数ベース)は第1版対象外
      for (let u = 0; u < (l.quantity || 1); u++) {
        const t = (l.tasks || {})[`${step.id}-${u}`] || (l.tasks || {})[`${idx}-${u}`];
        // 該当なし(skipped)/抜取スキップ/未完了の台は時間統計(stepBreakdown/measureWindow)と対称に除外。
        // 完了→該当なし変換しても elementDurations が残るため、status を見ないと内訳に古い値が居座る。
        if (!t || t.status !== 'completed' || t.samplingSkipped || !t.elementDurations) continue;
        const entries = Object.entries(t.elementDurations).filter(([, sec]) => sec > 0);
        if (!entries.length) continue;
        observedUnits++; // この台は内訳ありの1観測
        entries.forEach(([eid, sec]) => { (byEl[eid] = byEl[eid] || []).push(sec); });
      }
    });
  });
  const els = (plan?.elements || []).map(e => ({ id: e.id, label: e.label, durations: byEl[e.id] || [] }));
  // プランに無い要素IDも拾う(過去の観測)
  Object.keys(byEl).forEach(eid => { if (!els.some(e => e.id === eid)) els.push({ id: eid, label: '(削除された要素)', durations: byEl[eid] }); });
  const rows = els.map(e => ({ id: e.id, label: e.label, n: e.durations.length, median: medianOf(e.durations), durations: e.durations }));
  const total = rows.reduce((s, r) => s + r.median, 0) || 1;
  rows.forEach(r => { r.sharePct = Math.round(r.median / total * 1000) / 10; });
  return { rows: rows.sort((a, b) => b.median - a.median), totalMedian: total, observedUnits };
};
// ヒストグラム: durations を bins 個の階級に分ける
const histogramOf = (durations, bins = 8) => {
  if (!durations || !durations.length) return { buckets: [], min: 0, max: 0, width: 0 };
  const min = Math.min(...durations), max = Math.max(...durations);
  if (max <= min) return { buckets: [{ lo: min, hi: max, count: durations.length }], min, max, width: 0 };
  const width = (max - min) / bins;
  const buckets = Array.from({ length: bins }, (_, i) => ({ lo: min + i * width, hi: min + (i + 1) * width, count: 0 }));
  durations.forEach(d => { let bi = Math.floor((d - min) / width); if (bi >= bins) bi = bins - 1; if (bi < 0) bi = 0; buckets[bi].count++; });
  return { buckets, min, max, width };
};
// pdcaWindowDays / PDCA_KPIS / pdcaKpiValue / computeVerdict は src/domain/goal/verdictEngine.js に移動 (import済)。
// 改善テーマ候補: 完了ロットに現れる 型式×工程 を列挙 (カルテ化の入口・乖離候補算出に使う)
const enumerateModelSteps = (lots) => {
  const map = new Map();
  (lots || []).forEach(l => {
    if (l.status !== 'completed' && l.location !== 'completed') return;
    (l.steps || []).forEach(step => {
      const sk = targetTimeStepKey(step);
      const key = `${l.model}||${sk}`;
      if (!map.has(key)) map.set(key, { model: l.model, stepKey: sk, stepTitle: step.title, category: step.category || '', auto: isAutoStep(step) });
    });
  });
  return [...map.values()];
};
// 型式×テンプレ×工程 の列挙 (🎯目標レイヤー用)。実測: 68型式中23型式が複数テンプレで流れており、
// 型式×工程だけで束ねると検査種類の違う作業が混ざる(混在の実害16件・中央値差 最大15.6倍)。
const enumerateModelTplSteps = (lots) => {
  const map = new Map();
  (lots || []).forEach(l => {
    if (l.status !== 'completed' && l.location !== 'completed') return;
    const tpl = l.templateId || '';
    (l.steps || []).forEach(step => {
      const sk = targetTimeStepKey(step);
      const key = `${l.model}||${tpl}||${sk}`;
      if (!map.has(key)) map.set(key, { model: l.model, templateId: tpl, stepKey: sk, stepTitle: step.title, category: step.category || '', auto: isAutoStep(step) });
    });
  });
  return [...map.values()];
};

// === 分割測定アプリ(rotary_table)連携 Phase2: 時間取り半自動連動 ===
// Web→アプリ: rotaryCommands に prepare / start_capture を書く。アプリ→Web: rotaryEvents の done を購読し測定タイマーを自動停止。
// マスタ settings.rotaryLink.enabled が true のときだけ動く (既定OFF)。工程に step.rotaryLink + step.rotaryRole('prepare'|'capture')。
// 相関ID(workId) = ロット×台。prepare/start_capture/done をこのIDで結びつける (準備工程と測定工程は別工程でも同じ台なら同じID)。
const ROTARY_CMD_COL = 'rotaryCommands';
const ROTARY_EVT_COL = 'rotaryEvents';
// 分割アプリが prepare 指令の mode で条件マスタを切り替える6モード。文字列は分割アプリ側と完全一致させること。
// 型式(model)+このモードで測定条件が決まる(回転/傾斜=どのマスタか, 分割/再現/合体=どの条件群か)。
const ROTARY_MODES = ['回転分割', '傾斜分割', '回転再現性', '傾斜再現性', '回転分割+再現', '傾斜分割+再現'];
const rotaryWorkId = (lotId, unitIdx) => `${lotId}_u${unitIdx}`;
const rotaryCmdDoc = (db, id) => doc(db, 'artifacts', APP_DATA_ID, 'public', 'data', ROTARY_CMD_COL, id);
// 指令を書く (prepare=準備工程の開始 / start_capture=測定工程の開始)。失敗してもタイマー自体は止めない(現場優先)。
const writeRotaryCommand = async (db, kind, { workId, station, model, machine, mode }) => {
  if (!db || !workId || !station) return { ok: false, reason: 'missing' };
  try {
    const id = kind === 'prepare' ? `${workId}_prepare` : `${workId}_start`;
    const payload = kind === 'prepare'
      ? { type: 'prepare', station, workId, model: model || '', machine: machine || '', mode: mode || '', status: 'pending', createdAt: serverTimestamp() }
      : { type: 'start_capture', station, workId, status: 'pending', createdAt: serverTimestamp() };
    await setDoc(rotaryCmdDoc(db, id), payload);
    return { ok: true };
  } catch (e) {
    console.error('writeRotaryCommand failed', kind, e);
    return { ok: false, reason: e?.message || 'error' };
  }
};

// ロットの推定総時間。customTargetTimes があれば型式別較正値を使う。
// ロット1回工程は台数を掛けず1回分のみ加算 (段取りは台数に比例しない)。
const calculateLotEstimatedTime = (lot, customTargetTimes = null, modelGroups = null) => {
  if (!lot?.steps || !Array.isArray(lot.steps)) return 0;
  let perUnitTime = 0, lotOnceTime = 0;
  lot.steps.forEach(step => {
    // 型式グループ較正(modelGroups)も渡す。較正値を共有している型式で、計画(本関数)と達成率の目標基準が一致する。
    const t = getEffectiveTargetTime(step, lot.model, customTargetTimes, modelGroups);
    if (step?.lotOnce) lotOnceTime += t; else perUnitTime += t;
  });
  return perUnitTime * (lot.quantity || 1) + lotOnceTime;
};

// === 勤務時間マスタ ===
// ユーザ会社の実態に合わせたデフォルト勤務スケジュール:
//  - 8:30 始業 → 10:00 (休憩 10分) → 12:00 (休憩 45分) → 15:00 (休憩 15分) → 17:00 定時
//  - 17:00 → 17:15 (休憩 15分) → 17:15 → 19:15 残業終わり
// 実働: 8:30〜17:00 = 8.5h - 休憩 1.166h = 7.333h (定時)
//       残業 17:15〜19:15 = 2h → 合計 9.333h (残業込み)
const DEFAULT_WORK_SCHEDULE = {
  dayStart: '08:30',
  dayEnd: '17:00',           // 定時終わり
  overtimeStart: '17:15',    // 残業開始 (定時終わり後の休憩明け)
  overtimeEnd: '19:15',      // 残業終わり (=2時間残業を想定)
  breaks: [
    { start: '10:00', end: '10:10', name: '10時休憩' },
    { start: '12:00', end: '12:45', name: '昼休憩' },
    { start: '15:00', end: '15:15', name: '15時休憩' },
    { start: '17:00', end: '17:15', name: '残業前休憩' },
  ],
  daysPerWeek: 5,
  daysPerMonth: 20,
  includeOvertimeInCapacity: false, // 負荷計算に残業時間を含めるか (デフォルトは定時のみ)
};

// "HH:MM" を当日 0:00 からの分数に変換
const timeStrToMinutes = (str) => {
  if (!str || typeof str !== 'string') return 0;
  const [h, m] = str.split(':').map(Number);
  if (isNaN(h) || isNaN(m)) return 0;
  return h * 60 + m;
};

// 区間 [aStart, aEnd] と [bStart, bEnd] の重なり (分) を返す
const overlapMinutes = (aStart, aEnd, bStart, bEnd) => {
  const s = Math.max(aStart, bStart);
  const e = Math.min(aEnd, bEnd);
  return Math.max(0, e - s);
};

// 2つのタイムスタンプ間の「勤務時間内」だけの経過時間を秒で返す。
// 会社外時間 (夜間/休憩中/土日) はカウントしない。
//   schedule.daysPerWeek <= 5 の場合は土日除外
//   includeOvertime=true で残業時間 (19:15まで) も含める
const computeElapsedWorkSeconds = (startMs, endMs, schedule, includeOvertime = true) => {
  if (!startMs || !endMs || endMs <= startMs) return 0;
  const sch = { ...DEFAULT_WORK_SCHEDULE, ...(schedule || {}) };
  const dayStartMin = timeStrToMinutes(sch.dayStart);
  // 残業込みなら overtimeEnd まで、定時のみなら dayEnd まで
  const dayEndMin = (includeOvertime && sch.overtimeEnd) ? timeStrToMinutes(sch.overtimeEnd) : timeStrToMinutes(sch.dayEnd);
  const breaks = (sch.breaks || []).map(b => ({ start: timeStrToMinutes(b.start), end: timeStrToMinutes(b.end) }));
  const excludeWeekend = (sch.daysPerWeek || 5) <= 5;

  let totalSec = 0;
  // 日付ループ
  const startDate = new Date(startMs);
  const endDate = new Date(endMs);
  const cursor = new Date(startDate.getFullYear(), startDate.getMonth(), startDate.getDate());
  const lastDay = new Date(endDate.getFullYear(), endDate.getMonth(), endDate.getDate());

  while (cursor.getTime() <= lastDay.getTime()) {
    const dow = cursor.getDay();
    if (excludeWeekend && (dow === 0 || dow === 6)) {
      cursor.setDate(cursor.getDate() + 1);
      continue;
    }
    // この日の勤務時間レンジ (ms)
    const dayWorkStart = new Date(cursor); dayWorkStart.setHours(0, dayStartMin, 0, 0);
    const dayWorkEnd = new Date(cursor); dayWorkEnd.setHours(0, dayEndMin, 0, 0);
    // 計測範囲との重なり
    const overlapStart = Math.max(startMs, dayWorkStart.getTime());
    const overlapEnd = Math.min(endMs, dayWorkEnd.getTime());
    if (overlapEnd > overlapStart) {
      let overlapMs = overlapEnd - overlapStart;
      // 重なった範囲内の休憩を差し引く
      for (const b of breaks) {
        const breakStart = new Date(cursor); breakStart.setHours(0, b.start, 0, 0);
        const breakEnd = new Date(cursor); breakEnd.setHours(0, b.end, 0, 0);
        const bOverlap = Math.max(0, Math.min(overlapEnd, breakEnd.getTime()) - Math.max(overlapStart, breakStart.getTime()));
        overlapMs -= bOverlap;
      }
      totalSec += Math.max(0, overlapMs) / 1000;
    }
    cursor.setDate(cursor.getDate() + 1);
  }
  return Math.floor(totalSec);
};

// computeElapsedWorkSeconds の逆: 「この時刻から実作業を needSec 秒やったら、実際に何時に終わるか」。
//   到着予定 + 検査の見積 から終了予定を出す時に使う。単純に足すと嘘になる:
//   16:00着で見積3hを足すと 19:00 と出るが、実際は 15時休憩・定時17:00・翌朝跨ぎがあるので合わない。
//   休憩中/勤務時間外の開始は「次に働ける瞬間」まで送る。土日は daysPerWeek<=5 の時だけ飛ばす(既存の判定と同じ)。
//   ⚠戻り値は「その仕事が終わる壁時計の時刻」。needSec=0 なら開始時刻そのもの(丸めない)。
const WORK_END_MAX_DAYS = 60; // 見積が異常に大きい時の暴走止め(この日数で見つからなければ null)
const addWorkSeconds = (startMs, needSec, schedule, includeOvertime = true) => {
  if (!startMs || !Number.isFinite(needSec)) return null;
  let remainMs = Math.max(0, needSec) * 1000;
  if (remainMs === 0) return startMs;
  const sch = { ...DEFAULT_WORK_SCHEDULE, ...(schedule || {}) };
  const dayStartMin = timeStrToMinutes(sch.dayStart);
  const dayEndMin = (includeOvertime && sch.overtimeEnd) ? timeStrToMinutes(sch.overtimeEnd) : timeStrToMinutes(sch.dayEnd);
  if (!(dayEndMin > dayStartMin)) return null;
  const breaks = (sch.breaks || []).map(b => ({ start: timeStrToMinutes(b.start), end: timeStrToMinutes(b.end) }))
    .filter(b => b.end > b.start).sort((a, b) => a.start - b.start);
  const excludeWeekend = (sch.daysPerWeek || 5) <= 5;
  const at = (day, min) => { const d = new Date(day); d.setHours(0, min, 0, 0); return d.getTime(); };

  const cursor = new Date(startMs); cursor.setHours(0, 0, 0, 0);
  for (let guard = 0; guard < WORK_END_MAX_DAYS; guard++) {
    const dow = cursor.getDay();
    if (!(excludeWeekend && (dow === 0 || dow === 6))) {
      // その日の「働ける区間」= 勤務時間から休憩を抜いたもの。区間ごとに残りを削る。
      const segs = [];
      let segStart = dayStartMin;
      for (const b of breaks) {
        if (b.start > segStart) segs.push([segStart, Math.min(b.start, dayEndMin)]);
        segStart = Math.max(segStart, b.end);
      }
      if (segStart < dayEndMin) segs.push([segStart, dayEndMin]);
      for (const [s, e] of segs) {
        if (e <= s) continue;
        const segStartMs = Math.max(at(cursor, s), startMs); // 初日は開始時刻より前の区間は使えない
        const segEndMs = at(cursor, e);
        if (segEndMs <= segStartMs) continue;
        const cap = segEndMs - segStartMs;
        if (remainMs <= cap) return segStartMs + remainMs;
        remainMs -= cap;
      }
    }
    cursor.setDate(cursor.getDate() + 1);
  }
  return null; // 見積が大きすぎて WORK_END_MAX_DAYS 以内に終わらない → 呼び出し側で「算出不可」を出す
};

// 勤務スケジュールから「1 日の実働時間」を計算 (分単位)
// 戻り値: { regularMinutes, overtimeMinutes, totalMinutes, regularHours, overtimeHours, totalHours }
const computeWorkHours = (schedule) => {
  const sch = { ...DEFAULT_WORK_SCHEDULE, ...(schedule || {}) };
  const dayStart = timeStrToMinutes(sch.dayStart);
  const dayEnd = timeStrToMinutes(sch.dayEnd);
  const overtimeStart = timeStrToMinutes(sch.overtimeStart);
  const overtimeEnd = timeStrToMinutes(sch.overtimeEnd);
  const breaks = (sch.breaks || []).map(b => ({ start: timeStrToMinutes(b.start), end: timeStrToMinutes(b.end) }));

  // 定時内の実働: dayStart 〜 dayEnd の総時間から、その期間と重なる休憩を引く
  const regularSpan = Math.max(0, dayEnd - dayStart);
  const regularBreakMin = breaks.reduce((acc, b) => acc + overlapMinutes(b.start, b.end, dayStart, dayEnd), 0);
  const regularMinutes = Math.max(0, regularSpan - regularBreakMin);

  // 残業時間の実働: overtimeStart 〜 overtimeEnd の総時間から、その期間と重なる休憩を引く
  let overtimeMinutes = 0;
  if (overtimeEnd > overtimeStart) {
    const overtimeSpan = overtimeEnd - overtimeStart;
    const overtimeBreakMin = breaks.reduce((acc, b) => acc + overlapMinutes(b.start, b.end, overtimeStart, overtimeEnd), 0);
    overtimeMinutes = Math.max(0, overtimeSpan - overtimeBreakMin);
  }

  const totalMinutes = regularMinutes + overtimeMinutes;
  return {
    regularMinutes,
    overtimeMinutes,
    totalMinutes,
    regularHours: regularMinutes / 60,
    overtimeHours: overtimeMinutes / 60,
    totalHours: totalMinutes / 60,
  };
};

// 「分」を "Xh Ymin" 形式に整形
const formatHoursMinutes = (totalMin) => {
  const h = Math.floor(totalMin / 60);
  const m = Math.round(totalMin % 60);
  if (h === 0) return `${m}分`;
  if (m === 0) return `${h}時間`;
  return `${h}時間${m}分`;
};

// === 品質規格 / 型式オーバーライドの適用 (共通ヘルパー) ===
// ロット作成・Excel 取込・編集 で共通利用するため切り出し。
// 優先順位:
//   1) modelStandardMap[model] にマッピングがあれば品質規格を適用 (overrides + conditions)
//      - 規格内に templateId に一致するエントリがあればそれを使用
//      - 一致するエントリが無ければ規格は適用せず legacy fallback へ
//   2) なければ legacy measurementOverrides[model] を適用
//   3) どちらも無ければ steps をそのまま返す
// 戻り値: { steps: 加工後の steps, appliedStandard: ロットに焼き付けるスナップショット | null }

// 規格の中の「テンプレートごと設定」一覧を取得 (新形式 + 旧形式の両方を吸収)
//   新形式: qs.templates = [{ templateId, measurementOverrides, measurementConditions }, ...]
//   旧形式: qs.templateId + qs.measurementOverrides + qs.measurementConditions (1 件のみ)
const getQsTemplateEntries = (qs) => {
  if (!qs) return [];
  if (Array.isArray(qs.templates) && qs.templates.length > 0) {
    // ...t で全フィールド (defaultValues / checklistItemsByStep / stepProfile 等) を保持する。
    return qs.templates.map(t => ({
      ...t,
      templateId: t.templateId || '',
      measurementOverrides: t.measurementOverrides || {},
      measurementConditions: t.measurementConditions || {},
    }));
  }
  if (qs.templateId) {
    return [{
      templateId: qs.templateId,
      measurementOverrides: qs.measurementOverrides || {},
      measurementConditions: qs.measurementConditions || {},
      ...(qs.defaultValues ? { defaultValues: qs.defaultValues } : {}),
      ...(qs.checklistItemsByStep ? { checklistItemsByStep: qs.checklistItemsByStep } : {}),
      ...(qs.stepProfile ? { stepProfile: qs.stepProfile } : {}),
    }];
  }
  return [];
};

const applyQualityStandardToSteps = (model, baseSteps, settings, templateId = null) => {
  if (!model || !baseSteps) return { steps: baseSteps, appliedStandard: null, naStepIds: [] };
  let steps = baseSteps;
  let appliedStandard = null;
  const naStepIds = []; // 型式別プロファイルで「該当なし」にする step.id (ロット生成時に自動スキップ)

  // 時間ソース一本化: 型式別較正済み目標時間 (customTargetTimes) を step.targetTime へ焼き付け。
  // どの規格パスを通っても適用されるよう、関数化して各 return 前に通す。
  const applyCalibratedTargets = (stepsArr) => {
    const ctt = settings?.customTargetTimes;
    if (!ctt || !model) return stepsArr;
    // 型式グループ: 自型式に較正値が無ければ同グループ型式の値を引き継ぐ(目標時間のデータ共有)
    const groupModels = sameGroupModels(model, settings);
    const calOf = (s) => {
      const sk = `${s.category || ''}_${s.title || ''}`;
      const own = ctt[`model_${model}`]?.[sk];
      if (typeof own === 'number' && own > 0) return own;
      for (const sm of groupModels) { if (sm === model) continue; const v = ctt[`model_${sm}`]?.[sk]; if (typeof v === 'number' && v > 0) return v; }
      return null;
    };
    return stepsArr.map(s => {
      const cal = calOf(s);
      if (typeof cal === 'number' && cal > 0 && cal !== s.targetTime) {
        return { ...s, targetTime: cal, targetTimeCalibrated: true };
      }
      return s;
    });
  };

  // 1) 品質規格マスタを優先
  const qsId = settings?.modelStandardMap?.[model];
  const qs = qsId ? settings?.qualityStandards?.[qsId] : null;
  if (qs) {
    // 規格内に対象テンプレートに一致するエントリがあるか探す
    const entries = getQsTemplateEntries(qs);
    // templateId 指定時: 完全一致を探す → 無ければ「templateId 未指定」のエントリにフォールバック
    // templateId 未指定時: 1 件だけのときに採用 (誤適用を避けるため、複数あるなら null)
    let entry;
    if (templateId) {
      entry = entries.find(e => e.templateId === templateId)
           || entries.find(e => !e.templateId); // 全テンプレ共通エントリがあれば使う
    } else {
      // templateId 未指定: 全テンプレ共通エントリを優先、無ければ 1件しかないときに採用
      entry = entries.find(e => !e.templateId)
           || (entries.length === 1 ? entries[0] : null);
    }

    if (entry) {
      const qsOverrides = entry.measurementOverrides || {};
      const qsConditions = entry.measurementConditions || {};
      const qsDefaults = entry.defaultValues || {};  // 初期値プリセット (型式群で共有)
      const qsChecklist = entry.checklistItemsByStep || {};  // 確認チェック上書き
      const qsProfile = entry.stepProfile || {};  // 型式別 工程プロファイル: { [stepId]: { enabled, description?, pdfData?, images?, targetTime? } }
      steps = steps.map(s => {
        let outStep = s;
        // 確認チェック項目の上書き (測定/非測定どちらでも適用)
        if (qsChecklist[s.id] && Array.isArray(qsChecklist[s.id])) {
          outStep = { ...outStep, checklistItems: qsChecklist[s.id] };
        }
        // 型式別 工程プロファイル: 該当なし(enabled=false) は naStepIds へ。詳細/PDF/写真/目標時間は型式別に上書き。
        const prof = qsProfile[s.id];
        if (prof) {
          if (prof.enabled === false) naStepIds.push(s.id);
          if (prof.description != null && prof.description !== '') outStep = { ...outStep, description: prof.description };
          if (prof.pdfData) outStep = { ...outStep, pdfData: prof.pdfData };
          if (Array.isArray(prof.images) && prof.images.length > 0) outStep = { ...outStep, images: prof.images };
          if (typeof prof.targetTime === 'number' && prof.targetTime > 0) outStep = { ...outStep, targetTime: prof.targetTime };
        }
        if (!s.measurementConfig) return outStep;
        let newCfg = s.measurementConfig;
        const stepOv = qsOverrides[s.id];
        if (stepOv) {
          const newCalcs = (newCfg.calculations || []).map(c => {
            const calcOv = stepOv[c.id];
            if (!calcOv) return c;
            return {
              ...c,
              ...(calcOv.nominal !== undefined ? { nominal: calcOv.nominal } : {}),
              ...(calcOv.toleranceUpper !== undefined ? { toleranceUpper: calcOv.toleranceUpper } : {}),
              ...(calcOv.toleranceLower !== undefined ? { toleranceLower: calcOv.toleranceLower } : {}),
              ...(calcOv.toleranceEnabled !== undefined ? { toleranceEnabled: calcOv.toleranceEnabled } : {})
            };
          });
          newCfg = { ...newCfg, calculations: newCalcs };
        }
        const cond = qsConditions[s.id];
        if (cond && ((cond.params && cond.params.length > 0) || cond.note)) {
          newCfg = { ...newCfg, conditionPreset: { params: cond.params || [], note: cond.note || '' } };
        }
        // 初期値プリセットを焼き付け (測定画面で「初期値を入力」ボタンとして使う)
        const defaults = qsDefaults[s.id];
        if (defaults && Object.keys(defaults).length > 0) {
          newCfg = { ...newCfg, qsDefaultValues: { ...defaults } };
        }
        return { ...outStep, measurementConfig: newCfg };
      });
      appliedStandard = {
        id: qs.id,
        standardNo: qs.standardNo || '',
        name: qs.name || '',
        revision: qs.revision || '',
        templateId: entry.templateId,
        appliedAt: Date.now(),
        source: 'qualityStandard',
      };
      return { steps: applyCalibratedTargets(steps), appliedStandard, naStepIds };
    }
    // 規格はあるがこのテンプレ用のエントリ無し → legacy にフォールバック
  }

  // 2) レガシー measurementOverrides
  const overrides = settings?.measurementOverrides?.[model];
  if (overrides && typeof overrides === 'object') {
    steps = steps.map(s => {
      const stepOv = overrides[s.id];
      if (!stepOv || !s.measurementConfig) return s;
      const newCalcs = (s.measurementConfig.calculations || []).map(c => {
        const calcOv = stepOv[c.id];
        if (!calcOv) return c;
        return {
          ...c,
          ...(calcOv.nominal !== undefined ? { nominal: calcOv.nominal } : {}),
          ...(calcOv.toleranceUpper !== undefined ? { toleranceUpper: calcOv.toleranceUpper } : {}),
          ...(calcOv.toleranceLower !== undefined ? { toleranceLower: calcOv.toleranceLower } : {}),
          ...(calcOv.toleranceEnabled !== undefined ? { toleranceEnabled: calcOv.toleranceEnabled } : {})
        };
      });
      return { ...s, measurementConfig: { ...s.measurementConfig, calculations: newCalcs } };
    });
    appliedStandard = {
      id: null,
      standardNo: '(レガシーオーバーライド)',
      name: '型式別オーバーライド',
      revision: '',
      appliedAt: Date.now(),
      source: 'legacyOverride',
    };
  }

  // 時間ソース一本化: 較正済み目標時間を焼き付け (規格なし/レガシーパス)
  return { steps: applyCalibratedTargets(steps), appliedStandard, naStepIds };
};

// 型式別プロファイルの「該当なし」工程を、ロット生成時に各台 skipped で事前生成する。
// 作業者は検査画面で「解除」して検査することも可能 (融通を残す)。
const buildProfileSkippedTasks = (steps, naStepIds, qty) => {
  const tasks = {};
  if (!Array.isArray(naStepIds) || naStepIds.length === 0) return tasks;
  const naSet = new Set(naStepIds);
  (steps || []).forEach(s => {
    if (!naSet.has(s.id)) return;
    if (s.lotOnce) {
      // ロット1回工程: 台数分の台キーを作らず、1回分の lot キーのみ skipped
      tasks[`${s.id}-lot-0`] = { status: 'skipped', profileSkipped: true, duration: 0, startTime: null, firstStartTime: null, endTime: null, workerName: '規格(該当なし)' };
      return;
    }
    for (let u = 0; u < (qty || 1); u++) {
      tasks[`${s.id}-${u}`] = { status: 'skipped', profileSkipped: true, duration: 0, startTime: null, firstStartTime: null, endTime: null, workerName: '規格(該当なし)' };
    }
  });
  return tasks;
};

// === 進捗・ETA・遅延の計算ヘルパー ===
// ロットの進捗状況を一元計算 (LotCard / ProgressOverview / 遅延アラート 共通利用)
const computeLotProgress = (lot) => {
  if (!lot || !lot.steps || lot.steps.length === 0) return null;

  let totalTasks = 0;
  let completedCount = 0;
  let totalCompletedDuration = 0;
  const tasks = lot.tasks || {};

  lot.steps.forEach((step, sIdx) => {
    if (step.lotOnce) {
      // ロット1回工程: 分母は実施回数 (最低1回)。台数では数えない。
      const keys = lotOnceKeysOf(tasks, step);
      const n = Math.max(1, keys.length);
      totalTasks += n;
      keys.forEach(k => { const t = tasks[k]; if (t && (t.status === 'completed' || t.status === 'skipped')) { completedCount++; totalCompletedDuration += (t.duration || 0); } });
      return;
    }
    totalTasks += (lot.quantity || 1);
    for (let u = 0; u < (lot.quantity || 1); u++) {
      const t = (step.id && tasks[`${step.id}-${u}`]) || tasks[`${sIdx}-${u}`];
      if (t && (t.status === 'completed' || t.status === 'skipped')) {
        completedCount++;
        totalCompletedDuration += (t.duration || 0);
      }
    }
  });

  const progressPct = totalTasks > 0 ? Math.round((completedCount / totalTasks) * 100) : 0;
  const remainingTasks = totalTasks - completedCount;

  // 平均タスク時間 (完了済みタスクから算出、なければ targetTime ベース)
  let avgTaskTime;
  if (completedCount > 0) {
    avgTaskTime = totalCompletedDuration / completedCount;
  } else {
    const targetSum = lot.steps.reduce((s, st) => s + (st.targetTime || 60), 0);
    avgTaskTime = targetSum / lot.steps.length;
  }

  // 開始時刻 (Firestore Timestamp / number / undefined どれでも対応)
  // 「予測時間の開始」は 実際に作業を開始した時刻 (workStartTime) のみを使用する。
  // 入荷時刻や登録時刻をフォールバックに使うと、まだ着手していないロットでも
  // 過去の時刻が「開始」として表示されて紛らわしいため、未開始は 0 を返す。
  const toMs = (v) => { if (!v) return 0; if (typeof v === 'number') return v; if (v.seconds) return v.seconds * 1000; if (v.toMillis) return v.toMillis(); const t = new Date(v).getTime(); return isNaN(t) ? 0 : t; };
  const startMs = toMs(lot.workStartTime);

  // 予測完了時刻 (ETA)
  const remainingSec = remainingTasks * avgTaskTime;
  const etaMs = Date.now() + remainingSec * 1000;

  // 標準予定時刻 (targetTime ベースで純粋に算出された理想完了時刻)
  // 未開始の場合は「今すぐ着手した場合の理想完了時刻」を採用する
  const standardDurationSec = lot.steps.reduce((s, st) => s + (st.lotOnce ? 0 : (st.targetTime || 60)), 0) * (lot.quantity || 1)
    + lot.steps.reduce((s, st) => s + (st.lotOnce ? (st.targetTime || 60) : 0), 0); // ロット1回工程は×1
  const standardStartMs = startMs || Date.now();
  const standardEtaMs = standardStartMs + standardDurationSec * 1000;

  // 遅延判定: ETA が標準予定より 30分以上後なら warning, 1時間以上後なら critical
  const delayMs = etaMs - standardEtaMs;
  let delayLevel = 'ontime';
  if (delayMs > 60 * 60 * 1000) delayLevel = 'critical';
  else if (delayMs > 30 * 60 * 1000) delayLevel = 'warning';
  else if (delayMs < -10 * 60 * 1000) delayLevel = 'ahead';

  // 完了済みなら ETA は完了時刻、遅延なし
  const isCompleted = lot.status === 'completed' || lot.location === 'completed';
  if (isCompleted) {
    delayLevel = 'completed';
  }

  return {
    totalTasks, completedCount, progressPct, remainingTasks,
    avgTaskTime, startMs, etaMs, standardEtaMs, delayMs, delayLevel,
    isCompleted, isProcessing: lot.status === 'processing',
  };
};

// 時刻を HH:MM 形式で
const formatHHMM = (ms) => {
  if (!ms) return '--:--';
  const d = new Date(ms);
  return `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
};

// 「作業中」判定の共通化: lot.status === 'processing' か、カスタムモードで個別タスクが processing
const checkLotProcessing = (lot) => {
  if (!lot) return false;
  if (lot.status === 'processing') return true;
  const tasks = lot.tasks || {};
  for (const k in tasks) {
    if (tasks[k] && tasks[k].status === 'processing') return true;
  }
  return false;
};

// 停止理由カテゴリ → 色/絵文字 マッピング (4箇所で重複していたものを共通化)
const PAUSE_REASON_COLOR_MAP = {
  waiting_lot:      { bg: 'bg-amber-100',  border: 'border-amber-300',  text: 'text-amber-800',  emoji: '🟡' },
  waiting_repair:   { bg: 'bg-orange-100', border: 'border-orange-300', text: 'text-orange-800', emoji: '🟠' },
  paused:           { bg: 'bg-rose-100',   border: 'border-rose-300',   text: 'text-rose-800',   emoji: '🔴' },
  waiting_parts:    { bg: 'bg-purple-100', border: 'border-purple-300', text: 'text-purple-800', emoji: '🟣' },
  waiting_decision: { bg: 'bg-blue-100',   border: 'border-blue-300',   text: 'text-blue-800',   emoji: '🔵' },
};
const PAUSE_REASON_FALLBACK_COLOR = { bg: 'bg-slate-100', border: 'border-slate-300', text: 'text-slate-700', emoji: '⏸' };
const getPauseReasonColor = (category) => PAUSE_REASON_COLOR_MAP[category] || PAUSE_REASON_FALLBACK_COLOR;

// --- Measurement Utilities ---
// 数式評価 (セキュリティ強化版)
// - 変数 ID は英数字・アンダースコアのみ許可
// - 置換後の式は許可文字 + e/E (指数表記) のみ
// - new Function は使わず、自前 RPN 評価でサンドボックス化
// (evaluateFormula, evalArith, BLOCK_GAUGE_PRESETS は ./measurement-utils.js に移動)

const calculateMeasurementResult = (values, config) => {
  const entries = config.inputs.map(inp => ({ id: inp.id, val: Number(values[inp.id]) })).filter(e => !isNaN(e.val) && values[e.id] !== '' && values[e.id] != null);
  if (entries.length === 0) return null;
  const nums = entries.map(e => e.val);
  switch (config.calculation) {
    case 'max-min': return Math.max(...nums) - Math.min(...nums);
    case 'sum': return nums.reduce((a, b) => a + b, 0);
    case 'average': return nums.reduce((a, b) => a + b, 0) / nums.length;
    case 'formula': return evaluateFormula(config.formula, values);
    case 'group-max-min': {
      const groups = {};
      entries.forEach(e => {
        const prefix = e.id.replace(/[0-9]/g, '');
        if (!groups[prefix]) groups[prefix] = [];
        groups[prefix].push(e.val);
      });
      const groupMaxMins = Object.values(groups).filter(g => g.length > 0).map(g => Math.max(...g) - Math.min(...g));
      if (groupMaxMins.length === 0) return null; // 空グループ → null (Math.max([]) は -Infinity を返すため)
      return Math.max(...groupMaxMins);
    }
    default: return null;
  }
};

const calculateSingleResult = (values, relevantInputs, calc) => {
  // 入力ID + 「前の計算結果のID」両方を受け取れるように
  // values オブジェクトには通常入力に加えて、計算済みの calcId → result も入っている前提
  const entries = relevantInputs.map(inp => ({ id: inp.id, val: Number(values[inp.id]) })).filter(e => !isNaN(e.val) && values[e.id] !== '' && values[e.id] != null);
  if (calc.method === 'formula') {
    // 数式は relevantInputs に依存しない (values に全てが入っているため)
    return evaluateFormula(calc.formula, values);
  }
  if (entries.length === 0) return null;
  const nums = entries.map(e => e.val);
  switch (calc.method) {
    case 'max-min': return Math.max(...nums) - Math.min(...nums);
    case 'sum': return nums.reduce((a, b) => a + b, 0);
    case 'average': return nums.reduce((a, b) => a + b, 0) / nums.length;
    case 'abs-max': return Math.max(...nums.map(n => Math.abs(n)));
    case 'diff': {
      // 2点間の差: 入力 ID 順で最初と最後の差
      if (nums.length < 2) return null;
      return nums[0] - nums[nums.length - 1];
    }
    case 'group-max-min': {
      // 各グループ内の最大-最小 → さらに最大
      const groups = {};
      entries.forEach(e => {
        const inp = relevantInputs.find(i => i.id === e.id);
        const key = groupKeyFor(inp || { id: e.id });
        if (!groups[key]) groups[key] = [];
        groups[key].push(e.val);
      });
      const groupMaxMins = Object.values(groups).filter(g => g.length > 0).map(g => Math.max(...g) - Math.min(...g));
      if (groupMaxMins.length === 0) return null; // 空グループ防止
      return Math.max(...groupMaxMins);
    }
    case 'rows-diff': {
      // 通りの差: 各グループの平均値同士の差 (グループ平均 max - グループ平均 min)
      // 例: A グループ平均 50.02, B グループ平均 50.05 → 0.03
      const groups = {};
      entries.forEach(e => {
        const inp = relevantInputs.find(i => i.id === e.id);
        const key = groupKeyFor(inp || { id: e.id });
        if (!groups[key]) groups[key] = [];
        groups[key].push(e.val);
      });
      const groupAvgs = Object.values(groups).map(g => g.reduce((a, b) => a + b, 0) / g.length);
      if (groupAvgs.length < 2) return null; // グループが1つしかない場合は計算不可
      return Math.max(...groupAvgs) - Math.min(...groupAvgs);
    }
    default: return null;
  }
};

// --- Voice Assistant Utilities ---
// iOS Safari: speechSynthesisはユーザージェスチャーで一度アンロックが必要
let ttsUnlocked = false;
const unlockTTSForIOS = () => {
  if (ttsUnlocked || !window.speechSynthesis) return;
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  if (!isIOS) { ttsUnlocked = true; return; }
  const u = new SpeechSynthesisUtterance('');
  u.volume = 0;
  u.lang = 'ja-JP';
  window.speechSynthesis.speak(u);
  ttsUnlocked = true;
};
// iOS Safari: speechSynthesisが15秒でポーズするバグ対策
let iosResumeInterval = null;
const startIOSResumeFix = () => {
  if (iosResumeInterval) return;
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  if (!isIOS) return;
  iosResumeInterval = setInterval(() => {
    if (window.speechSynthesis?.speaking) window.speechSynthesis.resume();
  }, 5000);
};
const stopIOSResumeFix = () => {
  if (iosResumeInterval) { clearInterval(iosResumeInterval); iosResumeInterval = null; }
};

const speak = (text, onEnd, options = {}) => {
  if (!window.speechSynthesis) { onEnd?.(); return; }
  window.speechSynthesis.cancel();
  startIOSResumeFix();
  const doSpeak = () => {
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'ja-JP';
    utterance.rate = options.rate || 1.1;
    utterance.volume = options.volume ?? 1.0;
    // Use specified voice or find a Japanese voice
    if (options.voice) {
      utterance.voice = options.voice;
    } else if (options.voiceName) {
      const voices = window.speechSynthesis.getVoices();
      const found = voices.find(v => v.name === options.voiceName);
      if (found) utterance.voice = found;
      else {
        const jaVoice = voices.find(v => v.lang.startsWith('ja'));
        if (jaVoice) utterance.voice = jaVoice;
      }
    } else {
      const voices = window.speechSynthesis.getVoices();
      const jaVoice = voices.find(v => v.lang.startsWith('ja'));
      if (jaVoice) utterance.voice = jaVoice;
    }
    if (onEnd) utterance.onend = onEnd;
    utterance.onerror = () => { console.warn('Speech error for:', text); onEnd?.(); };
    window.speechSynthesis.speak(utterance);
  };
  // Voices may not be loaded yet
  if (window.speechSynthesis.getVoices().length === 0) {
    window.speechSynthesis.onvoiceschanged = () => { doSpeak(); window.speechSynthesis.onvoiceschanged = null; };
    // Fallback if voices never load
    setTimeout(() => { if (window.speechSynthesis.getVoices().length === 0) { doSpeak(); } }, 500);
  } else {
    doSpeak();
  }
};

let isSpeakingTTS = false;
const speakAsync = (text, options = {}) => new Promise(resolve => {
  isSpeakingTTS = true;
  speak(text, () => { isSpeakingTTS = false; resolve(); }, options);
});

// TTS再生が終わるまで待つ
const waitForTTSEnd = () => new Promise(resolve => {
  if (!isSpeakingTTS) { resolve(); return; }
  const check = setInterval(() => {
    if (!isSpeakingTTS) { clearInterval(check); setTimeout(resolve, 300); } // 300ms余裕
  }, 100);
  // 最大5秒で強制解除
  setTimeout(() => { clearInterval(check); isSpeakingTTS = false; resolve(); }, 5000);
});

const listenOnce = async (options = {}) => {
  // TTS再生中なら終わるまで待つ（自分の声を拾わないように）
  await waitForTTSEnd();

  return new Promise((resolve) => {
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    if (!SR) {
      const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
      if (options.onError) options.onError(isIOS
        ? '音声認識非対応: iOS/iPadOSではSafariの最新版（iOS 14.5以上）が必要です'
        : 'このブラウザは音声認識に対応していません（Chrome/Edgeを使用してください）');
      resolve(null); return;
    }
    const recognition = new SR();
    recognition.lang = 'ja-JP';
    recognition.continuous = false;
    recognition.interimResults = true;
    let resolved = false;
    const timeout = options.timeout || 10000;
    const timer = setTimeout(() => {
      if (!resolved) { resolved = true; try { recognition.stop(); } catch {} resolve(options.defaultValue ?? null); }
    }, timeout);
    recognition.onaudiostart = () => {
      if (options.onListening) options.onListening();
    };
    recognition.onresult = (event) => {
      const last = event.results[event.results.length - 1];
      if (last.isFinal) {
        if (!resolved) { resolved = true; clearTimeout(timer); resolve(last[0].transcript); }
      } else {
        if (options.onInterim) options.onInterim(last[0].transcript);
      }
    };
    recognition.onerror = (e) => {
      console.warn('[listenOnce] error:', e.error, e.message);
      if (e.error === 'not-allowed') {
        if (options.onError) options.onError('マイクの使用が許可されていません。アドレスバーの🔒→サイトのアクセス許可→マイク→許可');
      } else if (e.error === 'no-speech') {
        // 無音 - 正常
      } else if (e.error === 'aborted') {
        // 中断 - 正常
      } else if (e.error === 'network') {
        if (options.onError) options.onError('音声認識サービスに接続できません。インターネット接続を確認してください');
      } else {
        if (options.onError) options.onError(`音声認識エラー: ${e.error}`);
      }
      if (!resolved) { resolved = true; clearTimeout(timer); resolve(null); }
    };
    recognition.onend = () => { console.log('[listenOnce] onend, resolved:', resolved); if (!resolved) { resolved = true; clearTimeout(timer); resolve(options.defaultValue ?? null); } };
    try {
      recognition.start();
      console.log('[listenOnce] recognition.start() called, timeout:', timeout);
    } catch(e) {
      console.warn('Speech start failed:', e);
      if (options.onError) options.onError('音声認識の開始に失敗しました');
      resolve(null);
    }
  });
};

// Default voice command mappings
const DEFAULT_VOICE_COMMANDS = [
  { id: 'yes', label: 'はい（確認）', keywords: 'はい,うん,OK,オーケー,そう,イエス,yes', description: '確認・肯定の応答' },
  { id: 'no', label: 'いいえ（否定）', keywords: 'いいえ,いや,ダメ,違う,ノー,no', description: '否定の応答' },
  { id: 'complete', label: '完了', keywords: '完了,かんりょう,終わり,おわり,done', description: '現在の作業を完了' },
  { id: 'interrupt', label: '中断（一時停止）', keywords: '中断,ちゅうだん,止め,やめ,ストップ,stop', description: '作業時間の計測を一時停止/再開' },
  { id: 'next', label: '次へ', keywords: '次,つぎ,next', description: '次の工程/台に進む' },
  { id: 'measurement', label: '測定入力', keywords: '測定入力,測定開始,そくてい', description: '測定の音声入力を開始' },
  { id: 'sequential', label: '通常モード', keywords: '通常,じゅんじょ,順序,ノーマル', description: '通常（順序）モードを選択' },
  { id: 'custom', label: 'カスタムモード', keywords: 'カスタム,自由,じゆう', description: 'カスタムモードを選択' },
  { id: 'batch', label: 'まとめて', keywords: 'まとめ,一括,バッチ', description: 'まとめて開始/完了' },
  { id: 'allComplete', label: '全作業完了', keywords: '全部完了,全作業完了,すべて完了', description: '全工程を完了する' },
  { id: 'skip', label: '該当なし', keywords: '該当なし,該当無し,対象外,スキップ,飛ばす,とばす', description: 'この工程を該当なし(実施しない)に' },
  { id: 'ng', label: 'NG/不具合', keywords: 'NG,エヌジー,不具合,不良,だめ,ダメ,バツ', description: '不具合を報告する' },
  { id: 'rework', label: '修正', keywords: '修正,手直し,リワーク,やり直し,直す', description: '修正(リワーク)を開始' },
  { id: 'reworkDone', label: '修正完了', keywords: '修正完了,手直し完了,直りました,直った', description: '修正を完了する' },
  { id: 'resume', label: '再開', keywords: '再開,続ける,続き,リスタート', description: '中断から再開する' },
];

// Build matcher from voice commands config
const buildVoiceMatcher = (voiceCommands) => {
  const map = {};
  const cmds = voiceCommands || DEFAULT_VOICE_COMMANDS;
  cmds.forEach(cmd => {
    const words = (cmd.keywords || '').split(',').map(w => w.trim()).filter(Boolean);
    // ⚠ キーワードが空だと正規表現が /(?:)/ となり全発話に誤マッチ(暴発)する。空のときは「絶対に一致しない」マッチャにする。
    if (words.length === 0) { map[cmd.id] = () => false; return; }
    const pattern = new RegExp(words.map(w => w.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'), 'i');
    // 生テキストと基本正規化(数字読み変換なし)の両方で判定 → 語が数字化で壊れる事故を回避。
    map[cmd.id] = (text) => {
      if (!text) return false;
      return pattern.test(text) || pattern.test(normalizeVoiceTextBasic(text));
    };
  });
  return map;
};

// コマンド一致は「生テキスト」と「基本正規化(数字読み変換なし)」の両方で判定する共通ヘルパー。
const vt_ = (re, text) => !!text && (re.test(text) || re.test(normalizeVoiceTextBasic(text)));
// Fallback matchers (used when no settings loaded)
const isYesResponse = (text) => vt_(/はい|はーい|うん|OK|オーケー|オッケー|そう|了解|りょうかい|イエス|yes/i, text);
const isNoResponse = (text) => vt_(/いいえ|いや|ダメ|違う|ちがう|ノー|no/i, text);
const isCompleteCmd = (text) => vt_(/完了|かんりょう|終わり|おわり|できた|done/i, text);
const isInterruptCmd = (text) => vt_(/中断|ちゅうだん|一時停止|止めて|止め|やめて|ストップ|ポーズ|stop|pause/i, text);
const isNextCmd = (text) => { if (vt_(/次工程|次の工程/i, text)) return false; const t = normalizeVoiceTextBasic(text).trim(); return /^(次|つぎ|next)$/i.test(t) || vt_(/次へ|つぎへ|次の台|つぎの台|次お願い|次行って/i, text); };
const isNextStepCmd = (text) => vt_(/次工程|次の工程|つぎこうてい|つぎのこうてい/i, text);
const isCancelCmd = (text) => vt_(/キャンセル|取り消し|取消|とりけし|cancel/i, text);
// 「完全に音声で支配」用の追加コマンド (設定が無い時のフォールバック)
const isSkipCmd = (text) => vt_(/該当なし|該当無し|がいとうなし|対象外|スキップ|とばす|飛ばす|とばして|飛ばして|skip|パス/i, text);
const isNgCmd = (text) => vt_(/NG|エヌジー|エヌ.?ジー|不具合|不良|バツ|ばつ|×|だめ|ダメ/i, text);
const isReworkDoneCmd = (text) => vt_(/修正.?(?:完了|終わり|おわり|でき)|手直し.?(?:完了|終わり)|直りました|直った|なおった|治った|リワーク.?完了/i, text);
const isReworkCmd = (text) => { if (isReworkDoneCmd(text)) return false; return vt_(/修正|手直し|リワーク|やり直し|やりなおし|直す|なおす/i, text); };
const isResumeCmd = (text) => vt_(/再開|さいかい|続け|つづけ|続き|つづき|再スタート|リスタート|resume/i, text);
const isStatusCmd = (text) => vt_(/今どこ|いまどこ|今の工程|現在の工程|状況|どこまで|何工程|なん工程|進捗/i, text);
const isHelpCmd = (text) => vt_(/ヘルプ|help|使い方|コマンド|何て言えば|なんて言えば|何が言える|何が使える/i, text);
const isVoiceOffCmd = (text) => vt_(/音声.?(?:オフ|終了|切|止|やめ)|アシスタント.?(?:オフ|終了)|もう終わり|おしまい/i, text);

// 同ロット内の他工程の測定結果を1つのオブジェクトにまとめる (cross-step 参照用)
// 戻り値: { [入力ID または 計算ID]: 値 } — 現在の工程と ID 衝突する場合は現工程優先
// ID 衝突を避けたい場合は `stepタイトル_変数名` の形式でも引けるよう、両方の形式を入れる
// 同ロット内 他工程の測定結果を「数式から参照可能な変数」として収集する。
// 出力:
//  - bare ID (k, calc.id): 後方互換 (既存式は無修正で動く)。衝突時は先勝ち。
//  - prefixed ID (${stepId}_${k}, ${stepId}_${calc.id}): 衝突しない一意のID。新規式はこちらを推奨。
const collectCrossStepValues = (lot, currentStepId) => {
  if (!lot || !lot.steps || !lot.measurementResults) return {};
  const out = {};
  lot.steps.forEach(step => {
    if (!step || step.id === currentStepId) return; // 現工程は除外
    const cfg = step.measurementConfig;
    if (!cfg) return;
    const inputVals = lot.measurementResults[`${step.id}-0-values`]
      || lot.measurementResults[`${step.id}-values`]
      || {};
    const resultData = lot.measurementResults[`${step.id}-0`]
      || lot.measurementResults[`${step.id}-result`];
    const calcResults = resultData?.calcResults || [];
    Object.entries(inputVals).forEach(([k, v]) => {
      const num = Number(v);
      if (!Number.isFinite(num)) return;
      if (out[k] === undefined) out[k] = num; // bare (後方互換、先勝ち)
      out[`${step.id}_${k}`] = num;            // prefixed (衝突回避)
    });
    calcResults.forEach(cr => {
      if (cr?.id && Number.isFinite(cr.result)) {
        if (out[cr.id] === undefined) out[cr.id] = cr.result;
        out[`${step.id}_${cr.id}`] = cr.result;
      }
    });
  });
  return out;
};

// 計算チェーン: 計算は順番に評価され、前の計算結果は後続の計算で変数として使える。
// extraValues に他工程の計算結果を渡すと、数式参照で利用可能。
const calculateMeasurementResults = (values, config, extraValues = {}) => {
  const calculations = config.calculations || [{
    id: 'default',
    label: '計算結果',
    method: config.calculation,
    formula: config.formula,
    inputIds: [],
    toleranceUpper: config.toleranceUpper,
    toleranceLower: config.toleranceLower,
    unit: config.unit
  }];

  // 累積コンテキスト: 通常入力 + 他工程結果 + 計算済みの値
  const ctx = { ...extraValues, ...values };

  return calculations.map(calc => {
    // inputIds に含まれる ID は「通常入力 ID」または「同工程の前の計算 ID」の両方を許可
    let relevantInputs;
    if (calc.inputIds?.length > 0) {
      // 通常入力からマッチするもの
      const inputMatches = config.inputs.filter(inp => calc.inputIds.includes(inp.id));
      // 計算 ID からマッチするもの (前に計算済みのみ)
      const calcMatches = calc.inputIds
        .filter(id => !config.inputs.some(inp => inp.id === id) && ctx[id] !== undefined)
        .map(id => ({ id, label: id })); // 仮想入力として扱う
      relevantInputs = [...inputMatches, ...calcMatches];
    } else {
      relevantInputs = config.inputs;
    }
    const result = calculateSingleResult(ctx, relevantInputs, calc);
    // この計算結果を次の計算で参照可能にする
    if (result !== null && !isNaN(result)) {
      ctx[calc.id] = result;
    }
    // 公差判定:
    // - toleranceEnabled === false → 判定なし (記録のみ)
    // - nominal がある場合: 範囲 = nominal + [toleranceLower, toleranceUpper]
    // - nominal が無い場合: 既存挙動 (公差を絶対値として扱う)
    const toleranceEnabled = calc.toleranceEnabled !== false; // 未指定 or true で判定ON (後方互換)
    const nominal = Number.isFinite(Number(calc.nominal)) ? Number(calc.nominal) : 0;
    let isOk = null;
    let lowerLimit = null, upperLimit = null;
    if (result !== null && toleranceEnabled) {
      lowerLimit = nominal + (calc.toleranceLower ?? -Infinity);
      upperLimit = nominal + (calc.toleranceUpper ?? Infinity);
      isOk = result >= lowerLimit && result <= upperLimit;
    }
    return { ...calc, result, isOk, nominal, toleranceEnabled, lowerLimit, upperLimit };
  });
};

// 矢印比較を評価: 2つの値 (入力 or 計算結果) を比較し、1つの矢印を 1箇所に表示
// 戻り値: arrows ごとに { pos, dir: 'up'|'down'|'equal'|null, valA, valB, diff, label }
// pos は { x, y } in % (表示位置)
const evaluateArrows = (config, values, calcResults, extraValues = {}) => {
  const arrows = config?.arrows || [];
  if (arrows.length === 0) return [];
  const inputs = config?.inputs || [];
  // 全ての参照可能な値を統合
  const calcMap = {};
  (calcResults || []).forEach(cr => { if (cr?.id) calcMap[cr.id] = cr.result; });
  const allValues = { ...extraValues, ...values, ...calcMap };

  return arrows.map(arr => {
    const valA = Number(allValues[arr.sourceA]);
    const valB = Number(allValues[arr.sourceB]);
    // 表示位置の決定 (優先順位):
    //  1) 明示的に position が指定されていれば、それを使う
    //  2) sourceA と sourceB が両方とも入力ポイント (inputs に存在) なら、その中点
    //  3) どちらか一方だけ入力ポイントなら、その位置
    //  4) どれも該当しなければ中央 (50, 50)
    // ※ 以前は (1) → (4) しか無く、複数の矢印に position が無いと全部 (50, 50)
    //    に重なって表示されていた (拡大測定画面で 1 本しか見えないバグ)。
    let pos = arr.position;
    if (!pos) {
      const inputA = inputs.find(i => i.id === arr.sourceA);
      const inputB = inputs.find(i => i.id === arr.sourceB);
      if (inputA && inputB) pos = { x: (inputA.x + inputB.x) / 2, y: (inputA.y + inputB.y) / 2 };
      else if (inputA) pos = { x: inputA.x, y: inputA.y };
      else if (inputB) pos = { x: inputB.x, y: inputB.y };
      else pos = { x: 50, y: 50 };
    }
    if (!Number.isFinite(valA) || !Number.isFinite(valB)) {
      return { ...arr, pos, valA, valB, dir: null, diff: null };
    }
    const threshold = Number(arr.threshold) || 0;
    const diff = valA - valB;
    let dir;
    if (Math.abs(diff) <= threshold) dir = 'equal';
    else if (diff > 0) dir = 'up';   // A > B → ↗
    else dir = 'down';                // A < B → ↘
    return { ...arr, pos, valA, valB, dir, diff };
  });
};

// 音声テキスト正規化: 誤変換補正 + 全角→半角 + 漢数字→数字
// 基本正規化: 同音語補正 + 全角→半角 のみ。数字読み(し→4 等)は変換しない。
//   ※ コマンド一致(is*Cmd / buildVoiceMatcher)はこの基本正規化で判定する。数字読み変換を混ぜると
//     「該当なし→該当な4」「取り消し→取り消4」のように語が壊れて該当コマンドが不発になる事故が起きるため。
const normalizeVoiceTextBasic = (text) => {
  if (!text) return '';
  let t = text;
  const homophones = {
    '皇帝': '工程', '号艇': '工程', '後程': '工程', '高低': '工程', '肯定': '工程', 'こうてい': '工程',
    '交代': '工程', '好転': '工程', '公定': '工程', '行程': '工程', '校庭': '工程', '口頭': '工程',
    '代目': '台目', 'だいめ': '台目', '大目': '台目', '題目': '台目',
    '完了': '完了', 'かんりょう': '完了',
    '中断': '中断', 'ちゅうだん': '中断',
    '測定': '測定', 'そくてい': '測定',
    '次': '次', 'つぎ': '次',
  };
  Object.entries(homophones).forEach(([k, v]) => {
    if (k !== v) t = t.replace(new RegExp(k, 'g'), v);
  });
  // 全角数字→半角
  t = t.replace(/[０-９]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0));
  // 全角英字→半角
  t = t.replace(/[Ａ-Ｚａ-ｚ]/g, c => String.fromCharCode(c.charCodeAt(0) - 0xFEE0));
  return t;
};

// 音声テキスト正規化: 基本 + 漢数字/ひらがな数字→半角数字。「N工程/N台目」や測定値の解釈に使う。
const normalizeVoiceText = (text) => {
  if (!text) return '';
  let t = normalizeVoiceTextBasic(text);
  // 漢数字→半角 (位取り対応: 百/十)
  const kanjiMap = { '零': 0, '〇': 0, '一': 1, '二': 2, '三': 3, '四': 4, '五': 5, '六': 6, '七': 7, '八': 8, '九': 9, '十': 10, '百': 100 };
  // ひらがな数字→半角
  const hiraMap = { 'いち': '1', 'に': '2', 'さん': '3', 'し': '4', 'よん': '4', 'ご': '5', 'ろく': '6', 'なな': '7', 'しち': '7', 'はち': '8', 'きゅう': '9', 'く': '9', 'じゅう': '10' };
  // ひらがな数字→数字 (長い順にマッチ)
  Object.entries(hiraMap).sort((a,b) => b[0].length - a[0].length).forEach(([k, v]) => {
    t = t.replace(new RegExp(k, 'g'), v);
  });
  // 漢数字の位取り変換: 二十三→23, 十五→15 etc
  t = t.replace(/([一二三四五六七八九]?)百([一二三四五六七八九]?十?[一二三四五六七八九]?)/g, (_, h, rest) => {
    let val = (h ? kanjiMap[h] : 1) * 100;
    const tenMatch = rest.match(/([一二三四五六七八九]?)十([一二三四五六七八九]?)/);
    if (tenMatch) {
      val += (tenMatch[1] ? kanjiMap[tenMatch[1]] : 1) * 10;
      if (tenMatch[2]) val += kanjiMap[tenMatch[2]];
    } else {
      // 残り1文字の漢数字
      for (const c of rest) { if (kanjiMap[c] !== undefined && kanjiMap[c] < 10) val += kanjiMap[c]; }
    }
    return String(val);
  });
  t = t.replace(/([一二三四五六七八九]?)十([一二三四五六七八九]?)/g, (_, tens, ones) => {
    return String((tens ? kanjiMap[tens] : 1) * 10 + (ones ? kanjiMap[ones] : 0));
  });
  // 残りの単独漢数字
  t = t.replace(/[零〇一二三四五六七八九]/g, c => String(kanjiMap[c]));
  // 連続数字を結合しない（"1 0" → そのまま）
  return t;
};

const parseJapaneseNumber = (text) => {
  if (!text) return null;
  const norm = normalizeVoiceText(text);
  const direct = norm.replace(/[,\s]/g, '');
  if (/^[+-]?\d+\.?\d*$/.test(direct)) return parseFloat(direct);
  let cleaned = norm.replace(/プラス/g, '+').replace(/マイナス/g, '-').replace(/てん|点/g, '.').replace(/ミリ|mm/g, '');
  const numMatch = cleaned.match(/[+-]?\d+\.?\d*/);
  if (numMatch) return parseFloat(numMatch[0]);
  return null;
};

const getPastMeasurementData = (lots, model, stepId) => {
  const results = [];
  lots.forEach(lot => {
    if (lot.status !== 'completed' || lot.model !== model || !lot.measurementResults) return;
    Object.entries(lot.measurementResults).forEach(([key, result]) => {
      if (key.startsWith(stepId + '-')) results.push(result);
    });
  });
  return results;
};

const getPastInputStats = (pastData, inputId) => {
  const vals = pastData.map(d => d.values?.[inputId]).filter(v => v != null && !isNaN(Number(v))).map(Number);
  if (vals.length === 0) return null;
  return {
    last: vals[vals.length - 1],
    avg: (vals.reduce((a, b) => a + b, 0) / vals.length),
    count: vals.length
  };
};

