// --- Process Improvement Optimization ---

const calculateStats = (times) => {
    if (!times || times.length === 0) return null;
    const sorted = [...times].sort((a, b) => a - b);
    const q1 = sorted[Math.floor(sorted.length / 4)];
    const q3 = sorted[Math.floor(sorted.length * (3 / 4))];
    const iqr = q3 - q1;
    const validTimes = sorted.filter(t => t >= q1 - 1.5 * iqr && t <= q3 + 1.5 * iqr);
    if (validTimes.length === 0) return null;
    const validSorted = [...validTimes].sort((a, b) => a - b);
    const sum = validSorted.reduce((a, b) => a + b, 0);
    const mean = sum / validSorted.length;
    const variance = validSorted.reduce((a, b) => a + Math.pow(b - mean, 2), 0) / validSorted.length;
    const stdDev = Math.sqrt(variance);
    return {
        rawCount: times.length,
        validCount: validSorted.length,
        min: Math.min(...validSorted),
        max: Math.max(...validSorted),
        mean: Math.round(mean),
        median: validSorted[Math.floor(validSorted.length / 2)],
        stdDev: Math.round(stdDev),
        p25: validSorted[Math.floor(validSorted.length * 0.25)],
        p75: validSorted[Math.floor(validSorted.length * 0.75)]
    };
};

// 目標時間の変更履歴を「一元管理の表」で表示。いつ・誰が・どの対象の工程を・何から何に・
// どのエビデンスで変えたかを1行ずつ監査できる。
const TargetTimeHistoryPanel = ({ history }) => {
    const rows = [];
    [...history].sort((a, b) => b.timestamp - a.timestamp).forEach(h => {
        (h.updates || []).forEach(u => rows.push({ ...u, timestamp: h.timestamp, by: h.by, targetType: h.targetType, targetValue: h.targetValue }));
    });
    const fmt = (ts) => { const d = new Date(ts); return isNaN(d) ? '-' : `${d.getFullYear()}/${d.getMonth() + 1}/${d.getDate()} ${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`; };
    return (
        <div className="flex-1 overflow-auto pr-1">
            <div className="text-xs text-slate-500 mb-2 flex items-center gap-1"><History className="w-3.5 h-3.5" /> いつ・誰が・どの対象の工程を・何から何に・どのエビデンスで変えたかの記録（{rows.length}件）</div>
            <table className="w-full text-sm border-collapse">
                <thead className="sticky top-0 bg-slate-100 z-10">
                    <tr className="text-left text-slate-700">
                        <th className="px-3 py-2 font-black border-b border-slate-300 whitespace-nowrap">日時</th>
                        <th className="px-3 py-2 font-black border-b border-slate-300">担当</th>
                        <th className="px-3 py-2 font-black border-b border-slate-300">対象</th>
                        <th className="px-3 py-2 font-black border-b border-slate-300">工程</th>
                        <th className="px-3 py-2 font-black border-b border-slate-300 text-center">変更</th>
                        <th className="px-3 py-2 font-black border-b border-slate-300">戦略</th>
                        <th className="px-3 py-2 font-black border-b border-slate-300">エビデンス</th>
                    </tr>
                </thead>
                <tbody>
                    {rows.map((u, i) => (
                        <tr key={i} className="border-b border-slate-100 hover:bg-indigo-50/40 align-top">
                            <td className="px-3 py-2 text-[11px] text-slate-600 whitespace-nowrap">{fmt(u.timestamp)}</td>
                            <td className="px-3 py-2 font-bold text-slate-700 whitespace-nowrap">{u.by || '-'}</td>
                            <td className="px-3 py-2 whitespace-nowrap"><span className="text-[10px] bg-slate-200 text-slate-600 px-1.5 py-0.5 rounded mr-1">{u.targetType === 'app' ? '外観図' : '型式'}</span>{u.targetValue}</td>
                            <td className="px-3 py-2 text-slate-700"><span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded mr-1">{u.category}</span>{u.title}</td>
                            <td className="px-3 py-2 text-center font-mono whitespace-nowrap"><span className="text-slate-400 line-through">{u.oldTime}s</span> → <b className="text-blue-600">{u.newTime}s</b></td>
                            <td className="px-3 py-2"><span className="text-[10px] bg-indigo-50 text-indigo-700 px-1.5 py-0.5 rounded border border-indigo-100 font-bold">{u.strategyName}</span></td>
                            <td className="px-3 py-2 text-[11px] text-slate-600">{u.evidence ? `期間:${u.evidence.periodLabel} / ${u.evidence.validCount}件 / 平均${u.evidence.mean}s${u.evidence.stdDev != null ? ` / ±${u.evidence.stdDev}s` : ''}` : '-'}</td>
                        </tr>
                    ))}
                    {rows.length === 0 && <tr><td colSpan={7} className="text-center text-slate-400 py-10">変更履歴はありません</td></tr>}
                </tbody>
            </table>
        </div>
    );
};

// ===========================
// 型式別 公差・基準値オーバーライド設定パネル
// ===========================
// 工程テンプレートは1本だが、型式によって公差や基準値が変わるケースに対応
// データ構造: measurementOverrides[model][stepId][calcId] = { nominal, toleranceUpper, toleranceLower, toleranceEnabled }
// ロット作成時 (handleAddLot) に model に該当するオーバーライドが自動適用される
const MeasurementOverridesPanel = ({ templates, lots, measurementOverrides, saveSettings }) => {
    const [selectedTemplateId, setSelectedTemplateId] = useState('');
    const [selectedModel, setSelectedModel] = useState('');
    const [newModelInput, setNewModelInput] = useState('');

    // 利用可能な型式: ロットから抽出 + 既にオーバーライドが定義されてる型式
    const knownModels = useMemo(() => {
        const set = new Set();
        (lots || []).forEach(l => { if (l.model) set.add(l.model); });
        Object.keys(measurementOverrides || {}).forEach(m => set.add(m));
        return Array.from(set).sort();
    }, [lots, measurementOverrides]);

    // 選択されたテンプレートの測定工程一覧
    const measurementSteps = useMemo(() => {
        const tpl = templates.find(t => t.id === selectedTemplateId);
        if (!tpl) return [];
        return (tpl.steps || []).filter(s => s.type === 'measurement' && s.measurementConfig);
    }, [templates, selectedTemplateId]);

    const updateOverride = (model, stepId, calcId, patch) => {
        const next = { ...(measurementOverrides || {}) };
        next[model] = { ...(next[model] || {}) };
        next[model][stepId] = { ...(next[model][stepId] || {}) };
        const cur = next[model][stepId][calcId] || {};
        const merged = { ...cur, ...patch };
        // 全フィールドが空/デフォルトなら削除
        const isEmpty = (merged.nominal === undefined || merged.nominal === null || merged.nominal === '')
            && (merged.toleranceUpper === undefined || merged.toleranceUpper === '')
            && (merged.toleranceLower === undefined || merged.toleranceLower === '')
            && (merged.toleranceEnabled === undefined);
        if (isEmpty) {
            delete next[model][stepId][calcId];
            if (Object.keys(next[model][stepId]).length === 0) delete next[model][stepId];
            if (Object.keys(next[model]).length === 0) delete next[model];
        } else {
            next[model][stepId][calcId] = merged;
        }
        saveSettings({ measurementOverrides: next });
    };

    const removeModel = (model) => {
        if (!confirm(`型式「${model}」のオーバーライド設定を全て削除しますか？`)) return;
        const next = { ...(measurementOverrides || {}) };
        delete next[model];
        saveSettings({ measurementOverrides: next });
        if (selectedModel === model) setSelectedModel('');
    };

    const addNewModel = () => {
        const m = newModelInput.trim();
        if (!m) return;
        setSelectedModel(m);
        setNewModelInput('');
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
            <h3 className="text-lg font-bold mb-2 flex items-center gap-2 text-slate-800">
                <Ruler className="w-5 h-5 text-teal-600" /> 型式別 公差・基準値オーバーライド
            </h3>
            <p className="text-xs text-slate-500 mb-4">
                工程テンプレは1本だが、型式によって公差や基準値が変わる場合に使用。<br/>
                空欄 = テンプレのデフォルト値を使用。
                <span className="text-teal-700 font-bold ml-1">既存ロットには影響なし</span>。新規ロット作成時のみ適用されます。
            </p>

            {/* テンプレート & 型式 選択 */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-3 mb-4">
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">対象テンプレート</label>
                    <select
                        value={selectedTemplateId}
                        onChange={e => setSelectedTemplateId(e.target.value)}
                        className="w-full border rounded p-2 text-sm bg-slate-50"
                    >
                        <option value="">-- テンプレート選択 --</option>
                        {[...templates].sort((a, b) => new Intl.Collator('ja').compare(a.name || '', b.name || '')).map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </select>
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">対象型式</label>
                    <div className="flex gap-1">
                        <select
                            value={selectedModel}
                            onChange={e => setSelectedModel(e.target.value)}
                            className="flex-1 border rounded p-2 text-sm bg-slate-50"
                        >
                            <option value="">-- 型式選択 --</option>
                            {knownModels.map(m => <option key={m} value={m}>{m}{measurementOverrides[m] ? ' ●' : ''}</option>)}
                        </select>
                        <input
                            value={newModelInput}
                            onChange={e => setNewModelInput(e.target.value)}
                            placeholder="新規型式"
                            className="w-28 border rounded p-2 text-sm"
                        />
                        <button type="button" onClick={addNewModel} disabled={!newModelInput.trim()} className="bg-teal-500 hover:bg-teal-600 disabled:bg-slate-300 text-white px-3 py-2 rounded text-sm font-bold">追加</button>
                    </div>
                </div>
            </div>

            {/* 編集テーブル */}
            {selectedTemplateId && selectedModel ? (
                measurementSteps.length === 0 ? (
                    <div className="text-sm text-slate-400 py-4 text-center bg-slate-50 rounded">
                        このテンプレートに測定タイプの工程がありません
                    </div>
                ) : (
                    <div className="space-y-3">
                        {measurementSteps.map(step => {
                            const calcs = step.measurementConfig.calculations || [];
                            return (
                                <div key={step.id} className="border rounded-lg overflow-hidden">
                                    <div className="bg-slate-50 px-3 py-2 text-sm font-bold text-slate-700">
                                        工程: {step.title}
                                    </div>
                                    <table className="w-full text-xs">
                                        <thead className="bg-slate-100 text-slate-600">
                                            <tr>
                                                <th className="p-2 text-left font-bold">計算</th>
                                                <th className="p-2 text-right font-bold">基準値</th>
                                                <th className="p-2 text-right font-bold">上限公差(+)</th>
                                                <th className="p-2 text-right font-bold">下限公差(-)</th>
                                                <th className="p-2 text-center font-bold">判定</th>
                                                <th className="p-2 text-center font-bold">テンプレ値</th>
                                            </tr>
                                        </thead>
                                        <tbody className="divide-y divide-slate-100">
                                            {calcs.map(calc => {
                                                const ov = measurementOverrides[selectedModel]?.[step.id]?.[calc.id] || {};
                                                const fmt = v => (v == null || v === '') ? '' : v;
                                                return (
                                                    <tr key={calc.id} className="hover:bg-blue-50/30">
                                                        <td className="p-2 font-bold text-slate-700">{calc.label || calc.id}</td>
                                                        <td className="p-2">
                                                            <input
                                                                type="number" step="any"
                                                                value={fmt(ov.nominal)}
                                                                onChange={e => updateOverride(selectedModel, step.id, calc.id, { nominal: e.target.value === '' ? undefined : Number(e.target.value) })}
                                                                placeholder={calc.nominal != null ? String(calc.nominal) : '(0)'}
                                                                className="w-20 border rounded p-1 text-right font-mono"
                                                            />
                                                        </td>
                                                        <td className="p-2">
                                                            <input
                                                                type="number" step="0.001"
                                                                value={fmt(ov.toleranceUpper)}
                                                                onChange={e => updateOverride(selectedModel, step.id, calc.id, { toleranceUpper: e.target.value === '' ? undefined : Number(e.target.value) })}
                                                                placeholder={String(calc.toleranceUpper ?? '')}
                                                                className="w-20 border rounded p-1 text-right font-mono"
                                                            />
                                                        </td>
                                                        <td className="p-2">
                                                            <input
                                                                type="number" step="0.001"
                                                                value={fmt(ov.toleranceLower)}
                                                                onChange={e => updateOverride(selectedModel, step.id, calc.id, { toleranceLower: e.target.value === '' ? undefined : Number(e.target.value) })}
                                                                placeholder={String(calc.toleranceLower ?? '')}
                                                                className="w-20 border rounded p-1 text-right font-mono"
                                                            />
                                                        </td>
                                                        <td className="p-2 text-center">
                                                            <select
                                                                value={ov.toleranceEnabled === undefined ? 'default' : (ov.toleranceEnabled ? 'on' : 'off')}
                                                                onChange={e => {
                                                                    const v = e.target.value;
                                                                    updateOverride(selectedModel, step.id, calc.id, { toleranceEnabled: v === 'default' ? undefined : (v === 'on') });
                                                                }}
                                                                className="border rounded p-1 text-[11px]"
                                                            >
                                                                <option value="default">デフォルト</option>
                                                                <option value="on">ON (判定する)</option>
                                                                <option value="off">OFF (記録のみ)</option>
                                                            </select>
                                                        </td>
                                                        <td className="p-2 text-center text-slate-400 text-[10px]">
                                                            <div>基: {calc.nominal ?? 0}</div>
                                                            <div>±: {calc.toleranceLower}〜{calc.toleranceUpper}</div>
                                                        </td>
                                                    </tr>
                                                );
                                            })}
                                            {calcs.length === 0 && (
                                                <tr><td colSpan={6} className="p-3 text-center text-slate-400">この工程には計算設定がありません</td></tr>
                                            )}
                                        </tbody>
                                    </table>
                                </div>
                            );
                        })}
                        <div className="flex justify-end pt-2">
                            <button type="button" onClick={() => removeModel(selectedModel)} className="text-xs bg-rose-50 hover:bg-rose-100 text-rose-600 border border-rose-200 px-3 py-1.5 rounded font-bold flex items-center gap-1">
                                <Trash2 className="w-3 h-3" /> 「{selectedModel}」のオーバーライドを全削除
                            </button>
                        </div>
                    </div>
                )
            ) : (
                <div className="text-sm text-slate-400 py-6 text-center bg-slate-50 rounded">
                    テンプレートと型式を選択してください
                </div>
            )}

            {/* 設定済みオーバーライド一覧 */}
            {Object.keys(measurementOverrides || {}).length > 0 && (
                <div className="mt-6 pt-4 border-t">
                    <div className="text-xs font-bold text-slate-500 mb-2">設定済みオーバーライド ({Object.keys(measurementOverrides).length} 型式)</div>
                    <div className="flex flex-wrap gap-2">
                        {Object.entries(measurementOverrides).map(([m, data]) => {
                            const count = Object.values(data).reduce((s, st) => s + Object.keys(st).length, 0);
                            return (
                                <div key={m} className="bg-teal-50 border border-teal-200 rounded px-2 py-1 text-xs flex items-center gap-2">
                                    <span className="font-bold text-teal-800">{m}</span>
                                    <span className="text-teal-600">({count}件)</span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}
        </div>
    );
};

// ===========================
// 品質規格マスタ + 型式マッピングパネル
// ===========================
// 「型式 → 品質規格 → 公差/測定条件」の 2 段構造を実装。
// データ構造:
//   settings.qualityStandards: { [qsId]: { id, standardNo, name, revision, note, templateId,
//                                          measurementOverrides: {[stepId]: {[calcId]: {nominal, toleranceUpper, ...}}},
//                                          measurementConditions: {[stepId]: {params: [{key, value}], note}} } }
//   settings.modelStandardMap: { [model]: qsId }
//
// ロット作成時の優先順位:
//   1) modelStandardMap に型式がマッピングされていれば、その規格を適用
//   2) なければ既存の measurementOverrides[model] (レガシー) を適用
//   3) どちらもなければテンプレートのデフォルト値
// ロットには appliedStandard スナップショットを焼き付けてトレーサビリティを確保。
// ===========================
// 勤務時間マスタ設定パネル
// ===========================
// 始業/定時/残業/休憩時間を会社の実態に合わせて設定。
// 週次/月次の負荷計算 (ProgressOverviewView) で使用される。
const WorkScheduleSettingsPanel = ({ workSchedule, saveSettings, workloadEffectiveWorkers, registeredWorkerCount = 0 }) => {
    const sch = { ...DEFAULT_WORK_SCHEDULE, ...(workSchedule || {}) };
    const computed = computeWorkHours(sch);

    const updateSchedule = (patch) => {
        saveSettings({ workSchedule: { ...sch, ...patch } });
    };

    const updateBreak = (idx, patch) => {
        const next = (sch.breaks || []).map((b, i) => i === idx ? { ...b, ...patch } : b);
        updateSchedule({ breaks: next });
    };
    const addBreak = () => updateSchedule({ breaks: [...(sch.breaks || []), { start: '12:00', end: '12:30', name: '休憩' }] });
    const removeBreak = (idx) => updateSchedule({ breaks: (sch.breaks || []).filter((_, i) => i !== idx) });
    const resetToDefault = () => {
        if (!confirm('勤務時間設定をデフォルトに戻しますか？')) return;
        saveSettings({ workSchedule: { ...DEFAULT_WORK_SCHEDULE } });
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mt-6">
            <div className="flex items-center justify-between mb-2">
                <h3 className="text-lg font-bold flex items-center gap-2 text-slate-800">
                    <Clock className="w-5 h-5 text-blue-600" /> 勤務時間マスタ
                </h3>
                <button type="button" onClick={resetToDefault} className="text-xs bg-slate-100 hover:bg-slate-200 text-slate-600 px-2 py-1 rounded font-bold flex items-center gap-1">
                    <RotateCcw className="w-3 h-3" /> デフォルトに戻す
                </button>
            </div>
            <p className="text-xs text-slate-500 mb-4">
                会社の勤務時間 (始業・定時・残業・休憩) を設定します。週次/月次の負荷計算で使われ、休憩を除いた**実働時間**で人員上限を算出します。
            </p>

            {/* 始業 / 定時 / 残業 */}
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3 mb-4">
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">始業</label>
                    <input type="time" value={sch.dayStart} onChange={e => updateSchedule({ dayStart: e.target.value })} className="w-full border rounded p-2 text-sm font-mono" />
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">定時 (終わり)</label>
                    <input type="time" value={sch.dayEnd} onChange={e => updateSchedule({ dayEnd: e.target.value })} className="w-full border rounded p-2 text-sm font-mono" />
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">残業 開始</label>
                    <input type="time" value={sch.overtimeStart} onChange={e => updateSchedule({ overtimeStart: e.target.value })} className="w-full border rounded p-2 text-sm font-mono" />
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">残業 終わり</label>
                    <input type="time" value={sch.overtimeEnd} onChange={e => updateSchedule({ overtimeEnd: e.target.value })} className="w-full border rounded p-2 text-sm font-mono" />
                </div>
            </div>

            {/* 休憩時間 */}
            <div className="mb-4">
                <div className="flex items-center justify-between mb-1.5">
                    <label className="text-xs font-bold text-slate-600">休憩時間</label>
                    <button type="button" onClick={addBreak} className="text-xs bg-blue-50 hover:bg-blue-100 text-blue-700 px-2 py-1 rounded font-bold flex items-center gap-1"><Plus className="w-3 h-3" /> 休憩追加</button>
                </div>
                <div className="space-y-1.5">
                    {(sch.breaks || []).map((b, i) => (
                        <div key={i} className="flex items-center gap-2 bg-slate-50 p-2 rounded">
                            <input type="time" value={b.start} onChange={e => updateBreak(i, { start: e.target.value })} className="border rounded p-1 text-sm font-mono w-28" />
                            <span className="text-slate-400">〜</span>
                            <input type="time" value={b.end} onChange={e => updateBreak(i, { end: e.target.value })} className="border rounded p-1 text-sm font-mono w-28" />
                            <input value={b.name || ''} onChange={e => updateBreak(i, { name: e.target.value })} placeholder="名称 (例: 昼休憩)" className="flex-1 border rounded p-1 text-sm" />
                            <span className="text-xs text-slate-500 w-16 text-right font-mono">{Math.max(0, timeStrToMinutes(b.end) - timeStrToMinutes(b.start))}分</span>
                            <button type="button" onClick={() => removeBreak(i)} className="text-rose-400 hover:text-rose-600 p-1"><X className="w-4 h-4" /></button>
                        </div>
                    ))}
                    {(sch.breaks || []).length === 0 && <div className="text-xs text-slate-400 text-center py-2">休憩時間が設定されていません</div>}
                </div>
            </div>

            {/* 稼働日 / 想定作業者数 / 残業含めるか */}
            <div className="grid grid-cols-1 sm:grid-cols-4 gap-3 mb-4">
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">稼働日 / 週</label>
                    <input type="number" min="1" max="7" value={sch.daysPerWeek} onChange={e => updateSchedule({ daysPerWeek: Number(e.target.value) })} className="w-full border rounded p-2 text-sm font-mono" />
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1">稼働日 / 月</label>
                    <input type="number" min="1" max="31" value={sch.daysPerMonth} onChange={e => updateSchedule({ daysPerMonth: Number(e.target.value) })} className="w-full border rounded p-2 text-sm font-mono" />
                </div>
                <div>
                    <label className="block text-xs font-bold text-slate-600 mb-1" title="負荷計算で使う実働人数。登録作業者数と異なる場合に上書き">
                        想定作業者数
                        <span className="text-[10px] font-normal text-slate-400 ml-1">(登録 {registeredWorkerCount}人)</span>
                    </label>
                    <div className="flex items-center gap-1">
                        <input
                            type="number" min="0" max="99" step="1"
                            value={workloadEffectiveWorkers ?? ''}
                            placeholder={`登録 ${registeredWorkerCount} 人を使用`}
                            onChange={e => {
                                const v = e.target.value === '' ? null : Math.max(0, parseInt(e.target.value) || 0);
                                saveSettings({ workloadEffectiveWorkers: v });
                            }}
                            className="flex-1 border rounded p-2 text-sm font-mono"
                        />
                        {workloadEffectiveWorkers != null && workloadEffectiveWorkers !== '' && (
                            <button type="button" onClick={() => saveSettings({ workloadEffectiveWorkers: null })} className="text-[10px] text-slate-400 hover:text-rose-600 px-1" title="リセット (登録人数を使用)">
                                <Undo2 className="w-3.5 h-3.5"/>
                            </button>
                        )}
                    </div>
                    <p className="text-[10px] text-slate-400 mt-0.5">負荷バー/必要人数の計算に使用</p>
                </div>
                <div className="flex items-end">
                    <label className="flex items-center gap-2 cursor-pointer p-2 border rounded bg-slate-50 w-full">
                        <input type="checkbox" checked={!!sch.includeOvertimeInCapacity} onChange={e => updateSchedule({ includeOvertimeInCapacity: e.target.checked })} className="w-4 h-4 accent-blue-600" />
                        <span className="text-xs font-bold text-slate-700">負荷計算に残業時間も含める</span>
                    </label>
                </div>
            </div>

            {/* 計算結果サマリー */}
            <div className="bg-blue-50 border border-blue-200 rounded-lg p-3">
                <div className="text-xs font-bold text-blue-800 mb-2">📊 実働時間 (計算結果)</div>
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 text-sm">
                    <div>
                        <div className="text-[10px] text-blue-600 font-bold">1日 (定時内)</div>
                        <div className="text-lg font-mono font-black text-blue-800">{formatHoursMinutes(computed.regularMinutes)}</div>
                        <div className="text-[10px] text-slate-500">{computed.regularHours.toFixed(2)}h</div>
                    </div>
                    <div>
                        <div className="text-[10px] text-blue-600 font-bold">1日 (残業含む)</div>
                        <div className="text-lg font-mono font-black text-blue-800">{formatHoursMinutes(computed.totalMinutes)}</div>
                        <div className="text-[10px] text-slate-500">{computed.totalHours.toFixed(2)}h</div>
                    </div>
                    <div>
                        <div className="text-[10px] text-blue-600 font-bold">週 ({sch.daysPerWeek}日)</div>
                        <div className="text-lg font-mono font-black text-blue-800">{(computed.regularHours * sch.daysPerWeek).toFixed(1)}h</div>
                        <div className="text-[10px] text-slate-500">残業込 {(computed.totalHours * sch.daysPerWeek).toFixed(1)}h</div>
                    </div>
                    <div>
                        <div className="text-[10px] text-blue-600 font-bold">月 ({sch.daysPerMonth}日)</div>
                        <div className="text-lg font-mono font-black text-blue-800">{(computed.regularHours * sch.daysPerMonth).toFixed(1)}h</div>
                        <div className="text-[10px] text-slate-500">残業込 {(computed.totalHours * sch.daysPerMonth).toFixed(1)}h</div>
                    </div>
                </div>
                <div className="text-[10px] text-blue-700 mt-2">
                    {sch.includeOvertimeInCapacity ? '✓ 全体進捗の負荷計算は「残業込み」で計算されます' : '✓ 全体進捗の負荷計算は「定時内のみ」で計算されます'}
                </div>
            </div>
        </div>
    );
};

const QualityStandardsPanel = ({ templates, lots, qualityStandards, modelStandardMap, saveSettings, deleteSettingsFields }) => {
    const [selectedQsId, setSelectedQsId] = useState('');
    const [showCreate, setShowCreate] = useState(false);
    const [newStandardNo, setNewStandardNo] = useState('');
    const [newName, setNewName] = useState('');
    const [newRevision, setNewRevision] = useState('A');
    const [newTemplateId, setNewTemplateId] = useState('');
    const [newModelInput, setNewModelInput] = useState('');
    const [collapsedEntries, setCollapsedEntries] = useState({}); // { entryIdx: true } で折りたたみ
    const [profileStepOpen, setProfileStepOpen] = useState({}); // 工程プロファイルの詳細上書きを開いている step
    const [skelTplId, setSkelTplId] = useState(''); // 新規規格の雛形Excel 用に選んだテンプレ

    const qsList = useMemo(() => Object.values(qualityStandards || {}).sort((a, b) =>
        (a.standardNo || '').localeCompare(b.standardNo || '')), [qualityStandards]);

    const selectedQs = qualityStandards?.[selectedQsId];

    // 規格内のテンプレートエントリ一覧 (新旧フォーマット吸収)
    const templateEntries = useMemo(() => getQsTemplateEntries(selectedQs), [selectedQs]);

    // 利用可能な型式
    const knownModels = useMemo(() => {
        const set = new Set();
        (lots || []).forEach(l => { if (l.model) set.add(l.model); });
        Object.keys(modelStandardMap || {}).forEach(m => set.add(m));
        return Array.from(set).sort();
    }, [lots, modelStandardMap]);

    const createStandard = () => {
        const standardNo = newStandardNo.trim();
        const name = newName.trim();
        if (!standardNo || !name || !newTemplateId) {
            alert('規格番号、名称、対象テンプレートは必須です');
            return;
        }
        const id = 'qs-' + Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
        const now = Date.now();
        const next = { ...(qualityStandards || {}) };
        next[id] = {
            id,
            standardNo,
            name,
            revision: newRevision.trim() || 'A',
            note: '',
            // 新フォーマット: テンプレートエントリ配列
            templates: [{
                templateId: newTemplateId,
                measurementOverrides: {},
                measurementConditions: {},
            }],
            createdAt: now,
            updatedAt: now,
        };
        saveSettings({ qualityStandards: next });
        setSelectedQsId(id);
        setShowCreate(false);
        setNewStandardNo(''); setNewName(''); setNewRevision('A'); setNewTemplateId('');
    };

    const updateQs = (qsId, patch) => {
        const cur = qualityStandards?.[qsId];
        if (!cur) return;
        const next = { ...(qualityStandards || {}) };
        next[qsId] = { ...cur, ...patch, updatedAt: Date.now() };
        saveSettings({ qualityStandards: next });
    };

    // テンプレートエントリ配列を更新 (新フォーマットで保存)
    const writeTemplateEntries = (qsId, newEntries) => {
        updateQs(qsId, { templates: newEntries });
    };

    const addTemplateEntry = () => {
        if (!selectedQs) return;
        const next = [...templateEntries, { templateId: '', measurementOverrides: {}, measurementConditions: {} }];
        writeTemplateEntries(selectedQs.id, next);
    };

    const removeTemplateEntry = (idx) => {
        if (!selectedQs) return;
        const entry = templateEntries[idx];
        const tplName = templates.find(t => t.id === entry?.templateId)?.name || '(未選択)';
        if (templateEntries.length === 1) {
            alert('テンプレートエントリを 0 件にはできません。規格自体を削除する場合は「規格削除」ボタンを使ってください。');
            return;
        }
        if (!confirm(`テンプレート「${tplName}」の規格設定 (公差・測定条件) を削除しますか？\n規格自体・他のテンプレ設定は残ります。`)) return;
        const next = templateEntries.filter((_, i) => i !== idx);
        writeTemplateEntries(selectedQs.id, next);
    };

    const setEntryTemplateId = (idx, newTemplateId) => {
        if (!selectedQs) return;
        // 同じ規格内で重複チェック
        if (newTemplateId && templateEntries.some((e, i) => i !== idx && e.templateId === newTemplateId)) {
            alert('同じテンプレートは規格内で 1 回しか登録できません');
            return;
        }
        const next = [...templateEntries];
        next[idx] = { ...next[idx], templateId: newTemplateId };
        writeTemplateEntries(selectedQs.id, next);
    };

    // Excel取込時の検査日オフセット (K33日からの差分日数。負=前)
    const setEntryDaysBefore = (idx, daysBefore) => {
        if (!selectedQs) return;
        const next = [...templateEntries];
        next[idx] = { ...next[idx], daysBefore: daysBefore };
        writeTemplateEntries(selectedQs.id, next);
    };

    const updateEntryOverrides = (idx, newOverrides) => {
        if (!selectedQs) return;
        const next = [...templateEntries];
        next[idx] = { ...next[idx], measurementOverrides: newOverrides };
        writeTemplateEntries(selectedQs.id, next);
    };

    const updateEntryConditions = (idx, newConditions) => {
        if (!selectedQs) return;
        const next = [...templateEntries];
        next[idx] = { ...next[idx], measurementConditions: newConditions };
        writeTemplateEntries(selectedQs.id, next);
    };

    // 初期値プリセット (ブロックゲージ組合せなど) を保存
    //   defaultValues[stepId][inputId] = 値
    const updateEntryDefaultValues = (idx, newDefaults) => {
        if (!selectedQs) return;
        const next = [...templateEntries];
        next[idx] = { ...next[idx], defaultValues: newDefaults };
        writeTemplateEntries(selectedQs.id, next);
    };

    // 確認チェック項目の上書き (型式群ごとに項目を追加・削除できる)
    //   checklistItemsByStep[stepId] = [{ id, label, required }, ...]
    //   - 未設定 (undefined) → テンプレ標準の checklistItems を使用
    //   - 設定済 → このQSの専用リストで上書き (テンプレ標準は無視)
    const updateEntryChecklistItems = (idx, stepId, newItems) => {
        if (!selectedQs) return;
        const allItems = { ...(templateEntries[idx]?.checklistItemsByStep || {}) };
        if (newItems == null) {
            delete allItems[stepId];  // null/undefined で「テンプレ標準を使う」に戻す
        } else {
            allItems[stepId] = newItems;
        }
        const next = [...templateEntries];
        next[idx] = { ...next[idx], checklistItemsByStep: allItems };
        writeTemplateEntries(selectedQs.id, next);
    };

    // 型式別 工程プロファイル: { [stepId]: { enabled?, description?, pdfData?, images?, targetTime? } }
    //   enabled=false → ロット作成時に該当なしで事前スキップ。undefined/空 は除去 (Firestore は undefined 不可)。
    const updateStepProfile = (idx, stepId, patch) => {
        if (!selectedQs) return;
        const cur = { ...(templateEntries[idx]?.stepProfile || {}) };
        const merged = { ...(cur[stepId] || {}), ...patch };
        Object.keys(merged).forEach(k => { if (merged[k] === undefined || merged[k] === null) delete merged[k]; });
        if (Object.keys(merged).length === 0) delete cur[stepId]; else cur[stepId] = merged;
        const next = [...templateEntries];
        next[idx] = { ...next[idx], stepProfile: cur };
        writeTemplateEntries(selectedQs.id, next);
    };
    // 他の品質規格 (同じテンプレ) から工程プロファイルを丸ごとコピー (セミクロ→フルクロの差分編集を楽に)
    const copyStepProfileFrom = (idx, fromQsId) => {
        if (!selectedQs) return;
        const fromQs = qualityStandards?.[fromQsId];
        const myTplId = templateEntries[idx]?.templateId;
        const fromRaw = (fromQs?.templates && fromQs.templates.length > 0) ? fromQs.templates : (fromQs?.templateId ? [fromQs] : []);
        const fromEntry = fromRaw.find(e => e.templateId === myTplId) || fromRaw.find(e => !e.templateId) || fromRaw[0];
        if (!fromEntry || !fromEntry.stepProfile || Object.keys(fromEntry.stepProfile).length === 0) { alert('コピー元にこのテンプレの工程プロファイルがありません'); return; }
        if (!confirm('現在の工程プロファイルをコピー元で上書きします。よろしいですか？')) return;
        const next = [...templateEntries];
        next[idx] = { ...next[idx], stepProfile: { ...fromEntry.stepProfile } };
        writeTemplateEntries(selectedQs.id, next);
    };

    const deleteQs = async (qsId) => {
        const qs = qualityStandards?.[qsId];
        if (!qs) return;
        const usedModels = Object.entries(modelStandardMap || {}).filter(([, v]) => v === qsId).map(([k]) => k);
        const msg = usedModels.length > 0
            ? `規格「${qs.standardNo} ${qs.name}」を削除します。\n適用中の型式 (${usedModels.length}件): ${usedModels.join(', ')}\nの紐付けも解除されます。\n\n既存ロットは焼き付け済みなので影響ありません。続行しますか？`
            : `規格「${qs.standardNo} ${qs.name}」を削除しますか？`;
        if (!confirm(msg)) return;
        // 規格本体 + 紐付いている型式マッピングを Firestore から完全削除
        // (merge: true の setDoc では sub-key を omit しても削除されないため deleteField を使う)
        const paths = [
            `qualityStandards.${qsId}`,
            ...usedModels.map(m => `modelStandardMap.${m}`),
        ];
        if (typeof deleteSettingsFields === 'function') {
            await deleteSettingsFields(paths);
        } else {
            // フォールバック (deleteSettingsFields が無い古い環境用)
            const nextQs = { ...(qualityStandards || {}) };
            delete nextQs[qsId];
            const nextMap = { ...(modelStandardMap || {}) };
            usedModels.forEach(m => delete nextMap[m]);
            await saveSettings({ qualityStandards: nextQs, modelStandardMap: nextMap });
        }
        if (selectedQsId === qsId) setSelectedQsId('');
    };

    // 公差オーバーライドの更新 (テンプレートエントリ単位)
    const updateOverride = (entryIdx, stepId, calcId, patch) => {
        const entry = templateEntries[entryIdx];
        if (!entry) return;
        const overrides = { ...(entry.measurementOverrides || {}) };
        overrides[stepId] = { ...(overrides[stepId] || {}) };
        const cur = overrides[stepId][calcId] || {};
        const merged = { ...cur, ...patch };
        const isEmpty = (merged.nominal === undefined || merged.nominal === null || merged.nominal === '')
            && (merged.toleranceUpper === undefined || merged.toleranceUpper === '')
            && (merged.toleranceLower === undefined || merged.toleranceLower === '')
            && (merged.toleranceEnabled === undefined);
        if (isEmpty) {
            delete overrides[stepId][calcId];
            if (Object.keys(overrides[stepId]).length === 0) delete overrides[stepId];
        } else {
            overrides[stepId][calcId] = merged;
        }
        updateEntryOverrides(entryIdx, overrides);
    };

    // 測定条件の更新 (テンプレートエントリ単位)
    const updateCondition = (entryIdx, stepId, patch) => {
        const entry = templateEntries[entryIdx];
        if (!entry) return;
        const conditions = { ...(entry.measurementConditions || {}) };
        const cur = conditions[stepId] || { params: [], note: '' };
        conditions[stepId] = { ...cur, ...patch };
        updateEntryConditions(entryIdx, conditions);
    };

    const addConditionParam = (entryIdx, stepId) => {
        const entry = templateEntries[entryIdx];
        const cur = entry?.measurementConditions?.[stepId] || { params: [], note: '' };
        updateCondition(entryIdx, stepId, { params: [...(cur.params || []), { key: '', value: '' }] });
    };

    const updateConditionParam = (entryIdx, stepId, paramIdx, patch) => {
        const entry = templateEntries[entryIdx];
        const cur = entry?.measurementConditions?.[stepId] || { params: [], note: '' };
        const params = [...(cur.params || [])];
        params[paramIdx] = { ...params[paramIdx], ...patch };
        updateCondition(entryIdx, stepId, { params });
    };

    const removeConditionParam = (entryIdx, stepId, paramIdx) => {
        const entry = templateEntries[entryIdx];
        const cur = entry?.measurementConditions?.[stepId] || { params: [], note: '' };
        const params = (cur.params || []).filter((_, i) => i !== paramIdx);
        updateCondition(entryIdx, stepId, { params });
    };

    const setModelMapping = async (model, qsId) => {
        if (qsId) {
            // 追加・上書き: 通常の merge 更新で OK
            await saveSettings({ modelStandardMap: { ...(modelStandardMap || {}), [model]: qsId } });
        } else if (typeof deleteSettingsFields === 'function') {
            // 削除: deleteField を使わないと Firestore から実際に消えない
            await deleteSettingsFields([`modelStandardMap.${model}`]);
        } else {
            const next = { ...(modelStandardMap || {}) };
            delete next[model];
            await saveSettings({ modelStandardMap: next });
        }
    };

    // === 品質規格マスタ Excel往復 (全項目: 規格一覧/公差/測定条件/初期値/工程設定/チェック項目) ===
    const QS_CHK = 10;
    const qsCellText = (cell) => { const v = cell == null ? null : cell.value; if (v == null) return ''; if (typeof v === 'object') { if (v.text != null) return String(v.text); if (v.result != null) return String(v.result); if (Array.isArray(v.richText)) return v.richText.map(t => t.text).join(''); if (v.hyperlink) return String(v.text || v.hyperlink); return ''; } return String(v); };
    const qsNum = (s) => { const t = String(s == null ? '' : s).trim().replace(/[^0-9.\-]/g, ''); if (t === '' || t === '-') return undefined; const n = Number(t); return Number.isFinite(n) ? n : undefined; };
    const qsBool = (raw, dflt) => { const s = String(raw == null ? '' : raw).trim(); if (/^(はい|true|1|有効|○|yes|on)$/i.test(s)) return true; if (/^(いいえ|false|0|無効|×|no|off)$/i.test(s)) return false; return dflt; };
    const qsBuildWorkbook = async (ExcelJS, qsList) => {
        const wb = new ExcelJS.Workbook();
        const thin = { style: 'thin', color: { argb: 'FF000000' } };
        const bd = { top: thin, bottom: thin, left: thin, right: thin };
        const head = (row) => row.eachCell(c => { c.font = { bold: true, color: { argb: 'FFFFFFFF' } }; c.fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FF4F46E5' } }; c.border = bd; c.alignment = { vertical: 'middle', horizontal: 'center', wrapText: true }; });
        const body = (row) => row.eachCell(c => { c.border = bd; c.alignment = { vertical: 'middle', wrapText: true }; });
        const modelsByQs = {}; Object.entries(modelStandardMap || {}).forEach(([m, qid]) => { (modelsByQs[qid] = modelsByQs[qid] || []).push(m); });
        const tplById = {}; (templates || []).forEach(t => { tplById[t.id] = t; });
        const ws1 = wb.addWorksheet('規格一覧'); head(ws1.addRow(['規格ID', '規格No', '名称', '改訂', 'メモ', '対象型式(カンマ区切り)']));
        [16, 16, 24, 8, 30, 40].forEach((w, i) => { ws1.getColumn(i + 1).width = w; });
        const ws2 = wb.addWorksheet('公差・規格値'); head(ws2.addRow(['規格ID', '規格No', 'テンプレID', 'テンプレ名', '検査日オフセット', '工程ID', '工程名', '計算ID', '測定項目', '単位(参考)', '基準値', '公差上限', '公差下限', '判定有効']));
        [16, 14, 14, 20, 12, 14, 20, 14, 18, 10, 12, 12, 12, 10].forEach((w, i) => { ws2.getColumn(i + 1).width = w; });
        const ws3 = wb.addWorksheet('測定条件'); head(ws3.addRow(['規格ID', '規格No', 'テンプレID', 'テンプレ名', '工程ID', '工程名', '条件キー', '値', 'メモ']));
        [16, 14, 14, 20, 14, 20, 20, 20, 30].forEach((w, i) => { ws3.getColumn(i + 1).width = w; });
        const ws4 = wb.addWorksheet('初期値'); head(ws4.addRow(['規格ID', '規格No', 'テンプレID', 'テンプレ名', '工程ID', '工程名', '入力ID', '入力名', '初期値']));
        [16, 14, 14, 20, 14, 20, 16, 20, 14].forEach((w, i) => { ws4.getColumn(i + 1).width = w; });
        const ws5 = wb.addWorksheet('工程設定'); head(ws5.addRow(['規格ID', '規格No', 'テンプレID', 'テンプレ名', '工程ID', '工程名', '該当あり(はい/いいえ)', '説明上書き', '目標時間(秒)', 'PDF(参考)', '画像枚数(参考)']));
        [16, 14, 14, 20, 14, 20, 18, 36, 12, 10, 12].forEach((w, i) => { ws5.getColumn(i + 1).width = w; });
        const chkHdr = ['規格ID', '規格No', 'テンプレID', 'テンプレ名', '工程ID', '工程名', 'テンプレ標準(参考)', ...Array.from({ length: QS_CHK }, (_, i) => `チェック${i + 1}`)];
        const ws6 = wb.addWorksheet('チェック項目'); head(ws6.addRow(chkHdr));
        [16, 14, 14, 20, 14, 20, 30, ...Array(QS_CHK).fill(16)].forEach((w, i) => { ws6.getColumn(i + 1).width = w; });
        qsList.forEach(qs => {
            body(ws1.addRow([qs.id || '', qs.standardNo || '', qs.name || '', qs.revision || '', qs.note || '', (modelsByQs[qs.id] || []).join(', ')]));
            getQsTemplateEntries(qs).forEach(entry => {
                const tpl = tplById[entry.templateId]; const tplName = tpl ? (tpl.name || '') : '(テンプレ未登録)';
                const steps = (tpl && tpl.steps) ? tpl.steps : [];
                const ov = entry.measurementOverrides || {}, conds = entry.measurementConditions || {}, defs = entry.defaultValues || {}, prof = entry.stepProfile || {}, chk = entry.checklistItemsByStep || {};
                steps.forEach(s => {
                    const isM = s.type === 'measurement' && s.measurementConfig; const cfg = s.measurementConfig || {};
                    if (isM) (cfg.calculations || []).forEach(c => {
                        const o = (ov[s.id] && ov[s.id][c.id]) || {};
                        const nominal = o.nominal != null ? o.nominal : (c.nominal != null ? c.nominal : '');
                        const tu = o.toleranceUpper != null ? o.toleranceUpper : (c.toleranceUpper != null ? c.toleranceUpper : '');
                        const tl = o.toleranceLower != null ? o.toleranceLower : (c.toleranceLower != null ? c.toleranceLower : '');
                        const en = o.toleranceEnabled != null ? o.toleranceEnabled : c.toleranceEnabled;
                        body(ws2.addRow([qs.id || '', qs.standardNo || '', entry.templateId || '', tplName, (entry.daysBefore != null ? entry.daysBefore : ''), s.id || '', s.title || '', c.id || '', c.label || '', c.unit || '', nominal, tu, tl, (en === false ? 'いいえ' : (en === true ? 'はい' : ''))]));
                    });
                    if (isM) { const cd = conds[s.id] || { params: [], note: '' }; const ps = (cd.params && cd.params.length) ? cd.params : [{ key: '', value: '' }]; ps.forEach((p, i) => body(ws3.addRow([qs.id || '', qs.standardNo || '', entry.templateId || '', tplName, s.id || '', s.title || '', p.key || '', p.value || '', (i === 0 ? (cd.note || '') : '')]))); }
                    if (isM) (cfg.inputs || []).forEach(inp => { const dv = defs[s.id] && defs[s.id][inp.id]; body(ws4.addRow([qs.id || '', qs.standardNo || '', entry.templateId || '', tplName, s.id || '', s.title || '', inp.id || '', inp.label || inp.id || '', (dv != null ? dv : '')])); });
                    const pf = prof[s.id] || {}; body(ws5.addRow([qs.id || '', qs.standardNo || '', entry.templateId || '', tplName, s.id || '', s.title || '', (pf.enabled === false ? 'いいえ' : (pf.enabled === true ? 'はい' : '')), pf.description || '', (pf.targetTime != null ? pf.targetTime : ''), (pf.pdfData ? 'あり' : ''), (Array.isArray(pf.images) ? pf.images.length : 0)]));
                    const tplChk = Array.isArray(s.checklistItems) ? s.checklistItems : []; const custom = chk[s.id]; const items = Array.isArray(custom) ? custom : [];
                    const chkRow = [qs.id || '', qs.standardNo || '', entry.templateId || '', tplName, s.id || '', s.title || '', tplChk.map(it => it.label || '').filter(Boolean).join(' / ')];
                    for (let i = 0; i < QS_CHK; i++) { const it = items[i]; chkRow.push(it ? ((it.required === false ? '' : '★') + (it.label || '')) : ''); }
                    body(ws6.addRow(chkRow));
                });
            });
        });
        return wb;
    };
    const qsDownloadBlob = async (wb, filename) => { const buf = await wb.xlsx.writeBuffer(); const blob = new Blob([buf], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' }); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = filename; a.click(); };
    const qsExcelDownload = async () => {
        try {
            const ExcelJS = await loadExcelJS();
            const qsAll = Object.values(qualityStandards || {}).sort((a, b) => (a.standardNo || '').localeCompare(b.standardNo || '', 'ja'));
            const wb = await qsBuildWorkbook(ExcelJS, qsAll);
            await qsDownloadBlob(wb, '品質規格マスタ.xlsx');
        } catch (err) { console.error(err); alert('品質規格Excelの生成に失敗しました: ' + (err && err.message || err)); }
    };
    const qsSkeletonDownload = async () => {
        if (!skelTplId) { alert('雛形にするテンプレートを選んでください'); return; }
        try {
            const ExcelJS = await loadExcelJS();
            const tpl = (templates || []).find(t => t.id === skelTplId);
            const virt = { id: 'qs-' + generateId(), standardNo: '', name: '', revision: 'A', note: '', templates: [{ templateId: skelTplId, measurementOverrides: {}, measurementConditions: {} }] };
            const wb = await qsBuildWorkbook(ExcelJS, [virt]);
            await qsDownloadBlob(wb, `品質規格_雛形_${tpl ? tpl.name : 'template'}.xlsx`);
        } catch (err) { console.error(err); alert('雛形の生成に失敗しました: ' + (err && err.message || err)); }
    };
    const qsExcelImport = async (e) => {
        const file = e.target.files && e.target.files[0];
        if (!file) return;
        try {
            const ExcelJS = await loadExcelJS();
            const wb = new ExcelJS.Workbook(); await wb.xlsx.load(await file.arrayBuffer());
            const ws1 = wb.getWorksheet('規格一覧'), ws2 = wb.getWorksheet('公差・規格値'), ws3 = wb.getWorksheet('測定条件'), ws4 = wb.getWorksheet('初期値'), ws5 = wb.getWorksheet('工程設定'), ws6 = wb.getWorksheet('チェック項目');
            const T = qsCellText; const keyOf = (id, no) => id ? ('ID::' + id) : ('NO::' + no);
            const ensure = (m, k, def) => { if (!m.has(k)) m.set(k, def()); return m.get(k); };
            const headerQs = new Map();
            if (ws1) ws1.eachRow((row, idx) => { if (idx < 2) return; const id = T(row.getCell(1)).trim(), no = T(row.getCell(2)).trim(), name = T(row.getCell(3)).trim(); if (!id && !no) return; const models = T(row.getCell(6)).split(/[,、\n]+/).map(x => x.trim()).filter(Boolean); headerQs.set(keyOf(id, no), { id: id || '', standardNo: no, name, revision: T(row.getCell(4)).trim(), note: T(row.getCell(5)), models }); });
            const _qtplById = {}; (templates || []).forEach(t => { _qtplById[t.id] = t; });
            const tolByQs = new Map();
            if (ws2) ws2.eachRow((row, idx) => { if (idx < 2) return; const id = T(row.getCell(1)).trim(), no = T(row.getCell(2)).trim(), tplId = T(row.getCell(3)).trim(), stepId = T(row.getCell(6)).trim(), calcId = T(row.getCell(8)).trim(); if ((!id && !no) || !stepId || !calcId) return; const rec = ensure(ensure(tolByQs, keyOf(id, no), () => new Map()), tplId, () => ({ daysBefore: undefined, ov: {} })); const db = qsNum(T(row.getCell(5))); if (db !== undefined && rec.daysBefore === undefined) rec.daysBefore = db; const nom = qsNum(T(row.getCell(11))), tu = qsNum(T(row.getCell(12))), tl = qsNum(T(row.getCell(13))); const eb = qsBool(T(row.getCell(14)), undefined); const _st = _qtplById[tplId] && (_qtplById[tplId].steps || []).find(x => x.id === stepId); const _c = _st && _st.measurementConfig && (_st.measurementConfig.calculations || []).find(x => x.id === calcId); const dN = qsNum(_c && _c.nominal), dU = qsNum(_c && _c.toleranceUpper), dL = qsNum(_c && _c.toleranceLower), dE = _c ? _c.toleranceEnabled : undefined; const cell = {}; if (nom !== undefined && nom !== dN) cell.nominal = nom; if (tu !== undefined && tu !== dU) cell.toleranceUpper = tu; if (tl !== undefined && tl !== dL) cell.toleranceLower = tl; if (eb !== undefined && eb !== dE) cell.toleranceEnabled = eb; if (Object.keys(cell).length) (rec.ov[stepId] = rec.ov[stepId] || {})[calcId] = cell; });
            const condByQs = new Map();
            if (ws3) ws3.eachRow((row, idx) => { if (idx < 2) return; const id = T(row.getCell(1)).trim(), no = T(row.getCell(2)).trim(), tplId = T(row.getCell(3)).trim(), stepId = T(row.getCell(5)).trim(); if ((!id && !no) || !stepId) return; const rec = ensure(ensure(condByQs, keyOf(id, no), () => new Map()), tplId, () => ({})); const st = rec[stepId] || (rec[stepId] = { params: [], note: '' }); const k = T(row.getCell(7)).trim(), v = T(row.getCell(8)), memo = T(row.getCell(9)); if (k) st.params.push({ key: k, value: v }); if (memo && !st.note) st.note = memo; });
            const defByQs = new Map();
            if (ws4) ws4.eachRow((row, idx) => { if (idx < 2) return; const id = T(row.getCell(1)).trim(), no = T(row.getCell(2)).trim(), tplId = T(row.getCell(3)).trim(), stepId = T(row.getCell(5)).trim(), inpId = T(row.getCell(7)).trim(); if ((!id && !no) || !stepId || !inpId) return; const rec = ensure(ensure(defByQs, keyOf(id, no), () => new Map()), tplId, () => ({})); const val = T(row.getCell(9)); if (String(val).trim() !== '') (rec[stepId] = rec[stepId] || {})[inpId] = val; });
            const profByQs = new Map();
            if (ws5) ws5.eachRow((row, idx) => { if (idx < 2) return; const id = T(row.getCell(1)).trim(), no = T(row.getCell(2)).trim(), tplId = T(row.getCell(3)).trim(), stepId = T(row.getCell(5)).trim(); if ((!id && !no) || !stepId) return; const rec = ensure(ensure(profByQs, keyOf(id, no), () => new Map()), tplId, () => ({})); const p = {}; const enb = qsBool(T(row.getCell(7)), undefined); if (enb !== undefined) p.enabled = enb; const desc = T(row.getCell(8)); if (String(desc).trim() !== '') p.description = desc; const tt = qsNum(T(row.getCell(9))); if (tt !== undefined) p.targetTime = tt; rec[stepId] = p; });
            const chkByQs = new Map();
            if (ws6) ws6.eachRow((row, idx) => { if (idx < 2) return; const id = T(row.getCell(1)).trim(), no = T(row.getCell(2)).trim(), tplId = T(row.getCell(3)).trim(), stepId = T(row.getCell(5)).trim(); if ((!id && !no) || !stepId) return; const items = []; for (let i = 0; i < QS_CHK; i++) { const raw = T(row.getCell(8 + i)).trim(); if (raw) { const required = /^[★*]/.test(raw); items.push({ label: raw.replace(/^[★*]\s*/, ''), required }); } } const rec = ensure(ensure(chkByQs, keyOf(id, no), () => new Map()), tplId, () => ({})); rec[stepId] = items; });
            const allKeys = new Set([...headerQs.keys(), ...tolByQs.keys(), ...condByQs.keys(), ...defByQs.keys(), ...profByQs.keys(), ...chkByQs.keys()]);
            if (!allKeys.size) { alert('有効なデータが見つかりませんでした（各シートの2行目以降を確認）'); e.target.value = ''; return; }
            const nextQS = { ...(qualityStandards || {}) }; const nextMap = { ...(modelStandardMap || {}) }; let created = 0, updated = 0; const removedModels = new Set();
            allKeys.forEach(key => {
                const hdr = headerQs.get(key); let qsId, existing;
                if (key.startsWith('ID::')) { qsId = key.slice(4); existing = qualityStandards && qualityStandards[qsId]; } else { qsId = 'qs-' + generateId(); existing = null; }
                const base = existing ? { ...existing } : { id: qsId, standardNo: (hdr && hdr.standardNo) || '', name: (hdr && hdr.name) || '', revision: 'A', note: '', createdAt: Date.now() };
                if (hdr) { if (hdr.standardNo) base.standardNo = hdr.standardNo; if (hdr.name) base.name = hdr.name; if (hdr.revision) base.revision = hdr.revision; if (hdr.note != null) base.note = hdr.note; }
                base.id = qsId;
                const entryByTpl = new Map();
                getQsTemplateEntries(existing).forEach(en => entryByTpl.set(en.templateId || '', { ...en }));
                const tplSet = new Set();
                [tolByQs, condByQs, defByQs, profByQs, chkByQs].forEach(m => { const bt = m.get(key); if (bt) bt.forEach((_, tpl) => tplSet.add(tpl)); });
                tplSet.forEach(tpl => { if (!entryByTpl.has(tpl)) entryByTpl.set(tpl, { templateId: tpl, measurementOverrides: {}, measurementConditions: {} }); });
                entryByTpl.forEach((en, tpl) => {
                    const tolR = tolByQs.get(key) && tolByQs.get(key).get(tpl);
                    if (tolR) { en.measurementOverrides = tolR.ov; if (tolR.daysBefore !== undefined) en.daysBefore = tolR.daysBefore; }
                    if (ws3 && condByQs.get(key) && condByQs.get(key).has(tpl)) { const c = condByQs.get(key).get(tpl); const out = {}; Object.entries(c).forEach(([sid, v]) => { if ((v.params && v.params.length) || v.note) out[sid] = { params: v.params || [], note: v.note || '' }; }); en.measurementConditions = out; }
                    if (ws4 && defByQs.get(key) && defByQs.get(key).has(tpl)) { en.defaultValues = defByQs.get(key).get(tpl); }
                    if (ws6 && chkByQs.get(key) && chkByQs.get(key).has(tpl)) { const cm = chkByQs.get(key).get(tpl); const exChk = en.checklistItemsByStep || {}; const out = {}; Object.entries(cm).forEach(([sid, its]) => { if (its.length) out[sid] = its.map((it, i) => ({ id: (exChk[sid] && exChk[sid][i] && exChk[sid][i].id) || ('chk_' + generateId()), label: it.label, required: !!it.required })); }); en.checklistItemsByStep = out; }
                    if (ws5 && profByQs.get(key) && profByQs.get(key).has(tpl)) { const pm = profByQs.get(key).get(tpl); const exProf = en.stepProfile || {}; const out = { ...exProf }; Object.entries(pm).forEach(([sid, p]) => { const cur = { ...(exProf[sid] || {}) }; if (p.enabled !== undefined) cur.enabled = p.enabled; else delete cur.enabled; if (p.description !== undefined) cur.description = p.description; else delete cur.description; if (p.targetTime !== undefined) cur.targetTime = p.targetTime; else delete cur.targetTime; if (Object.keys(cur).length) out[sid] = cur; else delete out[sid]; }); en.stepProfile = out; }
                });
                base.templates = Array.from(entryByTpl.values());
                delete base.templateId; delete base.measurementOverrides; delete base.measurementConditions;
                base.updatedAt = Date.now(); nextQS[qsId] = base;
                if (hdr) { const wanted = new Set(hdr.models); hdr.models.forEach(m => { nextMap[m] = qsId; removedModels.delete(m); }); Object.keys(nextMap).forEach(m => { if (nextMap[m] === qsId && !wanted.has(m)) { delete nextMap[m]; removedModels.add(m); } }); }
                if (existing) updated++; else created++;
            });
            if (!window.confirm(`品質規格マスタを反映します。\n新規規格: ${created}件 / 更新: ${updated}件\n・各シート(公差/測定条件/初期値/工程設定/チェック項目)の内容で反映\n・公差はテンプレ既定と違う値にした項目のみ固定(既定と同じ/空欄=継承) / PDF・写真は保持\n・アップロードしたブックに無いシートは変更しません（Excelに無い規格も削除しません）\nよろしいですか？`)) { e.target.value = ''; return; }
            await saveSettings({ qualityStandards: nextQS, modelStandardMap: nextMap });
            const _delModels = [...removedModels].filter(m => !(m in nextMap));
            if (_delModels.length && typeof deleteSettingsFields === 'function') await deleteSettingsFields(_delModels.map(m => `modelStandardMap.${m}`));
            alert(`反映しました（新規${created}件・更新${updated}件）`);
        } catch (err) { console.error(err); alert('品質規格の取込に失敗しました: ' + (err && err.message || err)); }
        e.target.value = '';
    };

    return (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 mt-6">
            <h3 className="text-lg font-bold mb-2 flex items-center gap-2 text-slate-800">
                <ClipboardCheck className="w-5 h-5 text-indigo-600" /> 品質規格マスタ
                <span className="text-[10px] font-normal text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded">推奨</span>
            </h3>
            <p className="text-xs text-slate-500 mb-4">
                品質規格 (QS) = <span className="font-bold">公差・基準値 + 測定条件 + 対象テンプレート群 + Excel取込時の検査日オフセット</span> をひとまとめにしたマスタ。<br/>
                1 つの規格に<span className="font-bold text-indigo-700">複数のテンプレートを順番に紐付け</span>できます (例: 中間分割 → 一般傾斜 → 回転検査)。<br/>
                1 つの規格を複数型式で共有できます (例: <span className="font-mono bg-amber-100 text-amber-800 px-1 rounded">RTT-441/442/443 → QS-001「RT系 標準仕様」</span>)。<br/>
                <span className="text-indigo-700 font-bold">既存ロットには影響なし</span>。新規ロット作成時に、ロットの工程テンプレートと一致するエントリが適用されます。<br/>
                規格マッピングがある型式は、上の「型式別オーバーライド」より優先されます。
            </p>
            <div className="bg-amber-50 border border-amber-200 rounded p-2 mb-4 text-[11px] text-amber-800">
                💡 <span className="font-bold">規格の名前付けのコツ</span>: 「どんな製品群か」「どんな仕様か」が後で見て分かる名前を。<br/>
                例: <span className="font-mono">「RT系 標準仕様」</span> / <span className="font-mono">「特注パターンA」</span> / <span className="font-mono">「RBS 高精度モデル」</span> / <span className="font-mono">「KIT-22 改定3」</span><br/>
                規格番号は社内番号 (例: <span className="font-mono">QS-001</span>) や 図面番号 / 仕様書番号 をそのまま流用してOK。
            </div>

            {/* Excel往復 (全6シート + 新規雛形) */}
            <div className="bg-indigo-50 border border-indigo-200 rounded-lg p-3 mb-4">
                <div className="flex flex-wrap gap-2 items-center mb-2">
                    <button onClick={qsExcelDownload} className="text-xs flex items-center gap-1 bg-indigo-600 text-white px-3 py-2 rounded border border-indigo-700 hover:bg-indigo-700 font-bold"><FileSpreadsheet className="w-4 h-4"/> Excelダウンロード</button>
                    <label className="text-xs flex items-center gap-1 cursor-pointer bg-white text-indigo-700 px-3 py-2 rounded border border-indigo-300 hover:bg-indigo-100 font-bold"><FileUp className="w-4 h-4"/> Excel取込<input type="file" accept=".xlsx" className="hidden" onChange={qsExcelImport}/></label>
                    <span className="text-[11px] text-indigo-800 font-bold">設定できる全項目を一括編集（6シート）</span>
                </div>
                <div className="flex flex-wrap gap-2 items-center mb-2 border-t border-indigo-200 pt-2">
                    <span className="text-[11px] font-bold text-slate-600">新規規格の雛形:</span>
                    <select value={skelTplId} onChange={e => setSkelTplId(e.target.value)} className="text-xs border rounded p-1 bg-white max-w-[220px]">
                        <option value="">テンプレートを選択…</option>
                        {(templates || []).map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                    </select>
                    <button onClick={qsSkeletonDownload} className="text-xs flex items-center gap-1 bg-white text-indigo-700 px-3 py-1.5 rounded border border-indigo-300 hover:bg-indigo-100 font-bold"><FileSpreadsheet className="w-4 h-4"/> 雛形をダウンロード</button>
                    <span className="text-[10px] text-slate-500">選んだテンプレの全工程・項目が入った空の規格Excelを作成→規格No/名称/対象型式と値を記入→上の「Excel取込」で新規登録（規格IDは変更しない）</span>
                </div>
                <p className="text-[11px] text-slate-600 leading-relaxed">
                    <b>6シート</b>（規格一覧／公差・規格値／測定条件／初期値／工程設定／チェック項目）で品質規格の<b>設定できる全項目</b>をダウンロード→編集→取込で反映。
                    公差は<b>テンプレ既定と違う値にした項目だけ</b>がこの規格の固定値になります（既定と同じ値／空欄＝テンプレ既定を継承＝テンプレ変更が伝播）。チェック項目は先頭<b>★＝必須</b>。<b>PDF・写真はアプリ側を保持</b>。測定項目そのもの（点・計算・図）の新設は<b>工程テンプレート</b>側で。
                    <b className="text-indigo-700">規格ID空欄＝新規規格</b>。ブックに<b>無いシートは変更しません</b>（部分編集OK）。
                </p>
            </div>

            {/* 規格一覧 + 新規作成 */}
            <div className="flex flex-wrap items-start justify-between gap-3 mb-4">
                <div className="flex-1 min-w-[280px]">
                    <label className="block text-xs font-bold text-slate-600 mb-1">編集する規格</label>
                    <select
                        value={selectedQsId}
                        onChange={e => setSelectedQsId(e.target.value)}
                        className="w-full border rounded p-2 text-sm bg-slate-50"
                    >
                        <option value="">-- 規格を選択 --</option>
                        {qsList.map(qs => (
                            <option key={qs.id} value={qs.id}>
                                {qs.standardNo} Rev.{qs.revision} | {qs.name}
                            </option>
                        ))}
                    </select>
                </div>
                <button
                    type="button"
                    onClick={() => setShowCreate(!showCreate)}
                    className="bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-2 rounded text-sm font-bold shadow flex items-center gap-1 mt-5"
                >
                    <Plus className="w-4 h-4" /> 新規規格
                </button>
            </div>

            {/* 新規規格フォーム */}
            {showCreate && (
                <div className="border border-indigo-200 bg-indigo-50/40 rounded-lg p-3 mb-4 space-y-2">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-2">
                        <div>
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5">規格番号 *</label>
                            <input value={newStandardNo} onChange={e => setNewStandardNo(e.target.value)} placeholder="例: QS-12345" className="w-full border rounded p-1.5 text-sm" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5" title="どんな製品群・どんな仕様か分かる名前。型式リストから後で自動連想できます">名称 *</label>
                            <input value={newName} onChange={e => setNewName(e.target.value)} placeholder="例: RT系 標準仕様" className="w-full border rounded p-1.5 text-sm" />
                            <p className="text-[9px] text-slate-400 mt-0.5">
                                記入例: <span className="font-mono">「RT系 標準仕様」「特注パターンA」「RBSシリーズ 高精度」「KIT-22 改定3」</span>
                            </p>
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5">リビジョン</label>
                            <input value={newRevision} onChange={e => setNewRevision(e.target.value)} placeholder="A" className="w-full border rounded p-1.5 text-sm" />
                        </div>
                    </div>
                    <div>
                        <label className="block text-[10px] font-bold text-slate-600 mb-0.5">対象テンプレート *</label>
                        <select value={newTemplateId} onChange={e => setNewTemplateId(e.target.value)} className="w-full border rounded p-1.5 text-sm bg-white">
                            <option value="">-- テンプレートを選択 --</option>
                            {[...templates].sort((a, b) => new Intl.Collator('ja').compare(a.name || '', b.name || '')).map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
                        </select>
                    </div>
                    <div className="flex justify-end gap-2 pt-1">
                        <button type="button" onClick={() => setShowCreate(false)} className="px-3 py-1.5 text-xs font-bold text-slate-600 hover:bg-slate-100 rounded">キャンセル</button>
                        <button type="button" onClick={createStandard} className="px-4 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-bold rounded">作成</button>
                    </div>
                </div>
            )}

            {/* 規格編集本体 */}
            {selectedQs && (
                <div className="space-y-3">
                    {/* メタ情報 */}
                    <div className="bg-slate-50 rounded-lg p-3 grid grid-cols-1 md:grid-cols-4 gap-2">
                        <div>
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5">規格番号</label>
                            <input value={selectedQs.standardNo || ''} onChange={e => updateQs(selectedQs.id, { standardNo: e.target.value })} className="w-full border rounded p-1 text-sm" />
                        </div>
                        <div>
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5">リビジョン</label>
                            <input value={selectedQs.revision || ''} onChange={e => updateQs(selectedQs.id, { revision: e.target.value })} className="w-full border rounded p-1 text-sm" />
                        </div>
                        <div className="md:col-span-2">
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5" title="どんな製品群・どんな仕様か分かる名前">名称 <span className="font-normal text-slate-400">(記入例: RT系 標準仕様 / 特注パターンA / 高精度モデル)</span></label>
                            <input value={selectedQs.name || ''} onChange={e => updateQs(selectedQs.id, { name: e.target.value })} placeholder="例: RT系 標準仕様" className="w-full border rounded p-1 text-sm" />
                        </div>
                        <div className="md:col-span-3 flex items-end">
                            <div className="text-[10px] text-slate-500 leading-tight">
                                <span className="font-bold text-indigo-700">{templateEntries.length}</span> 件のテンプレートが紐付いています。下のセクションで個別に編集できます。
                            </div>
                        </div>
                        <div className="md:col-span-1 flex items-end">
                            <button type="button" onClick={() => deleteQs(selectedQs.id)} className="w-full px-2 py-1 bg-rose-50 hover:bg-rose-100 text-rose-600 border border-rose-200 rounded text-xs font-bold flex items-center justify-center gap-1">
                                <Trash2 className="w-3 h-3" /> 規格削除
                            </button>
                        </div>
                        <div className="md:col-span-4">
                            <label className="block text-[10px] font-bold text-slate-600 mb-0.5">備考</label>
                            <textarea value={selectedQs.note || ''} onChange={e => updateQs(selectedQs.id, { note: e.target.value })} className="w-full border rounded p-1 text-sm" rows={2} placeholder="規格書の出典・改訂理由など" />
                        </div>
                    </div>

                    {/* 型式マッピング (この規格に紐付ける型式) — 名称の直下に配置 */}
                    <div className="border-2 border-amber-100 rounded-lg overflow-hidden">
                        <div className="bg-amber-50 px-3 py-2 text-sm font-bold text-amber-900 flex items-center justify-between">
                            <span className="flex items-center gap-2"><Hash className="w-4 h-4" /> この規格に紐付ける型式</span>
                        </div>
                        <div className="p-3 bg-white">
                            <div className="flex flex-wrap gap-2 mb-3">
                                {Object.entries(modelStandardMap || {}).filter(([, v]) => v === selectedQs.id).map(([m]) => (
                                    <div key={m} className="bg-amber-50 border border-amber-300 rounded-full pl-3 pr-1 py-0.5 text-xs font-bold text-amber-800 flex items-center gap-1">
                                        {m}
                                        <button type="button" onClick={() => setModelMapping(m, '')} className="ml-1 hover:bg-amber-200 rounded-full p-0.5"><X className="w-3 h-3" /></button>
                                    </div>
                                ))}
                                {Object.entries(modelStandardMap || {}).filter(([, v]) => v === selectedQs.id).length === 0 && (
                                    <span className="text-xs text-slate-400">まだ型式が紐付けられていません</span>
                                )}
                            </div>
                            <div className="flex gap-2 items-center">
                                <select onChange={e => { if (e.target.value) { setModelMapping(e.target.value, selectedQs.id); e.target.value = ''; } }} className="flex-1 border rounded p-1.5 text-xs bg-slate-50">
                                    <option value="">-- 既存型式から追加 --</option>
                                    {knownModels.filter(m => modelStandardMap?.[m] !== selectedQs.id).map(m => (
                                        <option key={m} value={m}>
                                            {m}{modelStandardMap?.[m] ? ` (現在: ${qualityStandards[modelStandardMap[m]]?.standardNo || '?'})` : ''}
                                        </option>
                                    ))}
                                </select>
                                <input value={newModelInput} onChange={e => setNewModelInput(e.target.value)} placeholder="新規型式名を入力" className="w-40 border rounded p-1.5 text-xs" />
                                <button type="button" onClick={() => { const m = newModelInput.trim(); if (m) { setModelMapping(m, selectedQs.id); setNewModelInput(''); } }} disabled={!newModelInput.trim()} className="bg-amber-500 hover:bg-amber-600 disabled:bg-slate-300 text-white px-3 py-1.5 rounded text-xs font-bold">追加</button>
                            </div>
                            <p className="text-[10px] text-slate-500 mt-2">既存型式に別規格が割当済みの場合は上書きされます。新規ロット作成時から有効。</p>
                        </div>
                    </div>

                    {/* テンプレートエントリ一覧 (順番に使うテンプレートを並べる) */}
                    <div className="bg-indigo-50/50 border border-indigo-200 rounded-lg p-3">
                        <div className="flex items-center justify-between mb-2">
                            <div className="text-sm font-bold text-indigo-900 flex items-center gap-1.5">
                                <ClipboardList className="w-4 h-4"/> 対象テンプレート ({templateEntries.length} 件)
                                <span className="text-[10px] font-normal text-indigo-600 ml-1">受入→組立→中間→…→最終 のように順に並べられます</span>
                            </div>
                            <button type="button" onClick={addTemplateEntry} className="text-xs bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-1 rounded font-bold flex items-center gap-1">
                                <Plus className="w-3 h-3"/> テンプレート追加
                            </button>
                        </div>
                        {templateEntries.length === 0 && (
                            <div className="text-xs text-slate-400 text-center py-3">「+ テンプレート追加」で対象テンプレートを追加してください</div>
                        )}
                    </div>

                    {/* 各テンプレートエントリのカード */}
                    {templateEntries.map((entry, entryIdx) => {
                        const tpl = templates.find(t => t.id === entry.templateId);
                        // 編集対象 = 測定工程 OR 確認チェック項目を持つ工程 (型式群ごとに上書き可能)
                        const measurementSteps = (tpl?.steps || []).filter(s =>
                            (s.type === 'measurement' && s.measurementConfig) ||
                            (Array.isArray(s.checklistItems) && s.checklistItems.length > 0)
                        );
                        const isCollapsed = !!collapsedEntries[entryIdx];
                        const otherUsed = templateEntries.map((e, i) => i !== entryIdx ? e.templateId : null).filter(Boolean);
                        const stepCount = measurementSteps.length;
                        const overrideCount = Object.values(entry.measurementOverrides || {}).reduce((a, m) => a + Object.keys(m).length, 0);
                        const conditionCount = Object.keys(entry.measurementConditions || {}).filter(k => {
                            const c = entry.measurementConditions[k];
                            return (c?.params || []).length > 0 || c?.note;
                        }).length;
                        const defaultsCount = Object.values(entry.defaultValues || {}).reduce((a, obj) => a + Object.values(obj || {}).filter(v => v !== '' && v != null).length, 0);
                        return (
                            <div key={entryIdx} className="border-2 border-indigo-200 rounded-lg overflow-hidden">
                                {/* エントリヘッダー (折りたたみ可能) */}
                                <div className="bg-indigo-100 px-3 py-2 flex items-center justify-between gap-2">
                                    <button
                                        type="button"
                                        onClick={() => setCollapsedEntries(prev => ({ ...prev, [entryIdx]: !prev[entryIdx] }))}
                                        className="flex items-center gap-2 text-sm font-bold text-indigo-900 hover:text-indigo-700"
                                        title={isCollapsed ? 'クリックで展開' : 'クリックで折りたたみ'}
                                    >
                                        {isCollapsed ? <ChevronRight className="w-4 h-4"/> : <ChevronDown className="w-4 h-4"/>}
                                        <span className="bg-indigo-600 text-white text-[10px] font-bold rounded-full w-5 h-5 flex items-center justify-center shrink-0">{entryIdx + 1}</span>
                                        <span className="truncate">{tpl?.name || '(テンプレート未選択)'}</span>
                                    </button>
                                    <div className="flex items-center gap-2 shrink-0">
                                        <span className="text-[10px] text-indigo-700">工程 {stepCount} / 条件 {conditionCount} / 公差 {overrideCount} / 初期値 {defaultsCount}</span>
                                        {/* Excel取込時の検査日オフセット (K33基準) */}
                                        <div className="flex items-center gap-1 bg-emerald-50 border border-emerald-200 rounded px-1.5 py-0.5" title="Excel取込時、進捗管理表のZ列 (K33検査予定日) からの日数オフセット。負の数 = 何日前、0 = 当日、正の数 = 何日後">
                                            <FileSpreadsheet className="w-3 h-3 text-emerald-600"/>
                                            <span className="text-[10px] text-emerald-700 font-bold">K33</span>
                                            <input
                                                type="number"
                                                value={entry.daysBefore ?? ''}
                                                placeholder="0"
                                                onChange={e => {
                                                    const v = e.target.value === '' ? null : parseInt(e.target.value) || 0;
                                                    setEntryDaysBefore(entryIdx, v);
                                                }}
                                                className="w-12 border rounded p-0.5 text-xs text-center font-mono bg-white"
                                            />
                                            <span className="text-[10px] text-emerald-700">日</span>
                                        </div>
                                        <select
                                            value={entry.templateId || ''}
                                            onChange={e => setEntryTemplateId(entryIdx, e.target.value)}
                                            className="text-xs border rounded p-1 bg-white max-w-[200px]"
                                            title="このエントリに割り当てるテンプレート"
                                        >
                                            <option value="">-- 未選択 --</option>
                                            {templates.filter(t => !otherUsed.includes(t.id) || t.id === entry.templateId).map(t => (
                                                <option key={t.id} value={t.id}>{t.name}</option>
                                            ))}
                                        </select>
                                        <button type="button" onClick={() => removeTemplateEntry(entryIdx)} className="text-rose-600 hover:bg-rose-100 p-1 rounded" title="このテンプレート設定を削除">
                                            <Trash2 className="w-3.5 h-3.5"/>
                                        </button>
                                    </div>
                                </div>

                                {/* エントリ本体 (工程ごとの 条件 + 公差) */}
                                {!isCollapsed && (
                                    <div className="p-3 space-y-3 bg-white">
                                        {!entry.templateId ? (
                                            <div className="text-sm text-slate-400 py-4 text-center bg-slate-50 rounded">
                                                右上のドロップダウンで対象テンプレートを選択してください
                                            </div>
                                        ) : measurementSteps.length === 0 ? (
                                            <div className="text-sm text-slate-400 py-4 text-center bg-slate-50 rounded">
                                                このテンプレートに測定タイプの工程がありません
                                            </div>
                                        ) : (
                                            measurementSteps.map(step => {
                                                const isMeasurement = step.type === 'measurement' && step.measurementConfig;
                                                const calcs = isMeasurement ? (step.measurementConfig.calculations || []) : [];
                                                const condition = entry.measurementConditions?.[step.id] || { params: [], note: '' };
                                                const overrides = entry.measurementOverrides?.[step.id] || {};
                                                // 初期値プリセット (ブロックゲージ組合せなど): defaultValues[step.id][inputId]
                                                const stepDefaults = entry.defaultValues?.[step.id] || {};
                                                const inputsList = isMeasurement ? (step.measurementConfig.inputs || []) : [];
                                                // 確認チェック上書き: undefined = テンプレ標準を使う, 配列 = この規格専用
                                                const tplChecklist = Array.isArray(step.checklistItems) ? step.checklistItems : [];
                                                const customChecklist = entry.checklistItemsByStep?.[step.id];
                                                const hasCustomChecklist = Array.isArray(customChecklist);
                                                const effectiveChecklist = hasCustomChecklist ? customChecklist : tplChecklist;
                                                const updateDefault = (inpId, val) => {
                                                    const allDefaults = { ...(entry.defaultValues || {}) };
                                                    const stepObj = { ...(allDefaults[step.id] || {}) };
                                                    if (val === '' || val === null || val === undefined) {
                                                        delete stepObj[inpId];
                                                    } else {
                                                        stepObj[inpId] = val;
                                                    }
                                                    if (Object.keys(stepObj).length === 0) {
                                                        delete allDefaults[step.id];
                                                    } else {
                                                        allDefaults[step.id] = stepObj;
                                                    }
                                                    updateEntryDefaultValues(entryIdx, allDefaults);
                                                };
                                                const clearStepDefaults = () => {
                                                    const allDefaults = { ...(entry.defaultValues || {}) };
                                                    delete allDefaults[step.id];
                                                    updateEntryDefaultValues(entryIdx, allDefaults);
                                                };
                                                const filledCount = Object.values(stepDefaults).filter(v => v !== '' && v != null).length;
                                                return (
                                                    <div key={step.id} className="border border-indigo-100 rounded-lg overflow-hidden">
                                                        <div className="bg-indigo-50 px-3 py-1.5 text-xs font-bold text-indigo-900 flex items-center gap-2">
                                                            <Ruler className="w-3.5 h-3.5" /> 工程: {step.title}
                                                        </div>
                                                        {/* 測定条件 (HOW) — 測定工程のみ */}
                                                        {isMeasurement && (
                                                        <div className="p-3 bg-white border-b border-slate-100">
                                                            <div className="text-xs font-bold text-slate-600 mb-2 flex items-center gap-1.5">
                                                                <ListChecks className="w-3.5 h-3.5 text-purple-600" /> 測定条件 (HOW)
                                                                <span className="text-[10px] font-normal text-slate-400 ml-1">どう測るか / 段取り条件</span>
                                                            </div>
                                                            <div className="space-y-1.5">
                                                                {(condition.params || []).map((p, idx) => (
                                                                    <div key={idx} className="flex gap-2 items-center">
                                                                        <input value={p.key || ''} onChange={e => updateConditionParam(entryIdx, step.id, idx, { key: e.target.value })} placeholder="項目名 (例: 分割数)" className="flex-1 border rounded p-1 text-xs" />
                                                                        <input value={p.value || ''} onChange={e => updateConditionParam(entryIdx, step.id, idx, { value: e.target.value })} placeholder="値 (例: 8)" className="flex-1 border rounded p-1 text-xs" />
                                                                        <button type="button" onClick={() => removeConditionParam(entryIdx, step.id, idx)} className="text-rose-400 hover:text-rose-600 p-1"><X className="w-3 h-3" /></button>
                                                                    </div>
                                                                ))}
                                                                <button type="button" onClick={() => addConditionParam(entryIdx, step.id)} className="text-xs text-purple-600 hover:text-purple-800 flex items-center gap-1 font-bold">
                                                                    <Plus className="w-3 h-3" /> 条件項目を追加
                                                                </button>
                                                            </div>
                                                            <div className="mt-2">
                                                                <label className="block text-[10px] text-slate-500 mb-0.5">条件メモ (自由記述)</label>
                                                                <textarea value={condition.note || ''} onChange={e => updateCondition(entryIdx, step.id, { note: e.target.value })} className="w-full border rounded p-1.5 text-xs" rows={2} placeholder="例: ホイール45°毎、ウォーム評価あり、温度23°C基準" />
                                                            </div>
                                                        </div>
                                                        )}
                                                        {/* 初期値プリセット (ブロックゲージ組合せなど、型式群で共通の入力初期値) */}
                                                        {isMeasurement && inputsList.length > 0 && (
                                                            <div className="p-3 bg-amber-50/30 border-b border-slate-100">
                                                                <div className="text-xs font-bold text-slate-600 mb-2 flex items-center gap-1.5">
                                                                    <ListChecks className="w-3.5 h-3.5 text-amber-600" /> 初期値プリセット
                                                                    <span className="text-[10px] font-normal text-slate-400 ml-1">ブロックゲージ組合せなど。測定画面で「規格の初期値を入力」ボタンが出ます</span>
                                                                    {filledCount > 0 && (
                                                                        <button type="button" onClick={clearStepDefaults} className="ml-auto text-[10px] text-rose-500 hover:bg-rose-50 px-1.5 py-0.5 rounded font-bold border border-rose-200">
                                                                            <X className="w-2.5 h-2.5 inline mr-0.5"/>全クリア ({filledCount}件)
                                                                        </button>
                                                                    )}
                                                                </div>
                                                                <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 gap-1.5">
                                                                    {inputsList.map(inp => (
                                                                        <div key={inp.id} className="flex flex-col gap-0.5 bg-white border border-amber-200 rounded p-1.5">
                                                                            <span className="text-[9px] font-bold text-slate-500 truncate" title={inp.label}>
                                                                                {inp.label || inp.id}
                                                                            </span>
                                                                            <input
                                                                                type="text"
                                                                                value={stepDefaults[inp.id] ?? ''}
                                                                                onChange={e => updateDefault(inp.id, e.target.value)}
                                                                                placeholder="—"
                                                                                className="w-full border rounded px-1 py-0.5 text-xs font-mono text-right"
                                                                            />
                                                                        </div>
                                                                    ))}
                                                                </div>
                                                            </div>
                                                        )}
                                                        {/* 確認チェック上書き (型式群ごとにカスタマイズ可能) */}
                                                        <div className="p-3 bg-purple-50/30 border-b border-slate-100">
                                                            <div className="text-xs font-bold text-slate-600 mb-2 flex items-center gap-1.5">
                                                                <ListChecks className="w-3.5 h-3.5 text-purple-600" /> 確認チェック
                                                                <span className="text-[10px] font-normal text-slate-400 ml-1">
                                                                    {hasCustomChecklist ? '⚙ この規格専用' : 'テンプレ標準を継承'}
                                                                </span>
                                                                <span className="ml-auto flex items-center gap-1.5">
                                                                    {!hasCustomChecklist ? (
                                                                        <button type="button" onClick={() => updateEntryChecklistItems(entryIdx, step.id, [...tplChecklist])} className="text-[10px] bg-purple-100 hover:bg-purple-200 text-purple-700 px-2 py-0.5 rounded font-bold border border-purple-300">
                                                                            <Pencil className="w-2.5 h-2.5 inline mr-0.5"/>規格用に編集
                                                                        </button>
                                                                    ) : (
                                                                        <button type="button" onClick={() => { if (confirm('この規格専用の確認チェック設定を解除し、テンプレ標準に戻しますか？')) updateEntryChecklistItems(entryIdx, step.id, null); }} className="text-[10px] bg-slate-100 hover:bg-slate-200 text-slate-600 px-2 py-0.5 rounded font-bold border border-slate-300">
                                                                            <Undo2 className="w-2.5 h-2.5 inline mr-0.5"/>テンプレ標準に戻す
                                                                        </button>
                                                                    )}
                                                                </span>
                                                            </div>
                                                            {!hasCustomChecklist ? (
                                                                tplChecklist.length === 0 ? (
                                                                    <div className="text-[11px] text-slate-400 text-center py-2 bg-white rounded border border-dashed border-slate-200">
                                                                        テンプレ側にチェック項目が未設定です。「規格用に編集」で追加できます。
                                                                    </div>
                                                                ) : (
                                                                    <div className="space-y-1">
                                                                        {tplChecklist.map((item, idx) => (
                                                                            <div key={item.id || idx} className="bg-white border border-slate-200 rounded px-2 py-1 text-[11px] flex items-center gap-2">
                                                                                <span className="text-purple-500 font-bold w-4">{idx + 1}.</span>
                                                                                <span className="flex-1 text-slate-700">{item.label || '(無題)'}</span>
                                                                                <span className={`text-[9px] px-1.5 py-0.5 rounded font-bold ${item.required === false ? 'bg-slate-100 text-slate-500' : 'bg-rose-100 text-rose-700'}`}>
                                                                                    {item.required === false ? '任意' : '必須'}
                                                                                </span>
                                                                            </div>
                                                                        ))}
                                                                    </div>
                                                                )
                                                            ) : (
                                                                <div className="space-y-1.5">
                                                                    {customChecklist.map((item, idx) => {
                                                                        const updateItem = (patch) => {
                                                                            const next = [...customChecklist];
                                                                            next[idx] = { ...next[idx], ...patch };
                                                                            updateEntryChecklistItems(entryIdx, step.id, next);
                                                                        };
                                                                        const removeItem = () => {
                                                                            updateEntryChecklistItems(entryIdx, step.id, customChecklist.filter((_, i) => i !== idx));
                                                                        };
                                                                        return (
                                                                            <div key={item.id || idx} className="bg-white border border-purple-200 rounded p-1.5 flex items-center gap-1.5">
                                                                                <span className="text-[10px] font-bold text-purple-500 w-5 text-center">{idx + 1}</span>
                                                                                <input
                                                                                    value={item.label || ''}
                                                                                    onChange={e => updateItem({ label: e.target.value })}
                                                                                    placeholder="例: 色見本との一致を確認"
                                                                                    className="flex-1 border rounded px-2 py-0.5 text-xs"
                                                                                />
                                                                                <label className="flex items-center gap-1 text-[10px] font-bold text-slate-600 cursor-pointer shrink-0" title="チェック必須項目">
                                                                                    <input type="checkbox" checked={item.required !== false} onChange={e => updateItem({ required: e.target.checked })} className="w-3 h-3 accent-purple-600"/>
                                                                                    必須
                                                                                </label>
                                                                                <button type="button" onClick={removeItem} className="text-rose-400 hover:text-rose-600"><X className="w-3.5 h-3.5"/></button>
                                                                            </div>
                                                                        );
                                                                    })}
                                                                    <button
                                                                        type="button"
                                                                        onClick={() => updateEntryChecklistItems(entryIdx, step.id, [...customChecklist, { id: `chk_${Date.now()}_${Math.random().toString(36).slice(2, 5)}`, label: '', required: true }])}
                                                                        className="w-full py-1 bg-purple-100 hover:bg-purple-200 text-purple-700 text-[10px] font-bold rounded border border-purple-300 flex items-center justify-center gap-1"
                                                                    >
                                                                        <Plus className="w-3 h-3"/> 項目追加
                                                                    </button>
                                                                </div>
                                                            )}
                                                        </div>
                                                        {/* 公差・基準値 (WHAT) — 測定工程のみ */}
                                                        {isMeasurement && (
                                                        <div className="p-3 bg-white">
                                                            <div className="text-xs font-bold text-slate-600 mb-2 flex items-center gap-1.5">
                                                                <Target className="w-3.5 h-3.5 text-teal-600" /> 公差・基準値 (WHAT)
                                                                <span className="text-[10px] font-normal text-slate-400 ml-1">合否判定用スペック</span>
                                                            </div>
                                                            {calcs.length === 0 ? (
                                                                <div className="text-xs text-slate-400 py-2 text-center">この工程には計算設定がありません</div>
                                                            ) : (
                                                                <table className="w-full text-xs">
                                                                    <thead className="bg-slate-50 text-slate-600">
                                                                        <tr>
                                                                            <th className="p-1.5 text-left font-bold">計算</th>
                                                                            <th className="p-1.5 text-right font-bold">基準値</th>
                                                                            <th className="p-1.5 text-right font-bold">上限(+)</th>
                                                                            <th className="p-1.5 text-right font-bold">下限(-)</th>
                                                                            <th className="p-1.5 text-center font-bold">判定</th>
                                                                            <th className="p-1.5 text-center font-bold text-[10px]">テンプレ値</th>
                                                                        </tr>
                                                                    </thead>
                                                                    <tbody className="divide-y divide-slate-100">
                                                                        {calcs.map(calc => {
                                                                            const ov = overrides[calc.id] || {};
                                                                            const fmt = v => (v == null || v === '') ? '' : v;
                                                                            return (
                                                                                <tr key={calc.id} className="hover:bg-blue-50/30">
                                                                                    <td className="p-1.5 font-bold text-slate-700">{calc.label || calc.id}</td>
                                                                                    <td className="p-1.5"><input type="number" step="any" value={fmt(ov.nominal)} onChange={e => updateOverride(entryIdx, step.id, calc.id, { nominal: e.target.value === '' ? undefined : Number(e.target.value) })} placeholder={calc.nominal != null ? String(calc.nominal) : '(0)'} className="w-20 border rounded p-1 text-right font-mono text-xs" /></td>
                                                                                    <td className="p-1.5"><input type="number" step="0.001" value={fmt(ov.toleranceUpper)} onChange={e => updateOverride(entryIdx, step.id, calc.id, { toleranceUpper: e.target.value === '' ? undefined : Number(e.target.value) })} placeholder={String(calc.toleranceUpper ?? '')} className="w-20 border rounded p-1 text-right font-mono text-xs" /></td>
                                                                                    <td className="p-1.5"><input type="number" step="0.001" value={fmt(ov.toleranceLower)} onChange={e => updateOverride(entryIdx, step.id, calc.id, { toleranceLower: e.target.value === '' ? undefined : Number(e.target.value) })} placeholder={String(calc.toleranceLower ?? '')} className="w-20 border rounded p-1 text-right font-mono text-xs" /></td>
                                                                                    <td className="p-1.5 text-center">
                                                                                        <select value={ov.toleranceEnabled === undefined ? 'default' : (ov.toleranceEnabled ? 'on' : 'off')} onChange={e => { const v = e.target.value; updateOverride(entryIdx, step.id, calc.id, { toleranceEnabled: v === 'default' ? undefined : (v === 'on') }); }} className="border rounded p-1 text-[10px]">
                                                                                            <option value="default">デフォルト</option>
                                                                                            <option value="on">ON</option>
                                                                                            <option value="off">OFF</option>
                                                                                        </select>
                                                                                    </td>
                                                                                    <td className="p-1.5 text-center text-slate-400 text-[10px]"><div>基: {calc.nominal ?? 0}</div><div>±: {calc.toleranceLower}〜{calc.toleranceUpper}</div></td>
                                                                                </tr>
                                                                            );
                                                                        })}
                                                                    </tbody>
                                                                </table>
                                                            )}
                                                        </div>
                                                        )}
                                                    </div>
                                                );
                                            })
                                        )}
                                    </div>
                                )}
                                {/* === 型式別 工程プロファイル: 使う/該当なし + 詳細/PDF/写真/目標時間 の型式別上書き === */}
                                {tpl && (tpl.steps || []).length > 0 && (
                                  <div className="mt-3 border-t-2 border-indigo-100 pt-2">
                                    <div className="flex items-center justify-between mb-1 flex-wrap gap-1">
                                      <div className="text-xs font-black text-indigo-700">🧩 工程プロファイル（この型式群で使う工程）</div>
                                      <select className="text-[11px] border rounded px-1 py-0.5 bg-white" value="" onChange={(e)=>{ if(e.target.value){ copyStepProfileFrom(entryIdx, e.target.value); e.target.value=''; } }}>
                                        <option value="">他の規格からコピー…</option>
                                        {Object.values(qualityStandards||{}).filter(q=>q.id!==selectedQs.id).map(q=> <option key={q.id} value={q.id}>{q.standardNo} {q.name}</option>)}
                                      </select>
                                    </div>
                                    <div className="text-[10px] text-slate-500 mb-1.5">「該当なし」にした工程はこの型式群のロット作成時に自動でスキップ（作業者は検査画面で解除可）。詳細/PDF/写真/目標時間も型式別に上書きできます。</div>
                                    <div className="space-y-1">
                                      {(tpl.steps||[]).map(step => {
                                        const prof = entry.stepProfile?.[step.id] || {};
                                        const enabled = prof.enabled !== false;
                                        const pkey = `${entryIdx}_${step.id}`;
                                        const open = !!profileStepOpen[pkey];
                                        const isAuto = step.executionMode === 'batch' || (step.title||'').includes('自動');
                                        const hasOv = !!(prof.description || prof.pdfData || (prof.images && prof.images.length) || prof.targetTime);
                                        return (
                                          <div key={step.id} className={`rounded border ${enabled ? 'border-slate-200 bg-white' : 'border-slate-300 bg-slate-100'}`}>
                                            <div className="flex items-center gap-2 px-2 py-1">
                                              <button onClick={()=>updateStepProfile(entryIdx, step.id, { enabled: enabled ? false : undefined })}
                                                className={`text-[11px] font-bold px-2 py-0.5 rounded border whitespace-nowrap ${enabled ? 'bg-emerald-600 text-white border-emerald-700' : 'bg-slate-400 text-white border-slate-500'}`}>
                                                {enabled ? '使う' : '該当なし'}
                                              </button>
                                              {isAuto && <span className="text-[9px] bg-purple-100 text-purple-700 px-1 rounded shrink-0">自動</span>}
                                              <span className={`text-xs font-bold flex-1 truncate ${enabled ? 'text-slate-800' : 'text-slate-400 line-through'}`} title={step.title}>{step.title}</span>
                                              {hasOv && <span className="text-[9px] text-indigo-500 shrink-0" title="型式別の上書きあり">●上書</span>}
                                              <button onClick={()=>setProfileStepOpen(p=>({...p, [pkey]: !open}))} className="text-[10px] text-indigo-600 underline shrink-0">{open ? '閉じる' : '詳細'}</button>
                                            </div>
                                            {open && (
                                              <div className="px-2 pb-2 space-y-1.5 border-t border-slate-100 pt-1.5 bg-slate-50">
                                                <div>
                                                  <label className="text-[10px] text-slate-500">詳細・注意事項（この型式用に上書き / 空=テンプレ標準）</label>
                                                  <textarea value={prof.description || ''} onChange={(e)=>updateStepProfile(entryIdx, step.id, { description: e.target.value || undefined })} className="w-full text-xs border rounded p-1 h-14" placeholder="(空=テンプレ標準)"/>
                                                </div>
                                                <div className="flex items-center gap-2 flex-wrap">
                                                  <label className="text-[10px] text-slate-500">目標時間(秒)</label>
                                                  <input type="number" min="0" value={prof.targetTime ?? ''} onChange={(e)=>updateStepProfile(entryIdx, step.id, { targetTime: e.target.value === '' ? undefined : Math.max(0, Number(e.target.value)||0) })} className="w-20 text-xs border rounded p-1" placeholder="標準"/>
                                                  <label className="text-[10px] text-indigo-600 underline cursor-pointer">PDF差替
                                                    <input type="file" accept="application/pdf" className="hidden" onChange={async(e)=>{ const f=e.target.files?.[0]; if(f){ try{ const b=await getBase64(f); updateStepProfile(entryIdx, step.id, { pdfData: b }); alert('PDFを上書きしました'); }catch{ alert('PDFエラー'); } } e.target.value=''; }}/>
                                                  </label>
                                                  {prof.pdfData && <button onClick={()=>updateStepProfile(entryIdx, step.id, { pdfData: undefined })} className="text-[10px] text-rose-500 underline">PDF削除</button>}
                                                  <label className="text-[10px] text-indigo-600 underline cursor-pointer">写真追加
                                                    <input type="file" accept="image/*" className="hidden" onChange={async(e)=>{ const f=e.target.files?.[0]; if(f){ try{ const b=await getBase64(f); const url=await uploadImageToStorage(b,'qs-profile'); updateStepProfile(entryIdx, step.id, { images: [...(prof.images||[]), url] }); }catch{ alert('画像エラー'); } } e.target.value=''; }}/>
                                                  </label>
                                                  {(prof.images||[]).length>0 && <span className="text-[10px] text-slate-500">写真{prof.images.length}枚 <button onClick={()=>updateStepProfile(entryIdx, step.id, { images: undefined })} className="text-rose-500 underline">削除</button></span>}
                                                </div>
                                              </div>
                                            )}
                                          </div>
                                        );
                                      })}
                                    </div>
                                  </div>
                                )}
                            </div>
                        );
                    })}

                </div>
            )}

            {/* 規格マッピング一覧 (全体俯瞰) */}
            {Object.keys(modelStandardMap || {}).length > 0 && (
                <div className="mt-6 pt-4 border-t">
                    <div className="text-xs font-bold text-slate-500 mb-2">型式 ↔ 規格マッピング ({Object.keys(modelStandardMap).length} 件)</div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-2">
                        {Object.entries(modelStandardMap).map(([m, qsId]) => {
                            const qs = qualityStandards?.[qsId];
                            return (
                                <div key={m} className="bg-indigo-50 border border-indigo-200 rounded px-2 py-1.5 text-xs flex items-center justify-between gap-2">
                                    <div className="min-w-0 flex-1">
                                        <div className="font-bold text-indigo-900 truncate">{m}</div>
                                        <div className="text-indigo-600 text-[10px] truncate">→ {qs ? `${qs.standardNo} Rev.${qs.revision}` : '⚠ 不明な規格'}</div>
                                    </div>
                                    <button type="button" onClick={() => { setSelectedQsId(qsId); document.querySelector('[data-qs-panel]')?.scrollIntoView({ behavior: 'smooth', block: 'start' }); }} className="text-indigo-600 hover:text-indigo-800 p-1" title="この規格を編集"><Pencil className="w-3 h-3" /></button>
                                </div>
                            );
                        })}
                    </div>
                </div>
            )}
        </div>
    );
};

// 型式グループ管理: 同じ製品・工程の型式を束ねてデータ共有(作業順・目標時間)。管理者専用。
const ModelGroupManager = ({ lots = [], settings = {}, saveSettings }) => {
  const groups = settings.modelGroups || [];
  const allModels = useMemo(() => [...new Set((lots || []).map(l => (l.model || '').trim()).filter(Boolean))].sort(), [lots]);
  const completedCountByModel = useMemo(() => { const c = {}; (lots || []).forEach(l => { if (l.status === 'completed' && l.model) c[l.model] = (c[l.model] || 0) + 1; }); return c; }, [lots]);
  const groupOf = (m) => groups.find(g => (g.models || []).includes(m));
  const save = (ng) => saveSettings({ modelGroups: ng });
  const addGroup = () => save([...groups, { id: generateId(), name: 'グループ' + (groups.length + 1), models: [] }]);
  const rename = (id, name) => save(groups.map(g => g.id === id ? { ...g, name } : g));
  const del = (id) => save(groups.filter(g => g.id !== id));
  const toggle = (gid, model) => {
    // 1型式1グループ: 他グループから外してから対象グループへ入れる
    save(groups.map(g => {
      if (g.id === gid) { const has = (g.models || []).includes(model); return { ...g, models: has ? g.models.filter(m => m !== model) : [...(g.models || []), model] }; }
      return { ...g, models: (g.models || []).filter(m => m !== model) };
    }));
  };
  const ungrouped = allModels.filter(m => !groupOf(m));
  // 目標時間の一回きりコピー(立ち上げ用)
  const ctt = settings.customTargetTimes || {};
  const calCount = (m) => Object.keys(ctt[`model_${m}`] || {}).length;
  const [copyFrom, setCopyFrom] = useState('');
  const [copyTo, setCopyTo] = useState('');
  const doCopy = () => {
    if (!copyFrom || !copyTo || copyFrom === copyTo) return;
    const src = ctt[`model_${copyFrom}`];
    if (!src || !Object.keys(src).length) { alert('コピー元に目標時間の較正値がありません。'); return; }
    if (calCount(copyTo) > 0 && !confirm(`${copyTo} には既に較正値があります。上書きしますか？`)) return;
    saveSettings({ customTargetTimes: { ...ctt, [`model_${copyTo}`]: { ...src } } });
    alert(`${copyFrom} の目標時間を ${copyTo} にコピーしました（${Object.keys(src).length}工程）。`);
  };
  return (
    <div className="bg-white rounded-xl border p-4 h-full overflow-auto">
      <div className="flex items-start justify-between mb-3 gap-3">
        <div>
          <div className="text-lg font-black text-slate-800 flex items-center gap-2"><Layers className="w-5 h-5 text-indigo-600" /> 型式グループ（データ共有）</div>
          <div className="text-xs text-slate-500 mt-0.5 leading-relaxed">同じ製品で型式（サイズ・L/R 等）が違うものを束ねると、<b>作業順</b>と<b>目標時間</b>のデータを<b>合算</b>して解析します。<br />名前が変わっても同じグループに入れれば引き継げます。<b>1型式は1グループ</b>まで。数字 = 完了ロット数。</div>
        </div>
        <button onClick={addGroup} className="px-3 py-1.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold text-sm flex items-center gap-1 shrink-0"><Plus className="w-4 h-4" /> グループ追加</button>
      </div>
      {groups.length === 0 && <div className="text-center text-slate-400 py-6 text-sm border border-dashed rounded-lg mb-3">まだグループがありません。「グループ追加」で作り、下の型式を選んでください。</div>}
      <div className="space-y-3">
        {groups.map(g => {
          const totalLots = (g.models || []).reduce((a, m) => a + (completedCountByModel[m] || 0), 0);
          return (
            <div key={g.id} className="border rounded-lg p-3 bg-slate-50">
              <div className="flex items-center gap-2 mb-2">
                <input value={g.name} onChange={e => rename(g.id, e.target.value)} className="font-bold text-sm border rounded px-2 py-1 bg-white flex-1 max-w-xs" />
                <span className="text-xs text-slate-500">{(g.models || []).length}型式・完了{totalLots}ロット合算</span>
                <button onClick={() => del(g.id)} className="ml-auto text-rose-500 hover:bg-rose-50 rounded p-1" title="グループ削除"><Trash2 className="w-4 h-4" /></button>
              </div>
              <div className="flex flex-wrap gap-1.5">
                {allModels.map(m => {
                  const inThis = (g.models || []).includes(m);
                  const other = groupOf(m); const inOther = other && other.id !== g.id;
                  return (
                    <button key={m} onClick={() => toggle(g.id, m)} disabled={inOther} title={inOther ? `「${other.name}」に所属中` : ''}
                      className={`px-2 py-1 rounded text-[11px] font-bold border ${inThis ? 'bg-indigo-600 text-white border-indigo-600' : inOther ? 'bg-slate-100 text-slate-300 border-slate-200 cursor-not-allowed line-through' : 'bg-white text-slate-600 border-slate-300 hover:bg-indigo-50'}`}>
                      {m}{completedCountByModel[m] ? <span className="opacity-60 ml-0.5">({completedCountByModel[m]})</span> : ''}
                    </button>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>
      {groups.length > 0 && ungrouped.length > 0 && (
        <div className="mt-3 text-[11px] text-slate-400">未所属の型式 {ungrouped.length} 件はそれぞれ単独で解析されます。</div>
      )}
      {/* 目標時間の一回きりコピー(立ち上げ用) */}
      <div className="mt-4 pt-3 border-t">
        <div className="text-sm font-bold text-slate-700 mb-1 flex items-center gap-1"><Copy className="w-4 h-4 text-indigo-600" /> 目標時間を別型式にコピー（一回きり）</div>
        <div className="text-[11px] text-slate-500 mb-2">立ち上げ時など、ある型式の較正済み目標時間を別型式へ複製。以後は別々に育ちます。<br />（グループ化していれば自動で引き継ぐので、こちらは“グループにしないが一回だけ流用したい”時用）</div>
        <div className="flex items-center gap-2 flex-wrap">
          <select value={copyFrom} onChange={e => setCopyFrom(e.target.value)} className="border rounded px-2 py-1 text-sm">
            <option value="">コピー元…</option>
            {allModels.map(m => <option key={m} value={m}>{m}（{calCount(m)}工程）</option>)}
          </select>
          <span className="text-slate-400">→</span>
          <select value={copyTo} onChange={e => setCopyTo(e.target.value)} className="border rounded px-2 py-1 text-sm">
            <option value="">コピー先…</option>
            {allModels.map(m => <option key={m} value={m}>{m}（{calCount(m)}工程）</option>)}
          </select>
          <button onClick={doCopy} disabled={!copyFrom || !copyTo || copyFrom === copyTo} className="px-3 py-1 bg-indigo-600 disabled:bg-slate-300 text-white rounded font-bold text-sm">コピー</button>
        </div>
      </div>
    </div>
  );
};

// 実データ分析モーダル(読み取り専用): 1コンボの全ロットの実作業順を見比べ、改善シグナルを出す。
const WorkOrderReviewModal = ({ combo, lots = [], settings = {}, onClose, currentStrict = null, onMakeStrict, onSetGuide, onEditTemplate }) => {
  const data = useMemo(() => {
    if (!combo) return null;
    const groupModels = sameGroupModels(combo.model, settings);
    const completed = (lots || []).filter(l => l.status === 'completed' && groupModels.includes(l.model) && l.templateId === combo.templateId);
    const sample = completed.find(l => l.steps && l.steps.length) || completed[0];
    if (!sample) return { empty: true };
    return { ...analyzeLotsForReview(sample.steps, completed), grouped: groupModels.length > 1, groupModels, qty: sample.quantity || 1 };
  }, [combo, lots, settings]);
  const [openLots, setOpenLots] = useState({});
  // 現場の「気づき・改善」(type:'improvement') をこのコンボの全ロットから集める(完了/進行中問わず)。
  const improvements = useMemo(() => {
    if (!combo) return [];
    const groupModels = sameGroupModels(combo.model, settings);
    const comboLots = (lots || []).filter(l => groupModels.includes(l.model) && l.templateId === combo.templateId);
    const out = [];
    comboLots.forEach(l => (l.interruptions || []).forEach(it => { if (it.type === 'improvement') out.push({ ...it, lotOrderNo: l.orderNo, lotModel: l.model }); }));
    return out.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
  }, [combo, lots, settings]);
  const IMPROVE_LABELS = { split: '細分化', add: '追加', change: '変更', remove: '削除', order: '順番変更', other: 'その他' };
  if (!combo) return null;
  const fmtDate = (ts) => ts ? new Date(ts).toLocaleDateString() : '-';
  const ok = data && !data.empty && data.lotsWithTime > 0;
  const unneeded = ok ? Object.entries(data.skipRate).filter(([, v]) => v.pct >= 50).sort((a, b) => b[1].pct - a[1].pct) : [];
  const batchSig = ok ? Object.entries(data.blockAgg).filter(([, v]) => v.pct >= 50).sort((a, b) => b[1].pct - a[1].pct) : [];
  const orderVaries = ok && data.orderSignatures.length > 1;
  return (
    <div className="fixed inset-0 z-[140] bg-black/50 flex items-center justify-center p-4" onClick={onClose}>
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-4xl max-h-[92vh] flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>
        <div className="px-5 py-3 border-b bg-gradient-to-r from-indigo-50 to-slate-50 flex items-center justify-between">
          <div>
            <div className="text-xs text-indigo-700 font-bold">実データ分析（読み取り専用）</div>
            <div className="text-lg font-black text-slate-800">{combo.model} <span className="text-sm font-normal text-slate-500">× {combo.templateName}</span></div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-lg"><X className="w-5 h-5" /></button>
        </div>
        <div className="flex-1 overflow-auto p-4 space-y-4">
          {!ok ? (
            <div className="text-center text-slate-400 py-12">時刻データのある完了ロットがありません。</div>
          ) : (<>
            <div className="text-xs text-slate-600 bg-slate-50 rounded-lg p-2 border">
              完了 {data.totalLots}ロット / 時刻データあり <b>{data.lotsWithTime}</b>ロット / {data.qty}台
              {data.grouped && <span className="ml-2 text-indigo-600">（型式グループ {data.groupModels.length}型式を合算）</span>}
            </div>
            <div>
              <div className="font-bold text-sm text-slate-700 mb-1">① 作業順の揃い具合</div>
              <div className="text-[11px] text-slate-500 mb-1">テンプレ順: {data.tmplTitles.join(' › ')}</div>
              {orderVaries
                ? <div className="text-xs text-rose-700 font-bold mb-1">⚠ ロットで作業順がバラついています（{data.orderSignatures.length}パターン）</div>
                : <div className="text-xs text-emerald-700 font-bold mb-1">✓ 全ロットが同じ作業順</div>}
              <div className="space-y-1">
                {data.orderSignatures.map((p, i) => (
                  <div key={i} className="text-[11px] flex items-start gap-2">
                    <span className="bg-slate-200 px-1.5 rounded font-bold shrink-0">{p.n}ロット</span>
                    <span className="text-slate-700">{p.sig}</span>
                  </div>
                ))}
              </div>
            </div>
            <div>
              <div className="font-bold text-sm text-slate-700 mb-1">② 各ロットの実作業順（<span className="text-indigo-700">▦=全台まとめ</span> / <span className="text-purple-700">紫=自動測定</span>）</div>
              <div className="space-y-1.5">
                {data.perLot.map((p, i) => (
                  <div key={i} className="border rounded-lg p-2 bg-white">
                    <div className="flex items-center gap-2 text-[11px] mb-1 flex-wrap">
                      <span className="font-bold text-slate-700">指図{p.orderNo}</span>
                      <span className="text-slate-400">{p.model} / {p.qty}台 / {fmtDate(p.completedAt)}</span>
                      {p.matchesTemplate ? <span className="text-emerald-600 font-bold">✓テンプレ通り</span> : <span className="text-rose-600 font-bold">⚠順序ちがい</span>}
                      {p.ganttUnits && p.ganttUnits.length > 0 && (
                        <button onClick={() => setOpenLots(o => ({ ...o, [p.orderNo]: !o[p.orderNo] }))} className="ml-auto text-[11px] text-indigo-600 hover:underline font-bold">{openLots[p.orderNo] ? '台ごとの流れを閉じる' : '台ごとの作業の流れ▼'}</button>
                      )}
                    </div>
                    <div className="flex flex-wrap items-center gap-1">
                      {p.actualOrder.map((t, j) => (
                        <span key={j} className={`px-1.5 py-0.5 rounded text-[11px] border ${data.autoTitles.includes(t) ? 'bg-purple-50 border-purple-300 text-purple-700' : p.blocks[t] ? 'bg-indigo-100 border-indigo-300 text-indigo-800 font-bold' : 'bg-slate-50 border-slate-200 text-slate-600'}`}>
                          {p.blocks[t] ? '▦' : ''}{t}
                        </span>
                      ))}
                    </div>
                    {openLots[p.orderNo] && p.ganttUnits && (
                      <div className="mt-2 bg-slate-50 rounded border p-2 max-h-72 overflow-auto">
                        <div className="text-[10px] text-slate-500 mb-1 flex items-center gap-2"><span className="inline-flex items-center gap-1"><span className="w-2.5 h-2.5 bg-blue-500 rounded-sm inline-block" />手動</span><span className="inline-flex items-center gap-1"><span className="w-2.5 h-2.5 bg-violet-500 rounded-sm inline-block" />自動測定</span> ／ 同じ横軸＝並行作業が見える</div>
                        <MultiUnitGantt lot={{ orderNo: p.orderNo, units: p.ganttUnits }} />
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
            <div>
              <div className="font-bold text-sm text-slate-700 mb-1">③ 改善シグナル（データ根拠）</div>
              <div className="space-y-1 text-xs">
                {orderVaries && <div className="bg-amber-50 border border-amber-200 rounded p-2">🔀 <b>順番がばらつく</b>：②で入れ替わってる工程を比べ、速い順に揃える/テンプレ変更を検討。</div>}
                {batchSig.length > 0 && <div className="bg-indigo-50 border border-indigo-200 rounded p-2">▦ <b>まとめ作業</b>：{batchSig.map(([t, v]) => `${t}(${v.b}/${v.n}ロット${v.confident ? '・確定' : '・参考'})`).join('・')} → テンプレで“まとめ”/上に集約を検討。</div>}
                {unneeded.length > 0 && <div className="bg-rose-50 border border-rose-200 rounded p-2">🗑 <b>不要工程の候補</b>：{unneeded.map(([t, v]) => `${t}(該当なし ${v.sk}/${v.tot}台=${v.pct}%)`).join('・')} → テンプレから外す検討。</div>}
                {!orderVaries && batchSig.length === 0 && unneeded.length === 0 && <div className="text-slate-400">目立つ改善シグナルなし（安定）。</div>}
              </div>
            </div>
          </>)}
          {/* ④ 現場の気づき・改善(工程追加・変更の手がかり) ― 時刻データの有無に関係なく表示 */}
          <div>
            <div className="font-bold text-sm text-slate-700 mb-1 flex items-center gap-1"><Lightbulb className="w-4 h-4 text-indigo-600" /> 現場の気づき・改善（工程の追加・変更の手がかり）</div>
            {improvements.length === 0
              ? <div className="text-[11px] text-slate-400">まだありません。作業画面の「気づき・改善」から、工程の細分化・追加・変更などを理由つきで残せます（＝工程“追加”の手がかりはここから）。</div>
              : <div className="space-y-1">
                {improvements.map((it, i) => {
                  const reason = (it.label || '').split('：').slice(1).join('：').trim() || it.label || '';
                  return (
                    <div key={i} className="text-[11px] border border-indigo-100 bg-indigo-50/40 rounded p-1.5 flex items-start gap-2">
                      <span className="bg-indigo-600 text-white px-1.5 py-0.5 rounded font-bold shrink-0">{IMPROVE_LABELS[it.improvementKind] || '改善'}</span>
                      <div className="flex-1 min-w-0">
                        <div className="text-slate-700">{it.targetStepTitle && <b className="text-indigo-700">[{it.targetStepTitle}] </b>}{reason}</div>
                        <div className="text-[10px] text-slate-400">{it.workerName || '?'}・指図{it.lotOrderNo}・{it.timestamp ? new Date(it.timestamp).toLocaleDateString() : ''}</div>
                      </div>
                    </div>
                  );
                })}
              </div>}
          </div>
        </div>
        <div className="px-4 py-2.5 border-t bg-slate-50">
          <div className="text-[11px] text-slate-500 mb-1.5">見て納得したら、ここから動かす（厳密化・様子見は履歴に残ります）：</div>
          <div className="flex flex-wrap items-center gap-2">
            <button onClick={() => { onMakeStrict && onMakeStrict(); onClose && onClose(); }} disabled={currentStrict === true}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold border ${currentStrict === true ? 'bg-rose-100 text-rose-400 border-rose-200 cursor-default' : 'bg-rose-600 text-white border-rose-700 hover:bg-rose-700'}`}>
              {currentStrict === true ? '✓ この順番を厳密化中' : '🔒 この順番を厳密化'}
            </button>
            <button onClick={() => onEditTemplate && onEditTemplate()} className="px-3 py-1.5 rounded-lg text-xs font-bold border bg-indigo-600 text-white border-indigo-700 hover:bg-indigo-700">✏️ テンプレを改善（並べ替え・追加・削除）</button>
            <button onClick={() => { onSetGuide && onSetGuide(); onClose && onClose(); }} disabled={currentStrict === false}
              className={`px-3 py-1.5 rounded-lg text-xs font-bold border ${currentStrict === false ? 'bg-slate-200 text-slate-400 border-slate-200 cursor-default' : 'bg-white text-slate-600 border-slate-300 hover:bg-slate-50'}`}>👀 ガイドで様子見</button>
          </div>
          <div className="mt-2 text-[10px] text-slate-500 bg-amber-50 border border-amber-200 rounded p-1.5">
            💡 <b>工程の「追加」は時間データからは出ません</b>（既にあてる工程しか記録されないので）。追加の手がかりは現場の<b>「軽微不良・改善提案・不具合・クレーム」</b>です（ヘッダーの「不良/クレーム」やノート）。＝<b>並べ替え・削除・まとめ＝この時間データから／追加＝現場の声から</b>、と出どころが違います。
          </div>
        </div>
      </div>
    </div>
  );
};

const ProcessInsightsTab = ({ lots, workers, customTargetTimes, onSaveSettings, targetTimeHistory, settings, saveData = null, currentUserName = '' }) => {
  // === 進行中ロットへの較正値再適用 ===
  // 新規ロットは作成時に較正値が焼き付くが、既に作成済の進行中ロットには反映されていない。
  // 管理者がこのボタンで一括再適用できる。
  const [reapplyStatus, setReapplyStatus] = useState(null);
  const reapplyCalibrationToActiveLots = async () => {
    if (!saveData) return;
    const ctt = customTargetTimes || {};
    const targets = (lots || []).filter(l => l.status !== 'completed' && l.location !== 'completed' && l.model && ctt[`model_${l.model}`]);
    if (targets.length === 0) { alert('再適用対象の進行中ロットがありません (較正値のある型式の進行中ロットなし)'); return; }
    let updated = 0;
    setReapplyStatus('applying');
    try {
      for (const lot of targets) {
        const modelCal = ctt[`model_${lot.model}`];
        let changed = false;
        const newSteps = (lot.steps || []).map(s => {
          const cal = modelCal[`${s.category || ''}_${s.title || ''}`];
          if (typeof cal === 'number' && cal > 0 && cal !== s.targetTime) { changed = true; return { ...s, targetTime: cal, targetTimeCalibrated: true }; }
          return s;
        });
        if (changed) { await saveData('lots', lot.id, { steps: newSteps }); updated++; }
      }
      setReapplyStatus(`done:${updated}`);
      alert(`${updated} 件の進行中ロットに較正済み目標時間を再適用しました。`);
    } catch (e) {
      console.error(e); setReapplyStatus('error');
      alert('再適用に失敗しました: ' + e.message);
    }
  };
    const [targetValue, setTargetValue] = useState('');
    const [bulkStrategy, setBulkStrategy] = useState('standard');
    const [period, setPeriod] = useState('3m');
    const [customStartDate, setCustomStartDate] = useState(() => {
        const d = new Date(); d.setMonth(d.getMonth() - 1);
        const pad = (n) => n.toString().padStart(2, '0');
        return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
    });
    const [customEndDate, setCustomEndDate] = useState(() => {
        const d = new Date();
        const pad = (n) => n.toString().padStart(2, '0');
        return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
    });
    const [showHistory, setShowHistory] = useState(false);
    const [alertsOpen, setAlertsOpen] = useState(false); // 乖離アラートは既定で折りたたみ (場所を取らない)
    const [focusStepKey, setFocusStepKey] = useState(null); // 「開く」で選んだ工程をハイライト+スクロール
    const cardRefs = useRef({});
    useEffect(() => {
        if (focusStepKey && cardRefs.current[focusStepKey]) {
            cardRefs.current[focusStepKey].scrollIntoView({ behavior: 'smooth', block: 'center' });
            const t = setTimeout(() => setFocusStepKey(null), 2600);
            return () => clearTimeout(t);
        }
    }, [focusStepKey, targetValue]);

    const getPeriodDates = () => {
        let start = 0;
        let end = Infinity;
        if (period === 'custom') {
            if (customStartDate) start = new Date(customStartDate).getTime();
            if (customEndDate) { const ed = new Date(customEndDate); ed.setHours(23, 59, 59, 999); end = ed.getTime(); }
        } else {
            const d = new Date();
            if (period === '1m') d.setMonth(d.getMonth() - 1);
            else if (period === '3m') d.setMonth(d.getMonth() - 3);
            else if (period === '6m') d.setMonth(d.getMonth() - 6);
            else return { start: 0, end: Infinity };
            start = d.getTime();
        }
        return { start, end };
    };

    const availableModels = useMemo(() => {
        const models = new Set();
        lots.filter(l => l.status === 'completed' || l.location === 'completed').forEach(l => {
            if (l.model) models.add(l.model);
        });
        return Array.from(models).sort();
    }, [lots]);

    const insightsData = useMemo(() => {
        if (!targetValue) return [];
        const { start: startDate, end: endDate } = getPeriodDates();

        const targetLots = lots.filter(l => {
            if (l.status !== 'completed' && l.location !== 'completed') return false;
            if (l.model !== targetValue) return false;
            // 完了時刻を最優先(updatedAtは編集の度に動き標本が揺れる, Timestampは数値化)。
            const ts = toMsAny(l.completedAt) || toMsAny(l.updatedAt) || toMsAny(l.createdAt) || 0;
            if (ts < startDate || ts > endDate) return false;
            return true;
        });

        if (targetLots.length === 0) return [];

        const stepTimes = {};
        const workerTimesByStep = {};

        targetLots.forEach(lot => {
            (lot.steps || []).forEach((step, idx) => {
                const stepKey = `${step.category || ''}_${step.title}`;
                if (!stepTimes[stepKey]) {
                    stepTimes[stepKey] = { title: step.title, category: step.category || '', times: [], originalTarget: step.targetTime };
                    workerTimesByStep[stepKey] = {};
                }

                // ロット1回工程: 回数キー(lot-k)を収集 (1回=1標本、台数ループ不適用)
                const taskList = step.lotOnce
                    ? lotOnceKeysOf(lot.tasks || {}, step).map(k => lot.tasks?.[k])
                    : Array.from({ length: lot.quantity || 1 }, (_, i) => lot.tasks?.[`${step.id}-${i}`] || lot.tasks?.[`${idx}-${i}`]);
                taskList.forEach(task => {
                    if (task && task.status === 'completed' && task.duration > 0) {
                        stepTimes[stepKey].times.push(task.duration);
                        const worker = task.workerName || workers.find(w => w.id === task.workerId)?.name || '不明';
                        if (!workerTimesByStep[stepKey][worker]) workerTimesByStep[stepKey][worker] = [];
                        workerTimesByStep[stepKey][worker].push(task.duration);
                    }
                });
            });
        });

        const results = [];
        Object.keys(stepTimes).forEach(key => {
            const data = stepTimes[key];
            const stats = calculateStats(data.times);
            if (!stats) return;

            let bestWorker = null;
            let bestWorkerAvg = Infinity;
            Object.entries(workerTimesByStep[key]).forEach(([worker, times]) => {
                const wStats = calculateStats(times);
                if (wStats && wStats.validCount >= 3 && wStats.mean < bestWorkerAvg) {
                    bestWorkerAvg = wStats.mean;
                    bestWorker = worker;
                }
            });

            const insights = [];
            const coeffVariation = stats.stdDev / stats.mean;
            const savedKey = `model_${targetValue}`;
            const currentTarget = customTargetTimes[savedKey]?.[key] || data.originalTarget;

            if (coeffVariation > 0.4) {
                insights.push({ type: 'warning', text: '作業者や日による時間のバラつきが大きいです。手順の標準化や見直しを推奨します。' });
            }
            if (stats.mean > currentTarget * 1.3) {
                insights.push({ type: 'danger', text: `平均実績(${stats.mean}秒)が現在の目標(${currentTarget}秒)を大幅に超えています。目標が厳しすぎる可能性があります。` });
            } else if (stats.mean < currentTarget * 0.7) {
                insights.push({ type: 'info', text: `平均実績(${stats.mean}秒)が目標(${currentTarget}秒)を下回っています。目標を引き下げることで計画精度が向上します。` });
            }
            if (bestWorker && bestWorkerAvg < stats.mean * 0.8) {
                insights.push({ type: 'success', text: `ベストプラクティス: ${bestWorker}さんが安定して早く(${Math.round(bestWorkerAvg)}秒)作業しています。ノウハウ共有が有効です。` });
            }

            // === 推奨3案の値 ===
            //   標準バランス型 = 平均(mean) / 効率型 = 速い実績ペース / 余裕確保型 = 平均 + ばらつき(標準偏差)
            //   ※ 効率型: 作業者が1人だけだと「ベスト作業者の平均 = 全体平均」となり標準と同値になるバグ回避のため、
            //      p25(速い25%)より明確に速いベスト作業者がいる時だけその人基準、それ以外は p25 を使う。
            const p25 = stats.p25;
            const effFromWorker = (bestWorker && bestWorkerAvg < p25) ? Math.round(bestWorkerAvg) : null;
            const efficientValue = effFromWorker != null ? effFromWorker : p25;
            const conservativeValue = Math.round(stats.mean + stats.stdDev);
            const strategies = [
                { id: 'standard', name: '標準バランス型', desc: '全体の平均。標準的なスキル想定。', value: stats.mean, color: 'text-blue-800 bg-blue-50 border-blue-200 hover:bg-blue-100' },
                { id: 'aggressive', name: effFromWorker != null ? `効率型 (${bestWorker}基準)` : '効率追求型 (速い25%)', desc: effFromWorker != null ? `${bestWorker}さんの速いペースを基準` : '実績の速い25%(p25)を基準', value: efficientValue, color: 'text-emerald-800 bg-emerald-50 border-emerald-200 hover:bg-emerald-100' },
                { id: 'conservative', name: '余裕確保型', desc: 'バラつきを考慮した余裕あるペース。', value: conservativeValue, color: 'text-amber-800 bg-amber-50 border-amber-200 hover:bg-amber-100' }
            ];
            // データが少ない / ばらつきが小さいと3案がほぼ同値になる (バグではない)。その旨を伝えるフラグ。
            const stratVals = [stats.mean, efficientValue, conservativeValue];
            const strategiesSimilar = (Math.max(...stratVals) - Math.min(...stratVals)) <= Math.max(1, Math.round(stats.mean * 0.05));

            // === 【C】信頼度: 標本数とバラつき (変動係数) で較正値の信頼度を判定 ===
            // 高: n>=10 かつ CV<0.3 / 中: n>=5 かつ CV<0.5 / 低: それ未満
            const n = stats.validCount;
            const cv = stats.mean > 0 ? stats.stdDev / stats.mean : 1;
            let confidence = 'low';
            if (n >= 10 && cv < 0.3) confidence = 'high';
            else if (n >= 5 && cv < 0.5) confidence = 'mid';
            const confidenceLabel = confidence === 'high' ? '高' : confidence === 'mid' ? '中' : '低';

            results.push({ key, ...data, stats, currentTarget, insights, strategies, strategiesSimilar, confidence, confidenceLabel, cv });
        });

        return results.sort((a, b) => b.stats.mean - a.stats.mean);
    }, [lots, targetValue, customTargetTimes, period, customStartDate, customEndDate, workers]);

    // === 【E】乖離検知: 全型式を走査し、現在の目標時間と実績平均が乖離している工程を抽出 ===
    // 較正→承認→監視 ループの「監視」部分。再較正すべき箇所を管理者に提示する。
    const driftAlerts = useMemo(() => {
        const { start: startDate, end: endDate } = getPeriodDates();
        const byModelStep = {}; // `${model}||${stepKey}` → { model, title, category, target, times[] }
        lots.forEach(l => {
            if (l.status !== 'completed' && l.location !== 'completed') return;
            const ts0 = toMsAny(l.completedAt) || toMsAny(l.updatedAt) || toMsAny(l.createdAt) || 0;
            const ts = typeof ts0 === 'number' ? ts0 : new Date(ts0).getTime();
            if (ts < startDate || ts > endDate) return;
            const model = l.model;
            if (!model) return;
            (l.steps || []).forEach((step, idx) => {
                const sKey = `${step.category || ''}_${step.title}`;
                const mapKey = `${model}||${sKey}`;
                // 現在の実効目標 (較正値があればそれ、なければテンプレ)
                const cal = customTargetTimes[`model_${model}`]?.[sKey];
                const effTarget = (typeof cal === 'number' && cal > 0) ? cal : (step.targetTime || 0);
                if (!byModelStep[mapKey]) byModelStep[mapKey] = { model, title: step.title, category: step.category || '', stepKey: sKey, target: effTarget, calibrated: typeof cal === 'number' && cal > 0, times: [] };
                // ロット1回工程は回数キー(lot-k)が標本 (目標は1回あたりなのでそのまま比較可)
                const tList = step.lotOnce
                    ? lotOnceKeysOf(l.tasks || {}, step).map(k => l.tasks?.[k])
                    : Array.from({ length: l.quantity || 1 }, (_, i) => l.tasks?.[`${step.id}-${i}`] || l.tasks?.[`${idx}-${i}`]);
                tList.forEach(t => {
                    if (t && (t.status === 'completed' || t.status === 'ng') && t.duration > 0) byModelStep[mapKey].times.push(t.duration);
                });
            });
        });
        const alerts = [];
        Object.values(byModelStep).forEach(d => {
            if (d.times.length < 5) return; // 標本5件未満は判定しない
            if (!d.target || d.target <= 0) return;
            const mean = Math.round(d.times.reduce((a, b) => a + b, 0) / d.times.length);
            const ratio = mean / d.target;
            // 目標から ±30% 以上ずれていたら乖離アラート
            if (ratio >= 1.3 || ratio <= 0.7) {
                alerts.push({
                    model: d.model, title: d.title, category: d.category, stepKey: d.stepKey,
                    target: d.target, mean, ratio, n: d.times.length, calibrated: d.calibrated,
                    direction: ratio >= 1.3 ? 'over' : 'under',
                });
            }
        });
        return alerts.sort((a, b) => Math.abs(b.ratio - 1) - Math.abs(a.ratio - 1));
    }, [lots, customTargetTimes, period, customStartDate, customEndDate]);

    const applySuggestedTarget = (itemKey, strat, data) => {
        const savedKey = `model_${targetValue}`;
        const currentCustoms = customTargetTimes[savedKey] || {};
        const newCustomTimes = { ...customTargetTimes, [savedKey]: { ...currentCustoms, [itemKey]: strat.value } };
        const periodLabel = period === 'custom' ? `${customStartDate}~${customEndDate}` : period === '1m' ? '過去1ヶ月' : period === '3m' ? '過去3ヶ月' : period === '6m' ? '過去6ヶ月' : '全期間';
        const historyEntry = {
            timestamp: Date.now(), by: currentUserName || '?', targetType: 'model', targetValue,
            updates: [{ key: itemKey, category: data.category, title: data.title, oldTime: data.currentTarget, newTime: strat.value, strategyName: strat.name,
                evidence: { periodLabel, validCount: data.stats.validCount, mean: data.stats.mean, stdDev: data.stats.stdDev } }]
        };
        const newHistory = [...(targetTimeHistory || []), historyEntry];
        onSaveSettings({ customTargetTimes: newCustomTimes, targetTimeHistory: newHistory });
        alert('指定の目標時間をマスタに適用しました。次回以降のロットから反映されます。');
    };

    const applyAllSuggestedTargets = () => {
        const savedKey = `model_${targetValue}`;
        const currentCustoms = customTargetTimes[savedKey] || {};
        const newUpdates = {};
        const historyUpdates = [];
        const periodLabel = period === 'custom' ? `${customStartDate}~${customEndDate}` : period === '1m' ? '過去1ヶ月' : period === '3m' ? '過去3ヶ月' : period === '6m' ? '過去6ヶ月' : '全期間';

        insightsData.forEach(data => {
            const selectedStrat = data.strategies.find(s => s.id === bulkStrategy);
            if (selectedStrat && data.currentTarget !== selectedStrat.value) {
                newUpdates[data.key] = selectedStrat.value;
                historyUpdates.push({ key: data.key, category: data.category, title: data.title, oldTime: data.currentTarget, newTime: selectedStrat.value, strategyName: selectedStrat.name,
                    evidence: { periodLabel, validCount: data.stats.validCount, mean: data.stats.mean, stdDev: data.stats.stdDev } });
            }
        });

        if (historyUpdates.length === 0) { alert('更新する項目がありません。'); return; }

        const newCustomTimes = { ...customTargetTimes, [savedKey]: { ...currentCustoms, ...newUpdates } };
        const historyEntry = { timestamp: Date.now(), by: currentUserName || '?', targetType: 'model', targetValue, updates: historyUpdates };
        const newHistory = [...(targetTimeHistory || []), historyEntry];
        onSaveSettings({ customTargetTimes: newCustomTimes, targetTimeHistory: newHistory });
        alert(`表示されている全項目に「${bulkStrategy === 'standard' ? '標準バランス型' : bulkStrategy === 'aggressive' ? '効率追求型' : '余裕確保型'}」の目標時間を適用しました。`);
    };

    return (
        <div className="flex flex-col h-full gap-4">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 shrink-0 flex flex-wrap gap-4 items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><Zap className="w-5 h-5" /></div>
                    <div>
                        <h3 className="font-bold text-slate-800">工程改善・目標時間最適化</h3>
                        <p className="text-xs text-slate-500">実績データからエビデンスを算出し、状況に応じた最適な目標時間を提案します。</p>
                        <p className="text-[11px] text-emerald-700 font-bold mt-0.5 flex items-center gap-1">
                          <CheckCircle2 className="w-3 h-3"/> 適用先: 較正した目標時間は<b>新規ロット作成時に自動反映</b>され、ETA・進捗・データ最適順・ガントすべてに使われます
                        </p>
                    </div>
                </div>
                <div className="flex gap-2 items-center">
                    {saveData && currentUserName === '管理者' && (
                      <button
                        onClick={reapplyCalibrationToActiveLots}
                        disabled={reapplyStatus === 'applying'}
                        className="px-3 py-1.5 bg-emerald-600 hover:bg-emerald-700 disabled:bg-slate-300 text-white text-xs font-bold rounded shadow flex items-center gap-1"
                        title="作成済みの進行中ロットにも較正済み目標時間を反映する"
                      >
                        {reapplyStatus === 'applying' ? '適用中...' : '🔄 進行中ロットに再適用'}
                      </button>
                    )}
                    <button onClick={() => setShowHistory(false)} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all ${!showHistory ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                        最適化提案
                    </button>
                    <button onClick={() => setShowHistory(true)} className={`px-4 py-1.5 rounded-lg text-sm font-bold transition-all flex items-center gap-1 ${showHistory ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}>
                        <History className="w-4 h-4" /> 変更履歴
                    </button>
                </div>
            </div>

            {!showHistory ? (
                <>
                    {/* === 【E】乖離アラート: 目標と実績がズレた工程を全型式から検出 (既定は折りたたみ) === */}
                    {driftAlerts.length > 0 && (
                        <div className="bg-gradient-to-r from-rose-50 to-amber-50 border border-rose-300 rounded-xl shrink-0">
                            <button onClick={() => setAlertsOpen(o => !o)} className="w-full flex items-center gap-2 px-3 py-2 text-left">
                                <AlertOctagon className="w-5 h-5 text-rose-600 shrink-0"/>
                                <span className="font-black text-rose-900 text-sm">⚠ 目標時間の乖離アラート ({driftAlerts.length}件)</span>
                                <span className="text-[11px] text-rose-700 hidden md:inline">— 目標と実績が±30%以上ズレ。「開く」で該当工程へジャンプ</span>
                                <span className="ml-auto text-[11px] font-bold text-rose-600 shrink-0">{alertsOpen ? '▲ 閉じる' : '▼ 一覧を開く'}</span>
                            </button>
                            {alertsOpen && (
                            <div className="max-h-52 overflow-y-auto space-y-1 px-3 pb-3">
                                {driftAlerts.slice(0, 30).map((a, i) => (
                                    <div key={i} className="bg-white border border-rose-200 rounded px-2 py-1.5 flex items-center gap-2 text-xs">
                                        <span className={`text-[10px] font-black px-1.5 py-0.5 rounded shrink-0 ${a.direction === 'over' ? 'bg-rose-100 text-rose-700' : 'bg-blue-100 text-blue-700'}`}>
                                            {a.direction === 'over' ? `${Math.round((a.ratio-1)*100)}% 超過` : `${Math.round((1-a.ratio)*100)}% 短縮`}
                                        </span>
                                        <span className="font-bold text-slate-700 shrink-0">{a.model}</span>
                                        <span className="text-slate-500 truncate">/ {a.title}</span>
                                        <span className="ml-auto font-mono text-slate-600 shrink-0">目標{a.target}s→実績{a.mean}s</span>
                                        <span className="text-[10px] text-slate-400 shrink-0">n={a.n}{a.calibrated ? ' ✓' : ''}</span>
                                        <button
                                            onClick={() => { setTargetValue(a.model); setFocusStepKey(a.stepKey); }}
                                            className="text-[10px] bg-indigo-600 hover:bg-indigo-700 text-white px-2 py-0.5 rounded font-bold shrink-0"
                                            title="この型式・工程の最適化提案へジャンプ"
                                        >開く ▸</button>
                                    </div>
                                ))}
                                {driftAlerts.length > 30 && <div className="text-[10px] text-rose-500 mt-1 text-center">他 {driftAlerts.length - 30} 件</div>}
                            </div>
                            )}
                        </div>
                    )}

                    <div className="flex flex-wrap items-center gap-2 bg-white p-2.5 rounded-lg border shadow-sm shrink-0">
                        <span className="text-xs font-bold text-slate-500">型式</span>
                        <select value={targetValue} onChange={e => { setTargetValue(e.target.value); setFocusStepKey(null); }} className="border border-indigo-300 rounded px-3 py-1.5 font-bold text-indigo-800 outline-none focus:border-indigo-500 min-w-[170px]">
                            <option value="">型式を選択...</option>
                            {availableModels.map(opt => <option key={opt} value={opt}>{opt}</option>)}
                        </select>
                        <span className="text-xs font-bold text-slate-500 ml-1">集計</span>
                        <select value={period} onChange={e => setPeriod(e.target.value)} className="border rounded px-2 py-1.5 text-sm font-bold text-slate-700 bg-slate-50 outline-none">
                            <option value="1m">過去1ヶ月</option>
                            <option value="3m">過去3ヶ月</option>
                            <option value="6m">過去6ヶ月</option>
                            <option value="all">全期間</option>
                            <option value="custom">期間指定</option>
                        </select>
                        {period === 'custom' && (
                            <div className="flex items-center gap-1 bg-slate-50 p-1 rounded border">
                                <input type="date" value={customStartDate} onChange={e => setCustomStartDate(e.target.value)} className="bg-transparent text-xs font-bold text-slate-700 outline-none" />
                                <span className="text-slate-400 text-xs">~</span>
                                <input type="date" value={customEndDate} onChange={e => setCustomEndDate(e.target.value)} className="bg-transparent text-xs font-bold text-slate-700 outline-none" />
                            </div>
                        )}
                        {targetValue && insightsData.length > 0 && (
                            <>
                                <span className="text-[11px] text-slate-600 bg-slate-100 rounded px-2 py-1 whitespace-nowrap">工程<b>{insightsData.length}</b>件 / 有効データ計<b>{insightsData.reduce((s,d)=>s+d.stats.validCount,0)}</b>件で判断</span>
                                <div className="ml-auto flex items-center gap-1.5">
                                    <span className="text-xs font-bold text-slate-600 whitespace-nowrap">全工程に一括:</span>
                                    <select value={bulkStrategy} onChange={(e) => setBulkStrategy(e.target.value)} className="border rounded px-2 py-1.5 text-xs font-bold bg-slate-50">
                                        <option value="standard">標準バランス型</option>
                                        <option value="aggressive">効率追求型</option>
                                        <option value="conservative">余裕確保型</option>
                                    </select>
                                    <button onClick={applyAllSuggestedTargets} className="bg-indigo-600 hover:bg-indigo-700 text-white px-3 py-1.5 rounded font-bold shadow flex items-center gap-1 text-sm whitespace-nowrap"><Bot className="w-4 h-4" /> 適用</button>
                                </div>
                            </>
                        )}
                    </div>

                    {targetValue ? (
                        <div className="flex-1 overflow-y-auto min-h-0 space-y-4 pr-2">
                            {insightsData.map((data, idx) => (
                                <div key={idx} ref={el => { if (el) cardRefs.current[data.key] = el; }} className={`bg-white border rounded-xl shadow-sm overflow-hidden flex flex-col md:flex-row transition-all ${focusStepKey === data.key ? 'ring-4 ring-indigo-400 border-indigo-400' : ''}`}>
                                    <div className="p-4 border-b md:border-b-0 md:border-r bg-slate-50 md:w-1/3 flex flex-col justify-center">
                                        <div className="text-xs font-bold text-slate-400 mb-1">{data.category}</div>
                                        <div className="font-bold text-lg text-slate-800 mb-3">{data.title}</div>

                                        <div className="flex justify-between items-center text-sm bg-white border p-2 rounded mb-2">
                                            <span className="text-slate-500 font-bold">現在の設定目標:</span>
                                            <span className="font-mono font-black text-slate-800 text-lg">{data.currentTarget}秒</span>
                                        </div>

                                        <div className="text-xs font-bold text-indigo-600 mb-1 flex items-center gap-1"><Zap className="w-3 h-3" /> 状況に応じた推奨目標</div>
                                        {data.strategiesSimilar && (
                                            <div className="text-[10px] text-amber-700 bg-amber-50 border border-amber-200 rounded px-1.5 py-1 mb-1.5 leading-tight">
                                                ※ データが少ない/ばらつきが小さいため、3案の差がほぼありません（バグではありません）。データが貯まると差が出ます。
                                            </div>
                                        )}
                                        <div className="grid grid-cols-1 gap-2">
                                            {data.strategies.map(strat => (
                                                <div key={strat.id} className={`p-2 rounded border flex flex-col justify-between transition-colors ${strat.color}`}>
                                                    <div className="flex justify-between items-start">
                                                        <div>
                                                            <div className="text-xs font-bold mb-0.5">{strat.name}</div>
                                                            <div className="text-[10px] opacity-80 leading-tight pr-2">{strat.desc}</div>
                                                        </div>
                                                        <div className="font-mono font-black text-lg shrink-0">{strat.value}s</div>
                                                    </div>
                                                    {data.currentTarget !== strat.value && (
                                                        <button
                                                            onClick={() => applySuggestedTarget(data.key, strat, data)}
                                                            className="w-full mt-2 py-1 bg-white/60 hover:bg-white border border-current/20 rounded text-xs font-bold transition-colors shadow-sm"
                                                        >
                                                            この目標を採用する
                                                        </button>
                                                    )}
                                                </div>
                                            ))}
                                        </div>
                                    </div>

                                    <div className="p-4 flex-1 flex flex-col">
                                        <div className="flex justify-between items-center mb-2">
                                            <h4 className="text-sm font-bold text-slate-600 flex items-center gap-1"><Activity className="w-4 h-4" /> 統計エビデンス</h4>
                                            <div className="flex items-center gap-2">
                                                {/* 【C】信頼度バッジ */}
                                                <span className={`text-[10px] font-black px-2 py-0.5 rounded-full ${data.confidence === 'high' ? 'bg-emerald-100 text-emerald-700' : data.confidence === 'mid' ? 'bg-amber-100 text-amber-700' : 'bg-slate-200 text-slate-500'}`}
                                                  title={`信頼度: 標本${data.stats.validCount}件・変動係数${(data.cv*100).toFixed(0)}%。${data.confidence === 'high' ? 'データ十分・安定 → 較正値を信頼できます' : data.confidence === 'mid' ? '標本やや少 or ばらつき有 → 参考程度に' : 'データ不足 → 手動目標の維持を推奨'}`}>
                                                  信頼度 {data.confidenceLabel}
                                                </span>
                                                <span className="text-xs text-slate-400">有効: {data.stats.validCount}件</span>
                                            </div>
                                        </div>

                                        <div className="mb-4 bg-slate-100 rounded-full h-8 relative flex items-center px-2 shadow-inner overflow-hidden border border-slate-200">
                                            <span className="absolute left-2 text-[10px] text-slate-400">{data.stats.min}s (最速)</span>
                                            <span className="absolute right-2 text-[10px] text-slate-400">{data.stats.max}s (最遅)</span>
                                            <div className="absolute top-0 bottom-0 w-0.5 bg-blue-500" style={{ left: '50%', transform: 'translateX(-50%)' }}></div>
                                            <div className="absolute top-1 -mt-5 bg-blue-600 text-white text-[10px] px-1.5 rounded font-bold" style={{ left: '50%', transform: 'translateX(-50%)' }}>
                                                平均 {data.stats.mean}s
                                            </div>
                                            <div className="absolute h-2 bg-blue-400/40 rounded-full" style={{ left: '25%', right: '25%', top: '50%', transform: 'translateY(-50%)' }}></div>
                                        </div>

                                        <div className="grid grid-cols-3 gap-2 mb-4 text-center">
                                            <div className="bg-slate-50 p-2 rounded border">
                                                <div className="text-[10px] text-slate-500 font-bold mb-0.5">平均値</div>
                                                <div className="font-mono text-sm font-bold">{data.stats.mean}秒</div>
                                            </div>
                                            <div className="bg-slate-50 p-2 rounded border">
                                                <div className="text-[10px] text-slate-500 font-bold mb-0.5">中央値</div>
                                                <div className="font-mono text-sm font-bold">{data.stats.median}秒</div>
                                            </div>
                                            <div className="bg-slate-50 p-2 rounded border">
                                                <div className="text-[10px] text-slate-500 font-bold mb-0.5">バラつき(標準偏差)</div>
                                                <div className="font-mono text-sm font-bold">{'\u00B1'}{data.stats.stdDev}秒</div>
                                            </div>
                                        </div>

                                        {data.insights.length > 0 && (
                                            <div className="mt-auto space-y-1.5">
                                                <div className="text-xs font-bold text-slate-500 mb-1">自動インサイト:</div>
                                                {data.insights.map((insight, i) => {
                                                    let colors = 'bg-slate-50 text-slate-700 border-slate-200';
                                                    let Icon = AlertCircle;
                                                    if (insight.type === 'warning') { colors = 'bg-amber-50 text-amber-800 border-amber-200'; Icon = AlertTriangle; }
                                                    if (insight.type === 'danger') { colors = 'bg-rose-50 text-rose-800 border-rose-200'; Icon = AlertOctagon; }
                                                    if (insight.type === 'info') { colors = 'bg-blue-50 text-blue-800 border-blue-200'; Icon = HelpCircle; }
                                                    if (insight.type === 'success') { colors = 'bg-emerald-50 text-emerald-800 border-emerald-200'; Icon = TrendingUp; }
                                                    return (
                                                        <div key={i} className={`flex gap-2 p-2 rounded border text-xs font-bold ${colors}`}>
                                                            <Icon className="w-4 h-4 shrink-0 mt-0.5" />
                                                            <span>{insight.text}</span>
                                                        </div>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>
                                </div>
                            ))}
                            {insightsData.length === 0 && (
                                <div className="text-center py-10 bg-white rounded-xl border border-slate-200 text-slate-400">
                                    指定された期間の完了実績データが不足しているため、分析できません。
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="flex-1 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-xl bg-slate-50/50 text-slate-400 font-bold p-6">
                            <Target className="w-12 h-12 mb-3 opacity-20" />
                            <p>上部のメニューから分析対象の「型式」を選択してください。</p>
                            <p className="text-xs mt-2 font-normal text-slate-500">十分な完了実績がある型式ほど、正確なエビデンスと提案が生成されます。</p>
                        </div>
                    )}
                </>
            ) : (
                <TargetTimeHistoryPanel history={targetTimeHistory || []} />
            )}
        </div>
    );
};

// Advanced Analysis View
// === AI 深掘り分析セクション ===
// 改善ヒントタブ内に表示される。Gemini を呼んで深い洞察を取得・表示
const AIDeepAnalysisSection = ({ payload }) => {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);
  const handleRun = async () => {
    setLoading(true);
    setError(null);
    try {
      const r = await requestGeminiDeepAnalysis(payload);
      setResult(r);
    } catch (e) {
      setError(e.message || String(e));
    } finally {
      setLoading(false);
    }
  };
  return (
    <div className="bg-gradient-to-br from-purple-50 to-indigo-50 rounded-xl shadow-sm border-2 border-indigo-200 p-5">
      <div className="flex items-center justify-between mb-3">
        <div>
          <h3 className="text-lg font-bold text-indigo-900 flex items-center gap-2"><Bot className="w-5 h-5 text-purple-600"/> 🤖 AI 深掘り分析 (Gemini)</h3>
          <div className="text-xs text-slate-600 mt-1">下のデータを Gemini に渡して、人間が気づきにくい相関・隠れた問題・優先アクションを抽出します</div>
        </div>
        <button
          onClick={handleRun}
          disabled={loading}
          className={`px-4 py-2 rounded-lg font-bold text-sm flex items-center gap-2 shadow ${loading ? 'bg-slate-300 text-slate-500' : 'bg-gradient-to-r from-indigo-600 to-purple-600 hover:shadow-lg text-white'}`}
        >
          {loading ? <><Loader2 className="w-4 h-4 animate-spin"/> 解析中...</> : result ? <><Zap className="w-4 h-4"/> 再分析</> : <><Bot className="w-4 h-4"/> AI 分析を実行</>}
        </button>
      </div>
      {error && (
        <div className="bg-rose-50 border border-rose-300 rounded-lg p-3 text-sm text-rose-800">
          <div className="font-bold">❌ エラー</div>
          <div className="text-xs mt-1">{error}</div>
          {error.includes('VITE_GEMINI_API_KEY') && (
            <div className="text-xs mt-2 bg-white p-2 rounded border border-rose-200">
              💡 .env ファイルに <code className="bg-slate-100 px-1 rounded">VITE_GEMINI_API_KEY=...</code> を設定してビルドし直してください。
            </div>
          )}
        </div>
      )}
      {result && (
        <div className="space-y-4 mt-2">
          {/* 総括 */}
          {result.summary && (
            <div className="bg-white border-l-4 border-indigo-500 rounded-r-lg p-3 text-sm text-indigo-900">
              <div className="font-bold text-xs text-indigo-600 mb-1">📋 AI 総括</div>
              {result.summary}
            </div>
          )}
          {/* Top Insights */}
          {(result.topInsights || []).length > 0 && (
            <div>
              <div className="font-bold text-sm text-slate-700 mb-2 flex items-center gap-1.5"><AlertCircle className="w-4 h-4 text-amber-500"/> 主要な洞察</div>
              <div className="space-y-2">
                {result.topInsights.map((ins, i) => (
                  <div key={i} className={`border rounded-lg p-3 ${ins.severity === 'high' ? 'bg-rose-50 border-rose-300' : ins.severity === 'mid' ? 'bg-amber-50 border-amber-300' : 'bg-emerald-50 border-emerald-300'}`}>
                    <div className="flex items-start gap-2">
                      <span className="text-lg">{ins.severity === 'high' ? '🔴' : ins.severity === 'mid' ? '🟡' : '🟢'}</span>
                      <div className="flex-1">
                        <div className="font-bold text-sm text-slate-800">{ins.title}</div>
                        <div className="text-xs text-slate-600 mt-1"><span className="font-bold">根拠:</span> {ins.evidence}</div>
                        <div className="text-xs text-slate-700 mt-1"><span className="font-bold">示唆:</span> {ins.implication}</div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
          {/* Priority Actions */}
          {(result.priorityActions || []).length > 0 && (
            <div>
              <div className="font-bold text-sm text-slate-700 mb-2 flex items-center gap-1.5"><Target className="w-4 h-4 text-emerald-600"/> 優先アクション</div>
              <div className="space-y-2">
                {result.priorityActions.map((act, i) => (
                  <div key={i} className="bg-emerald-50 border border-emerald-300 rounded-lg p-3">
                    <div className="flex items-start gap-2">
                      <span className="bg-emerald-600 text-white text-xs font-bold px-2 py-0.5 rounded-full">#{i+1}</span>
                      <div className="flex-1">
                        <div className="font-bold text-sm text-emerald-900">{act.action}</div>
                        <div className="text-xs text-slate-600 mt-1">期待効果: {act.expectedImpact} · 工数感: {act.effort}</div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
          {/* Hidden Issues */}
          {(result.hiddenIssues || []).length > 0 && (
            <div>
              <div className="font-bold text-sm text-slate-700 mb-2 flex items-center gap-1.5"><Activity className="w-4 h-4 text-purple-600"/> 隠れた問題</div>
              <div className="space-y-2">
                {result.hiddenIssues.map((h, i) => (
                  <div key={i} className="bg-purple-50 border border-purple-300 rounded-lg p-3">
                    <div className="font-bold text-sm text-purple-900">{h.issue}</div>
                    <div className="text-xs text-slate-600 mt-1">💡 検出根拠: {h.detection}</div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
      {!result && !loading && !error && (
        <div className="text-xs text-slate-500 mt-2">
          現在 {payload?.removalCandidates?.length || 0} 件の不要工程候補・{payload?.skillGaps?.length || 0} 件のスキル差・{payload?.parallelRanking?.length || 0} 件の並列実績を分析対象としています。
        </div>
      )}
    </div>
  );
};

